{
  "name": "GenPaper AI",
  "description": "An AI-powered academic question paper generator using Bloom's Taxonomy standards."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface QuestionCounts {
  mcq: number;
  ar: number; // Assertion-Reason
  vsaq: number; // Very Short Answer
  saq: number; // Short Answer
  laq: number; // Long Answer
  caseStudy: number;
}

export interface PaperConfig {
  subject: string;
  grade: string;
  totalMarks: number;
  difficulty: 'Easy' | 'Medium' | 'Hard';
  counts: QuestionCounts;
}

export interface GeneratedPaper {
  id: string;
  timestamp: number;
  config: PaperConfig;
  title: string;
  content: string; // Markdown content of the question paper
  answerKey: string; // Markdown content of the answer key
}

export interface HistoryStats {
  totalGenerated: number;
  topics: string[];
}

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { PaperConfig, GeneratedPaper } from "../types";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

// Define the response schema strictly to ensure easy parsing
const paperResponseSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    title: {
      type: Type.STRING,
      description: "The formal title of the examination paper (e.g., 'Grade 10 Physics Mid-Term').",
    },
    questionPaper: {
      type: Type.STRING,
      description: "The full question paper formatted in Markdown. Use clear headers (Section A, B, etc.), numbered lists, and bold text for emphasis. Ensure pedagogical quality.",
    },
    answerKey: {
      type: Type.STRING,
      description: "The comprehensive answer key and marking scheme formatted in Markdown.",
    },
  },
  required: ["title", "questionPaper", "answerKey"],
};

export const generateQuestionPaper = async (config: PaperConfig): Promise<GeneratedPaper> => {
  if (!apiKey) {
    throw new Error("API Key is missing. Please check your environment configuration.");
  }

  const prompt = `
    Act as a senior academic curriculum developer. Generate a high-quality question paper based on the following specifications:

    Subject: ${config.subject}
    Grade/Level: ${config.grade}
    Total Marks: ${config.totalMarks}
    Difficulty: ${config.difficulty}

    Structure the paper with the following question distribution:
    - Multiple Choice Questions (MCQ): ${config.counts.mcq}
    - Assertion-Reasoning (A/R): ${config.counts.ar} (Format: A is true, R is false, etc.)
    - Very Short Answer (VSAQ): ${config.counts.vsaq}
    - Short Answer (SAQ): ${config.counts.saq}
    - Long Answer (LAQ): ${config.counts.laq}
    - Case Study/Source-based: ${config.counts.caseStudy} (Provide a paragraph/source followed by sub-questions)

    Pedagogical Guidelines:
    1. Apply Bloom's Taxonomy. Ensure a mix of knowledge, understanding, application, and analysis based on the difficulty level '${config.difficulty}'.
    2. Questions should be clear, unambiguous, and grade-appropriate.
    3. Group questions into logical sections (e.g., Section A: Objective, Section B: Short, Section C: Long).
    4. Provide the output in strict Markdown format within the JSON response.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: paperResponseSchema,
        temperature: 0.4, // Lower temperature for more structured/academic output
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response received from AI.");

    const data = JSON.parse(text);

    return {
      id: crypto.randomUUID(),
      timestamp: Date.now(),
      config,
      title: data.title,
      content: data.questionPaper,
      answerKey: data.answerKey,
    };
  } catch (error) {
    console.error("Error generating paper:", error);
    throw error;
  }
};

import React from 'react';

interface MarkdownRendererProps {
  content: string;
  className?: string;
}

// A simple parser to handle basic Markdown structures used in the papers
// This avoids needing 'react-markdown' or other heavy libs in this specific environment
const MarkdownRenderer: React.FC<MarkdownRendererProps> = ({ content, className }) => {
  const lines = content.split('\n');

  return (
    <div className={`space-y-3 ${className}`}>
      {lines.map((line, index) => {
        // Headers
        if (line.startsWith('### ')) {
          return <h3 key={index} className="text-lg font-bold mt-4 mb-2">{line.replace('### ', '')}</h3>;
        }
        if (line.startsWith('## ')) {
          return <h2 key={index} className="text-xl font-bold mt-6 mb-3 border-b pb-1">{line.replace('## ', '')}</h2>;
        }
        if (line.startsWith('# ')) {
          return <h1 key={index} className="text-2xl font-bold mt-8 mb-4 text-center uppercase">{line.replace('# ', '')}</h1>;
        }

        // Horizontal Rules
        if (line.trim() === '---' || line.trim() === '***') {
          return <hr key={index} className="my-6 border-gray-300" />;
        }

        // List Items (Simple)
        if (line.trim().match(/^(\d+\.|-|\*)\s/)) {
            // Very basic bold handling: **text** -> <b>text</b>
            const parts = line.split(/(\*\*.*?\*\*)/g);
            return (
                <div key={index} className="ml-4 flex">
                    <span className="mr-2">{line.trim().charAt(0) === '-' || line.trim().charAt(0) === '*' ? '•' : ''}</span>
                    <p className="whitespace-pre-wrap">
                        {parts.map((part, i) => {
                             if (part.startsWith('**') && part.endsWith('**')) {
                                 return <strong key={i}>{part.slice(2, -2)}</strong>;
                             }
                             return part;
                        })}
                    </p>
                </div>
            )
        }

        // Empty lines
        if (line.trim() === '') {
          return <div key={index} className="h-2"></div>;
        }

        // Paragraphs with Bold support
        const parts = line.split(/(\*\*.*?\*\*)/g);
        return (
          <p key={index} className="whitespace-pre-wrap leading-relaxed text-gray-800">
            {parts.map((part, i) => {
              if (part.startsWith('**') && part.endsWith('**')) {
                return <strong key={i}>{part.slice(2, -2)}</strong>;
              }
              return part;
            })}
          </p>
        );
      })}
    </div>
  );
};

export default MarkdownRenderer;

