export default Dashboard;

import React, { useState } from 'react';
import { PaperConfig, QuestionCounts } from '../types';

interface PaperFormProps {
  onGenerate: (config: PaperConfig) => void;
  onCancel: () => void;
  isGenerating: boolean;
}

const PaperForm: React.FC<PaperFormProps> = ({ onGenerate, onCancel, isGenerating }) => {
  const [subject, setSubject] = useState('');
  const [grade, setGrade] = useState('');
  const [totalMarks, setTotalMarks] = useState(50);
  const [difficulty, setDifficulty] = useState<'Easy' | 'Medium' | 'Hard'>('Medium');

  const [counts, setCounts] = useState<QuestionCounts>({
    mcq: 5,
    ar: 2,
    vsaq: 5,
    saq: 3,
    laq: 2,
    caseStudy: 1,
  });

  const handleCountChange = (key: keyof QuestionCounts, value: number) => {
    setCounts(prev => ({ ...prev, [key]: Math.max(0, value) }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onGenerate({
      subject,
      grade,
      totalMarks,
      difficulty,
      counts
    });
  };

  return (
    <div className="max-w-3xl mx-auto p-6">
      <div className="bg-white rounded-2xl shadow-lg border border-gray-100 overflow-hidden">
        <div className="p-6 bg-indigo-50 border-b border-indigo-100">
            <h2 className="text-2xl font-bold text-indigo-900">Configure Paper</h2>
            <p className="text-indigo-600 text-sm mt-1">Define the parameters for your AI-generated assessment.</p>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-8">
          {/* General Info */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">Subject / Topic</label>
              <input
                type="text"
                required
                className="w-full px-4 py-2 rounded-lg border border-gray-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
                placeholder="e.g. Photosynthesis, World War II"
                value={subject}
                onChange={(e) => setSubject(e.target.value)}
              />
            </div>
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">Grade Level</label>
              <input
                type="text"
                required
                className="w-full px-4 py-2 rounded-lg border border-gray-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
                placeholder="e.g. Grade 10, Undergraduate"
                value={grade}
                onChange={(e) => setGrade(e.target.value)}
              />
            </div>
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">Total Marks</label>
              <input
                type="number"
                min="10"
                max="100"
                className="w-full px-4 py-2 rounded-lg border border-gray-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
                value={totalMarks}
                onChange={(e) => setTotalMarks(parseInt(e.target.value))}
              />
            </div>
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">Difficulty</label>
              <select
                className="w-full px-4 py-2 rounded-lg border border-gray-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all bg-white"
                value={difficulty}
                onChange={(e) => setDifficulty(e.target.value as any)}
              >
                <option value="Easy">Easy</option>
                <option value="Medium">Medium</option>
                <option value="Hard">Hard</option>
              </select>
            </div>
          </div>

          <hr className="border-gray-100" />

          {/* Question Distribution */}
          <div>
            <h3 className="text-lg font-semibold text-gray-800 mb-4 flex items-center gap-2">
              <span className="w-1 h-6 bg-indigo-500 rounded-full"></span>
              Question Distribution
            </h3>
            <div className="grid grid-cols-2 md:grid-cols-3 gap-6">
              {[
                { label: "MCQs", key: "mcq", desc: "1 Mark each" },
                { label: "Assertion-Reason", key: "ar", desc: "Logic based" },
                { label: "Very Short (VSAQ)", key: "vsaq", desc: "1-2 lines" },
                { label: "Short Answer (SAQ)", key: "saq", desc: "Paragraph" },
                { label: "Long Answer (LAQ)", key: "laq", desc: "Detailed" },
                { label: "Case Study", key: "caseStudy", desc: "Source based" },
              ].map((item) => (
                <div key={item.key} className="bg-gray-50 p-3 rounded-lg border border-gray-100">
                  <label className="block text-xs font-bold text-gray-500 uppercase mb-1">{item.label}</label>
                  <input
                    type="number"
                    min="0"
                    max="20"
                    className="w-full px-3 py-1.5 rounded border border-gray-200 focus:border-indigo-500 focus:ring-1 focus:ring-indigo-500 outline-none"
                    value={counts[item.key as keyof QuestionCounts]}
                    onChange={(e) => handleCountChange(item.key as keyof QuestionCounts, parseInt(e.target.value))}
                  />
                  <p className="text-xs text-gray-400 mt-1">{item.desc}</p>
                </div>
              ))}
            </div>
          </div>

          {/* Actions */}
          <div className="flex justify-end gap-3 pt-4">
            <button
              type="button"
              onClick={onCancel}
              className="px-6 py-2.5 rounded-lg text-gray-600 font-medium hover:bg-gray-100 transition-colors"
              disabled={isGenerating}
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={isGenerating}
              className={`px-8 py-2.5 rounded-lg text-white font-bold shadow-lg transition-all flex items-center gap-2
                ${isGenerating 
                  ? 'bg-indigo-400 cursor-not-allowed' 
                  : 'bg-indigo-600 hover:bg-indigo-700 hover:shadow-indigo-500/30 active:scale-95'
                }`}
            >
              {isGenerating ? (
                <>
                  <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                  Generating...
                </>
              ) : (
                'Generate Paper'
              )}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default PaperForm;

import React, { useState } from 'react';
import { GeneratedPaper } from '../types';
import MarkdownRenderer from './MarkdownRenderer';

interface PaperPreviewProps {
  paper: GeneratedPaper;
  onBack: () => void;
}

const PaperPreview: React.FC<PaperPreviewProps> = ({ paper, onBack }) => {
  const [showAnswerKey, setShowAnswerKey] = useState(false);

  const handleDownload = () => {
    // Create a blob for the text file
    const fileContent = `
${paper.title}
Subject: ${paper.config.subject}
Grade: ${paper.config.grade}
----------------------------------------

${paper.content}

========================================
ANSWER KEY
========================================

${paper.answerKey}
    `;

    const blob = new Blob([fileContent], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${paper.title.replace(/\s+/g, '_')}_Mock_Paper.txt`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  return (
    <div className="max-w-5xl mx-auto p-4 sm:p-8 animate-fade-in pb-20">

      {/* Top Controls */}
      <div className="flex flex-col sm:flex-row justify-between items-center mb-8 gap-4 sticky top-0 bg-white/90 backdrop-blur-sm p-4 rounded-xl shadow-sm z-10 border border-gray-100">
        <button 
          onClick={onBack}
          className="text-gray-600 hover:text-gray-900 flex items-center gap-2 font-medium"
        >
          ← Back to Dashboard
        </button>

        <div className="flex gap-3">
          <button 
            onClick={() => setShowAnswerKey(!showAnswerKey)}
            className="px-4 py-2 border border-indigo-200 text-indigo-700 rounded-lg hover:bg-indigo-50 font-medium transition-colors"
          >
            {showAnswerKey ? 'Show Question Paper' : 'Show Answer Key'}
          </button>
          <button 
            onClick={handleDownload}
            className="px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 shadow-md transition-all font-medium flex items-center gap-2"
          >
            <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"></path><polyline points="7 10 12 15 17 10"></polyline><line x1="12" y1="15" x2="12" y2="3"></line></svg>
            Download Mock
          </button>
        </div>
      </div>

      {/* Paper View */}
      <div className="bg-white shadow-xl shadow-gray-200/50 rounded-lg overflow-hidden min-h-[800px] border border-gray-200">
        {/* Header Section representing a real paper header */}
        <div className="bg-white p-8 sm:p-12 border-b-2 border-gray-800 text-center">
            <h1 className="text-3xl font-serif font-bold text-gray-900 mb-2">{paper.title}</h1>
            <div className="flex justify-center gap-8 text-sm font-serif text-gray-700 uppercase tracking-widest mt-4">
                <span>Subject: {paper.config.subject}</span>
                <span>Max Marks: {paper.config.totalMarks}</span>
                <span>Time: 2 Hours</span> {/* Hardcoded standard time for demo */}
            </div>
            <div className="mt-4 text-xs text-gray-500 italic">
                Generated by GenPaper AI
            </div>
        </div>

        <div className="p-8 sm:p-16 paper-font">
            {showAnswerKey ? (
                <div className="animate-fade-in">
                    <div className="bg-yellow-50 border-l-4 border-yellow-400 p-4 mb-8">
                        <h2 className="text-yellow-800 font-bold uppercase tracking-wide text-sm">Confidential: Marking Scheme & Answer Key</h2>
                    </div>
                    <MarkdownRenderer content={paper.answerKey} />
                </div>
            ) : (
                <div className="animate-fade-in">
                    <div className="text-sm text-gray-600 mb-8 border p-4 rounded bg-gray-50">
                        <strong>General Instructions:</strong>
                        <ul className="list-disc ml-5 mt-2 space-y-1">
                            <li>All questions are compulsory.</li>
                            <li>The question paper has been divided into multiple sections based on the format requested.</li>
                            <li>Calculators are not permitted unless specified.</li>
                        </ul>
                    </div>
                    <MarkdownRenderer content={paper.content} />
                </div>
            )}
        </div>
      </div>
    </div>
  );
};

export default PaperPreview;

import React, { useState, useCallback } from 'react';
import Dashboard from './components/Dashboard';
import PaperForm from './components/PaperForm';
import PaperPreview from './components/PaperPreview';
import { PaperConfig, GeneratedPaper } from './types';
import { generateQuestionPaper } from './services/geminiService';

type View = 'dashboard' | 'create' | 'preview';

const App: React.FC = () => {
  const [view, setView] = useState<View>('dashboard');
  const [history, setHistory] = useState<GeneratedPaper[]>([]);
  const [currentPaper, setCurrentPaper] = useState<GeneratedPaper | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleGenerate = async (config: PaperConfig) => {
    setIsGenerating(true);
    setError(null);
    try {
      const newPaper = await generateQuestionPaper(config);
      setHistory(prev => [...prev, newPaper]);
      setCurrentPaper(newPaper);
      setView('preview');
    } catch (err: any) {
      setError(err.message || "Failed to generate paper. Please try again.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleViewPaper = (paper: GeneratedPaper) => {
    setCurrentPaper(paper);
    setView('preview');
  };

  const handleCreateNew = useCallback(() => {
    setView('create');
    setError(null);
  }, []);

  const handleBackToDashboard = useCallback(() => {
    setView('dashboard');
    setCurrentPaper(null);
  }, []);

  const handleCancelCreate = useCallback(() => {
    setView('dashboard');
  }, []);

  return (
    <div className="min-h-screen bg-gray-50 text-gray-900 font-sans selection:bg-indigo-100 selection:text-indigo-800">

      {/* Top Navigation Bar */}
      <nav className="bg-white border-b border-gray-200 px-6 py-4 flex justify-between items-center sticky top-0 z-50">
        <div className="flex items-center gap-2">
            <div className="bg-indigo-600 w-8 h-8 rounded-lg flex items-center justify-center text-white font-bold text-lg">
                G
            </div>
            <span className="text-xl font-bold tracking-tight text-gray-800">GenPaper<span className="text-indigo-600">AI</span></span>
        </div>
        <div className="text-sm text-gray-500 hidden sm:block">
            AI-Powered Assessment Generator
        </div>
      </nav>

      {/* Main Content Area */}
      <main className="container mx-auto py-8 px-4">
        {error && (
            <div className="max-w-4xl mx-auto mb-6 p-4 bg-red-50 border-l-4 border-red-500 text-red-700 rounded-r shadow-sm flex justify-between items-center">
                <span>{error}</span>
                <button onClick={() => setError(null)} className="text-red-500 font-bold hover:text-red-800">&times;</button>
            </div>
        )}

        {view === 'dashboard' && (
          <Dashboard 
            history={history} 
            onCreateNew={handleCreateNew} 
            onViewPaper={handleViewPaper} 
          />
        )}

        {view === 'create' && (
          <PaperForm 
            onGenerate={handleGenerate} 
            onCancel={handleCancelCreate} 
            isGenerating={isGenerating} 
          />
        )}

        {view === 'preview' && currentPaper && (
          <PaperPreview 
            paper={currentPaper} 
            onBack={handleBackToDashboard} 
          />
        )}
      </main>
    </div>
  );
};

