  const [counts, setCounts] = useState<QuestionCounts>({
    mcq: 5,
    ar: 2,
    vsaq: 5,
    saq: 3,
    laq: 2,
    caseStudy: 1,
  });

  const [currentCalculatedMarks, setCurrentCalculatedMarks] = useState(0);

  // Update calculation whenever counts change
  useEffect(() => {
    const total = QUESTION_SPECS.reduce((acc, spec) => acc + (counts[spec.key] * spec.marks), 0);
    setCurrentCalculatedMarks(total);
