import React, { useState } from 'react';
import { QuestionBank } from '../types';
import { CBSE_DATA } from '../constants';
import MarkdownRenderer from './MarkdownRenderer';
import { generateQuestionBankUpdate } from '../services/geminiService';

interface QuestionBankProps {
  banks: QuestionBank[];
  onUpdateBank: (bank: QuestionBank) => void;
  onBack: () => void;
}

const QuestionBankView: React.FC<QuestionBankProps> = ({ banks, onUpdateBank, onBack }) => {
  const [selectedSubject, setSelectedSubject] = useState<string>('');
  const [grade, setGrade] = useState<string>('');
  const [isUpdating, setIsUpdating] = useState(false);

  // Find existing bank for selected subject
  const currentBank = banks.find(b => b.subject === selectedSubject && b.grade === grade);

  const handleUpdate = async () => {
    if (!selectedSubject || !grade) return;

    setIsUpdating(true);
    try {
      const newContent = await generateQuestionBankUpdate(selectedSubject, grade);

      const updatedBank: QuestionBank = currentBank 
        ? {
            ...currentBank,
            lastUpdated: Date.now(),
            content: `### Update: ${new Date().toLocaleDateString()} ${new Date().toLocaleTimeString()}\n\n${newContent}\n\n---\n\n${currentBank.content}`
          }
        : {
            id: crypto.randomUUID(),
            subject: selectedSubject,
            grade: grade,
            lastUpdated: Date.now(),
            content: `### Question Bank: ${selectedSubject} (${grade})\n\n${newContent}`
          };

      onUpdateBank(updatedBank);
    } catch (error) {
      console.error(error);
      alert("Failed to update question bank. Please check your connection or API limit.");
    } finally {
      setIsUpdating(false);
    }
  };

  const handleDownload = () => {
    if (!currentBank) return;
    const blob = new Blob([currentBank.content], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `QuestionBank_${currentBank.subject}_${currentBank.grade}.txt`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  return (
    <div className="max-w-6xl mx-auto p-4 sm:p-6 animate-fade-in pb-20">
      {/* Header */}
      <div className="flex justify-between items-center mb-6">
        <button 
          onClick={onBack}
          className="text-gray-600 hover:text-gray-900 flex items-center gap-2 font-medium"
        >
          ← Back to Dashboard
        </button>
        <h1 className="text-2xl font-bold text-gray-800">Master Question Bank</h1>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">

        {/* Controls Sidebar */}
        <div className="lg:col-span-1 space-y-4">
          <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-100">
            <h3 className="font-bold text-gray-700 mb-3">Select Context</h3>

            <div className="space-y-3">
              <div>
                <label className="block text-xs font-semibold text-gray-500 mb-1">Subject</label>
                <select 
                  className="w-full px-3 py-2 rounded-lg border border-gray-200 bg-white text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
                  value={selectedSubject}
                  onChange={(e) => setSelectedSubject(e.target.value)}
                >
                  <option value="">Select Subject</option>
                  {Object.keys(CBSE_DATA).map(subj => (
                    <option key={subj} value={subj}>{subj}</option>
                  ))}
                </select>
              </div>

              <div>
                <label className="block text-xs font-semibold text-gray-500 mb-1">Grade</label>
                <input 
                  type="text"
                  className="w-full px-3 py-2 rounded-lg border border-gray-200 bg-white text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
                  placeholder="e.g. Class 10"
                  value={grade}
                  onChange={(e) => setGrade(e.target.value)}
                />
              </div>
            </div>

            <button
              onClick={handleUpdate}
              disabled={!selectedSubject || !grade || isUpdating}
              className={`w-full mt-4 py-2.5 rounded-lg font-bold text-white shadow-sm transition-all flex items-center justify-center gap-2
                ${(!selectedSubject || !grade || isUpdating) ? 'bg-gray-300 cursor-not-allowed' : 'bg-green-600 hover:bg-green-700 active:scale-95'}
              `}
            >
              {isUpdating ? (
                 <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                   <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                   <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                 </svg>
              ) : (
                currentBank ? 'Update / Add Questions' : 'Create Bank'
              )}
            </button>
          </div>

          {currentBank && (
            <div className="bg-indigo-50 p-4 rounded-xl border border-indigo-100 text-sm text-indigo-800">
               <p className="font-bold mb-1">Status</p>
               <p>Bank Available</p>
               <p className="text-xs text-indigo-600 mt-1">Last updated: {new Date(currentBank.lastUpdated).toLocaleDateString()}</p>
               <button 
                 onClick={handleDownload}
                 className="mt-3 text-xs underline font-bold hover:text-indigo-900"
               >
                 Download Full Bank
               </button>
            </div>
          )}
        </div>

        {/* Content Area */}
        <div className="lg:col-span-3">
          <div className="bg-white rounded-xl shadow-sm border border-gray-200 min-h-[600px] flex flex-col">
            {currentBank ? (
              <div className="p-8 paper-font overflow-y-auto max-h-[800px]">
                <MarkdownRenderer content={currentBank.content} />
              </div>
            ) : (
              <div className="flex-1 flex flex-col items-center justify-center text-gray-400 p-8 text-center">
                <svg className="w-16 h-16 mb-4 opacity-50" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10"></path>
                </svg>
                <h3 className="text-lg font-medium text-gray-600">No Question Bank Selected</h3>
                <p className="max-w-md mt-2">Select a Subject and Grade from the sidebar and click "Create Bank" to start generating your repository.</p>
              </div>
            )}
          </div>
        </div>

      </div>
    </div>
  );
};

