import React, { useState, useEffect } from 'react';
import { PaperConfig, QuestionCounts } from '../types';
import { CBSE_DATA } from '../constants';

// Defined Weights and Specs
const QUESTION_SPECS: { label: string; key: keyof QuestionCounts; marks: number }[] = [
  { label: "MCQs", key: "mcq", marks: 1 },
  { label: "Assertion-Reason", key: "ar", marks: 1 },
  { label: "Very Short (VSAQ)", key: "vsaq", marks: 2 },
  { label: "Short Answer (SAQ)", key: "saq", marks: 3 },
  { label: "Case Study", key: "caseStudy", marks: 4 },
  { label: "Long Answer (LAQ)", key: "laq", marks: 5 },
];

interface PaperFormProps {
  onGenerate: (config: PaperConfig) => void;
  onCancel: () => void;
  isGenerating: boolean;
}

const PaperForm: React.FC<PaperFormProps> = ({ onGenerate, onCancel, isGenerating }) => {
  const [selectedSubject, setSelectedSubject] = useState('');
  const [selectedTopic, setSelectedTopic] = useState('');

  const [grade, setGrade] = useState('');
  const [totalMarks, setTotalMarks] = useState(50);
  const [difficulty, setDifficulty] = useState<'Easy' | 'Medium' | 'Hard'>('Medium');

  // State for counts is now Record<Key, string> to allow empty values
  const [counts, setCounts] = useState<Record<keyof QuestionCounts, string>>({
    mcq: '',
    ar: '',
    vsaq: '',
    saq: '',
    laq: '',
    caseStudy: '',
  });

  const [errors, setErrors] = useState<Record<keyof QuestionCounts, string | null>>({
    mcq: null,
    ar: null,
    vsaq: null,
    saq: null,
    laq: null,
    caseStudy: null,
  });

  const [currentCalculatedMarks, setCurrentCalculatedMarks] = useState<number | null>(null);

  // Update calculation whenever counts change
  useEffect(() => {
    const allFieldsFilled = QUESTION_SPECS.every(spec => counts[spec.key] !== '');

    if (allFieldsFilled) {
      const total = QUESTION_SPECS.reduce((acc, spec) => {
        const val = parseInt(counts[spec.key]) || 0;
        return acc + (val * spec.marks);
      }, 0);
      setCurrentCalculatedMarks(total);
    } else {
      setCurrentCalculatedMarks(null);
    }
  }, [counts]);

  const validateField = (key: keyof QuestionCounts, value: string) => {
    if (value === '') {
      return 'This field is required';
    }
    const num = parseInt(value);
    if (isNaN(num) || num < 0) {
      return 'Invalid number';
    }
    return null;
  };

  const handleCountChange = (key: keyof QuestionCounts, value: string) => {
    // Prevent non-numeric characters (except empty string)
    if (value !== '' && !/^\d+$/.test(value)) return;

    setCounts(prev => ({ ...prev, [key]: value }));

    // Clear error immediately if valid, or validate if it was previously errored
    if (value !== '') {
        setErrors(prev => ({ ...prev, [key]: null }));
    }
  };

  const handleBlur = (key: keyof QuestionCounts) => {
    const error = validateField(key, counts[key]);
    setErrors(prev => ({ ...prev, [key]: error }));
  };

  const handleSubjectChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const newSubject = e.target.value;
    setSelectedSubject(newSubject);
    setSelectedTopic(''); // Reset topic when subject changes
  };

  const handleAutoDistribute = () => {
    let newCounts: Record<keyof QuestionCounts, number> = { mcq: 0, ar: 0, vsaq: 0, saq: 0, laq: 0, caseStudy: 0 };
    let currentSum = 0;

    // 1. Minimum 1 each if mathematically possible
    for (const spec of QUESTION_SPECS) {
        if (currentSum + spec.marks <= totalMarks) {
            newCounts[spec.key]++;
            currentSum += spec.marks;
        }
    }

    // 2. Distribute remainder
    while (currentSum < totalMarks) {
        const candidates = QUESTION_SPECS.filter(spec => currentSum + spec.marks <= totalMarks);
        if (candidates.length === 0) break;

        // Sort candidates by current count (ascending) to maintain balance
        candidates.sort((a, b) => newCounts[a.key] - newCounts[b.key]);

        const bestSpec = candidates[0];
        newCounts[bestSpec.key]++;
        currentSum += bestSpec.marks;
    }

    // Convert to strings for state
    const stringCounts: any = {};
    QUESTION_SPECS.forEach(spec => {
        stringCounts[spec.key] = newCounts[spec.key].toString();
    });

    setCounts(stringCounts);
    // Clear all errors
    setErrors({ mcq: null, ar: null, vsaq: null, saq: null, laq: null, caseStudy: null });
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    // Validate all fields
    let hasErrors = false;
    const newErrors: any = {};

    QUESTION_SPECS.forEach(spec => {
        const error = validateField(spec.key, counts[spec.key]);
        if (error) {
            hasErrors = true;
            newErrors[spec.key] = error;
        }
    });

    if (hasErrors) {
        setErrors(newErrors);
        return;
    }

    // Convert strings to final QuestionCounts number object
    const finalCounts: any = {};
    QUESTION_SPECS.forEach(spec => {
        finalCounts[spec.key] = parseInt(counts[spec.key]);
    });

    let fullSubject = selectedSubject;
    if (selectedTopic === 'All Topics') {
        const allChapters = CBSE_DATA[selectedSubject]?.join(', ');
        fullSubject = `${selectedSubject}: All Topics (Covering: ${allChapters})`;
    } else if (selectedTopic) {
        fullSubject = `${selectedSubject}: ${selectedTopic}`;
    }

    onGenerate({
      subject: fullSubject,
      grade,
      totalMarks,
      difficulty,
      counts: finalCounts as QuestionCounts
    });
  };

  return (
    <div className="max-w-3xl mx-auto p-6">
      <div className="bg-white rounded-2xl shadow-lg border border-gray-100 overflow-hidden">
        <div className="p-6 bg-indigo-50 border-b border-indigo-100">
            <h2 className="text-2xl font-bold text-indigo-900">Configure Paper</h2>
            <p className="text-indigo-600 text-sm mt-1">Define the parameters for your AI-generated assessment.</p>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-8">
          {/* General Info */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">

            {/* Subject Dropdown */}
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">Subject</label>
              <select
                required
                className="w-full px-4 py-2 rounded-lg border border-gray-300 bg-white focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all text-gray-900"
                value={selectedSubject}
                onChange={handleSubjectChange}
              >
                <option value="" disabled>Select Subject</option>
                {Object.keys(CBSE_DATA).map((subj) => (
                  <option key={subj} value={subj} className="text-gray-900">{subj}</option>
                ))}
              </select>
            </div>

            {/* Topic Dropdown */}
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">Topic / Chapter</label>
              <select
                required
                disabled={!selectedSubject}
                className="w-full px-4 py-2 rounded-lg border border-gray-300 bg-white focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all text-gray-900 disabled:bg-gray-100 disabled:text-gray-400"
                value={selectedTopic}
                onChange={(e) => setSelectedTopic(e.target.value)}
              >
                <option value="" disabled>Select Topic</option>
                {selectedSubject && (
                    <option value="All Topics" className="text-gray-900 font-bold bg-gray-50">
                        All Topics (Entire Syllabus)
                    </option>
                )}
                {selectedSubject && CBSE_DATA[selectedSubject]?.map((topic) => (
                  <option key={topic} value={topic} className="text-gray-900">{topic}</option>
                ))}
              </select>
            </div>

            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">Grade Level</label>
              <input
                type="text"
                required
                className="w-full px-4 py-2 rounded-lg border border-gray-300 bg-white focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all text-gray-900"
                placeholder="e.g. Class 10, Class 12"
                value={grade}
                onChange={(e) => setGrade(e.target.value)}
              />
            </div>
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">Total Marks</label>
              <div className="flex gap-2">
                  <input
                    type="number"
                    min="10"
                    max="100"
                    className="w-full px-4 py-2 rounded-lg border border-gray-300 bg-white focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all text-gray-900"
                    value={totalMarks}
                    onChange={(e) => setTotalMarks(parseInt(e.target.value))}
                  />
                  <button
                    type="button"
                    onClick={handleAutoDistribute}
                    className="px-3 py-2 bg-indigo-100 text-indigo-700 rounded-lg hover:bg-indigo-200 transition-colors text-sm font-semibold whitespace-nowrap"
                    title="Automatically distribute marks evenly"
                  >
                    Auto Distribute
                  </button>
              </div>
            </div>
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">Difficulty</label>
              <select
                className="w-full px-4 py-2 rounded-lg border border-gray-300 bg-white focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all text-gray-900"
                value={difficulty}
                onChange={(e) => setDifficulty(e.target.value as any)}
              >
                <option value="Easy" className="text-gray-900 bg-white">Easy</option>
                <option value="Medium" className="text-gray-900 bg-white">Medium</option>
                <option value="Hard" className="text-gray-900 bg-white">Hard</option>
              </select>
            </div>
          </div>

          <hr className="border-gray-100" />

          {/* Question Distribution */}
          <div>
            <div className="flex justify-between items-center mb-4">
                <h3 className="text-lg font-semibold text-gray-800 flex items-center gap-2">
                  <span className="w-1 h-6 bg-indigo-500 rounded-full"></span>
                  Question Distribution
                </h3>
                {currentCalculatedMarks !== null && (
                    <div className={`text-sm font-bold px-3 py-1 rounded-full ${currentCalculatedMarks === totalMarks ? 'bg-green-100 text-green-700' : 'bg-orange-100 text-orange-700'}`}>
                        Current: {currentCalculatedMarks} / {totalMarks} Marks
                    </div>
                )}
                {currentCalculatedMarks === null && (
                     <div className="text-sm font-bold px-3 py-1 rounded-full bg-gray-100 text-gray-500">
                        Total Pending...
                     </div>
                )}
            </div>

            <div className="grid grid-cols-2 md:grid-cols-3 gap-6 mb-6">
              {QUESTION_SPECS.map((item) => {
                const isError = !!errors[item.key];
                return (
                    <div key={item.key} className="relative">
                        <div className={`p-3 rounded-lg border ${isError ? 'bg-red-50 border-red-200' : 'bg-gray-50 border-gray-100'} transition-colors`}>
                            <label className={`block text-xs font-bold uppercase mb-1 ${isError ? 'text-red-700' : 'text-gray-700'}`}>
                                {item.label}
                            </label>
                            <input
                                type="number"
                                min="0"
                                placeholder="Enter number of questions"
                                className={`w-full px-3 py-1.5 rounded border bg-white focus:ring-1 outline-none text-gray-900 placeholder:text-gray-400 text-sm
                                    ${isError 
                                        ? 'border-red-500 focus:border-red-500 focus:ring-red-200' 
                                        : 'border-gray-200 focus:border-indigo-500 focus:ring-indigo-500'}`}
                                value={counts[item.key]}
                                onChange={(e) => handleCountChange(item.key, e.target.value)}
                                onBlur={() => handleBlur(item.key)}
                            />
                            <p className="text-xs text-gray-500 mt-1">{item.marks} Mark{item.marks > 1 ? 's' : ''} each</p>
                        </div>
                        {errors[item.key] && (
                            <p className="absolute -bottom-5 left-0 text-xs font-bold text-red-500 animate-fade-in">
                                {errors[item.key]}
                            </p>
                        )}
                    </div>
                );
              })}
            </div>

            {/* Detailed Summary Table */}
            <div className="overflow-hidden border border-gray-200 rounded-lg shadow-sm mt-8">
                <table className="min-w-full text-sm">
                    <thead className="bg-gray-50 text-gray-700 border-b border-gray-200">
                        <tr>
                            <th className="px-4 py-2 text-left font-semibold">Question Type</th>
                            <th className="px-4 py-2 text-center font-semibold">Marks/Q</th>
                            <th className="px-4 py-2 text-center font-semibold">Count</th>
                            <th className="px-4 py-2 text-right font-semibold">Total</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-100">
                        {QUESTION_SPECS.map((spec) => (
                            <tr key={spec.key} className="bg-white hover:bg-gray-50 transition-colors">
                                <td className="px-4 py-2 text-gray-800 font-medium">{spec.label}</td>
                                <td className="px-4 py-2 text-center text-gray-600">{spec.marks}</td>
                                <td className="px-4 py-2 text-center text-gray-600 font-medium">
                                    {counts[spec.key] === '' ? '-' : counts[spec.key]}
                                </td>
                                <td className="px-4 py-2 text-right font-semibold text-gray-800">
                                    {counts[spec.key] === '' ? '-' : (parseInt(counts[spec.key]) * spec.marks)}
                                </td>
                            </tr>
                        ))}
                        <tr className="bg-indigo-50 font-bold border-t-2 border-indigo-100">
                            <td className="px-4 py-3 text-indigo-900">Grand Total</td>
                            <td className="px-4 py-3 text-center">-</td>
                            <td className="px-4 py-3 text-center text-indigo-900">
                                {currentCalculatedMarks === null ? '-' : Object.values(counts).reduce((a, b) => a + (parseInt(b) || 0), 0)}
                            </td>
                            <td className={`px-4 py-3 text-right text-lg ${currentCalculatedMarks !== totalMarks ? 'text-orange-600' : 'text-indigo-900'}`}>
                                {currentCalculatedMarks === null ? 'Pending...' : currentCalculatedMarks}
                            </td>
                        </tr>
                    </tbody>
                </table>
            </div>
            {currentCalculatedMarks !== null && currentCalculatedMarks !== totalMarks && (
                <p className="text-xs text-orange-600 mt-2 text-right font-medium">
                    * Total does not match required marks. Please adjust counts or use Auto Distribute.
                </p>
            )}
            {currentCalculatedMarks === null && (
                 <p className="text-xs text-red-600 mt-2 text-right font-medium">
                    * Please fill in all question fields to calculate totals.
                </p>
            )}
          </div>

          {/* Actions */}
          <div className="flex justify-end gap-3 pt-4">
            <button
              type="button"
              onClick={onCancel}
              className="px-6 py-2.5 rounded-lg text-gray-600 font-medium hover:bg-gray-100 transition-colors"
              disabled={isGenerating}
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={isGenerating || currentCalculatedMarks === null || currentCalculatedMarks === 0}
              className={`px-8 py-2.5 rounded-lg text-white font-bold shadow-lg transition-all flex items-center gap-2
                ${isGenerating || currentCalculatedMarks === null || currentCalculatedMarks === 0
                  ? 'bg-indigo-400 cursor-not-allowed' 
                  : 'bg-indigo-600 hover:bg-indigo-700 hover:shadow-indigo-500/30 active:scale-95'
                }`}
            >
              {isGenerating ? (
                <>
                  <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                  Generating...
                </>
              ) : (
                'Generate Paper'
              )}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default PaperForm;

import React, { useState, useEffect } from 'react';
import { PaperConfig, QuestionCounts } from '../types';
import { CBSE_DATA } from '../constants';

// Defined Weights and Specs
const QUESTION_SPECS: { label: string; key: keyof QuestionCounts; marks: number }[] = [
  { label: "MCQs", key: "mcq", marks: 1 },
  { label: "Assertion-Reason", key: "ar", marks: 1 },
  { label: "Very Short (VSAQ)", key: "vsaq", marks: 2 },
  { label: "Short Answer (SAQ)", key: "saq", marks: 3 },
  { label: "Case Study", key: "caseStudy", marks: 4 },
  { label: "Long Answer (LAQ)", key: "laq", marks: 5 },
];

interface PaperFormProps {
  onGenerate: (config: PaperConfig) => void;
  onCancel: () => void;
  isGenerating: boolean;
}

const PaperForm: React.FC<PaperFormProps> = ({ onGenerate, onCancel, isGenerating }) => {
  const [selectedSubject, setSelectedSubject] = useState('');
  const [selectedTopic, setSelectedTopic] = useState('');

  const [grade, setGrade] = useState('');
  const [totalMarks, setTotalMarks] = useState(50);
  const [difficulty, setDifficulty] = useState<'Easy' | 'Medium' | 'Hard'>('Medium');

  // State for counts is now Record<Key, string> to allow empty values
  const [counts, setCounts] = useState<Record<keyof QuestionCounts, string>>({
    mcq: '',
    ar: '',
    vsaq: '',
    saq: '',
    laq: '',
    caseStudy: '',
  });

  const [errors, setErrors] = useState<Record<keyof QuestionCounts, string | null>>({
    mcq: null,
    ar: null,
    vsaq: null,
    saq: null,
    laq: null,
    caseStudy: null,
  });

  const [currentCalculatedMarks, setCurrentCalculatedMarks] = useState<number | null>(null);

  // Update calculation whenever counts change
  useEffect(() => {
    const allFieldsFilled = QUESTION_SPECS.every(spec => counts[spec.key] !== '');

    if (allFieldsFilled) {
      const total = QUESTION_SPECS.reduce((acc, spec) => {
        const val = parseInt(counts[spec.key]) || 0;
        return acc + (val * spec.marks);
      }, 0);
      setCurrentCalculatedMarks(total);
    } else {
      setCurrentCalculatedMarks(null);
    }
  }, [counts]);

  const validateField = (key: keyof QuestionCounts, value: string) => {
    if (value === '') {
      return 'This field is required';
    }
    const num = parseInt(value);
    if (isNaN(num) || num < 0) {
      return 'Invalid number';
    }
    return null;
  };

  const handleCountChange = (key: keyof QuestionCounts, value: string) => {
    // Prevent non-numeric characters (except empty string)
    if (value !== '' && !/^\d+$/.test(value)) return;

    setCounts(prev => ({ ...prev, [key]: value }));

    // Clear error immediately if valid, or validate if it was previously errored
    if (value !== '') {
        setErrors(prev => ({ ...prev, [key]: null }));
    }
  };

  const handleBlur = (key: keyof QuestionCounts) => {
    const error = validateField(key, counts[key]);
    setErrors(prev => ({ ...prev, [key]: error }));
  };

  const handleSubjectChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const newSubject = e.target.value;
    setSelectedSubject(newSubject);
    setSelectedTopic(''); // Reset topic when subject changes
  };

  const handleAutoDistribute = () => {
    let newCounts: Record<keyof QuestionCounts, number> = { mcq: 0, ar: 0, vsaq: 0, saq: 0, laq: 0, caseStudy: 0 };
    let currentSum = 0;

    // 1. Minimum 1 each if mathematically possible
    for (const spec of QUESTION_SPECS) {
        if (currentSum + spec.marks <= totalMarks) {
            newCounts[spec.key]++;
            currentSum += spec.marks;
        }
    }

    // 2. Distribute remainder
    while (currentSum < totalMarks) {
        const candidates = QUESTION_SPECS.filter(spec => currentSum + spec.marks <= totalMarks);
        if (candidates.length === 0) break;

        // Sort candidates by current count (ascending) to maintain balance
        candidates.sort((a, b) => newCounts[a.key] - newCounts[b.key]);

        const bestSpec = candidates[0];
        newCounts[bestSpec.key]++;
        currentSum += bestSpec.marks;
    }

    // Convert to strings for state
    const stringCounts: any = {};
    QUESTION_SPECS.forEach(spec => {
        stringCounts[spec.key] = newCounts[spec.key].toString();
    });

    setCounts(stringCounts);
    // Clear all errors
    setErrors({ mcq: null, ar: null, vsaq: null, saq: null, laq: null, caseStudy: null });
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    // Validate all fields
    let hasErrors = false;
    const newErrors: any = {};

    QUESTION_SPECS.forEach(spec => {
        const error = validateField(spec.key, counts[spec.key]);
        if (error) {
            hasErrors = true;
            newErrors[spec.key] = error;
        }
    });

    if (hasErrors) {
        setErrors(newErrors);
        return;
    }

    // Convert strings to final QuestionCounts number object
    const finalCounts: any = {};
    QUESTION_SPECS.forEach(spec => {
        finalCounts[spec.key] = parseInt(counts[spec.key]);
    });

    let fullSubject = selectedSubject;
    if (selectedTopic === 'All Topics') {
        const allChapters = CBSE_DATA[selectedSubject]?.join(', ');
        fullSubject = `${selectedSubject}: All Topics (Covering: ${allChapters})`;
    } else if (selectedTopic) {
        fullSubject = `${selectedSubject}: ${selectedTopic}`;
    }

    onGenerate({
      subject: fullSubject,
      grade,
      totalMarks,
      difficulty,
      counts: finalCounts as QuestionCounts
    });
  };

  return (
    <div className="max-w-3xl mx-auto p-6">
      <div className="bg-white rounded-2xl shadow-lg border border-gray-100 overflow-hidden">
        <div className="p-6 bg-indigo-50 border-b border-indigo-100">
            <h2 className="text-2xl font-bold text-indigo-900">Configure Paper</h2>
            <p className="text-indigo-600 text-sm mt-1">Define the parameters for your AI-generated assessment.</p>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-8">
          {/* General Info */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">

            {/* Subject Dropdown */}
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">Subject</label>
              <select
                required
                className="w-full px-4 py-2 rounded-lg border border-gray-300 bg-white focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all text-gray-900"
                value={selectedSubject}
                onChange={handleSubjectChange}
              >
                <option value="" disabled>Select Subject</option>
                {Object.keys(CBSE_DATA).map((subj) => (
                  <option key={subj} value={subj} className="text-gray-900">{subj}</option>
                ))}
              </select>
            </div>

            {/* Topic Dropdown */}
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">Topic / Chapter</label>
              <select
                required
                disabled={!selectedSubject}
                className="w-full px-4 py-2 rounded-lg border border-gray-300 bg-white focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all text-gray-900 disabled:bg-gray-100 disabled:text-gray-400"
                value={selectedTopic}
                onChange={(e) => setSelectedTopic(e.target.value)}
              >
                <option value="" disabled>Select Topic</option>
                {selectedSubject && (
                    <option value="All Topics" className="text-gray-900 font-bold bg-gray-50">
                        All Topics (Entire Syllabus)
                    </option>
                )}
                {selectedSubject && CBSE_DATA[selectedSubject]?.map((topic) => (
                  <option key={topic} value={topic} className="text-gray-900">{topic}</option>
                ))}
              </select>
            </div>

            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">Grade Level</label>
              <input
                type="text"
                required
                className="w-full px-4 py-2 rounded-lg border border-gray-300 bg-white focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all text-gray-900"
                placeholder="e.g. Class 10, Class 12"
                value={grade}
                onChange={(e) => setGrade(e.target.value)}
              />
            </div>
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">Total Marks</label>
              <div className="flex gap-2">
                  <input
                    type="number"
                    min="10"
                    max="100"
                    className="w-full px-4 py-2 rounded-lg border border-gray-300 bg-white focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all text-gray-900"
                    value={totalMarks}
                    onChange={(e) => setTotalMarks(parseInt(e.target.value))}
                  />
                  <button
                    type="button"
                    onClick={handleAutoDistribute}
                    className="px-3 py-2 bg-indigo-100 text-indigo-700 rounded-lg hover:bg-indigo-200 transition-colors text-sm font-semibold whitespace-nowrap"
                    title="Automatically distribute marks evenly"
                  >
                    Auto Distribute
                  </button>
              </div>
            </div>
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">Difficulty</label>
              <select
                className="w-full px-4 py-2 rounded-lg border border-gray-300 bg-white focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all text-gray-900"
                value={difficulty}
                onChange={(e) => setDifficulty(e.target.value as any)}
              >
                <option value="Easy" className="text-gray-900 bg-white">Easy</option>
                <option value="Medium" className="text-gray-900 bg-white">Medium</option>
                <option value="Hard" className="text-gray-900 bg-white">Hard</option>
              </select>
            </div>
          </div>

          <hr className="border-gray-100" />

          {/* Question Distribution */}
          <div>
            <div className="flex justify-between items-center mb-4">
                <h3 className="text-lg font-semibold text-gray-800 flex items-center gap-2">
                  <span className="w-1 h-6 bg-indigo-500 rounded-full"></span>
                  Question Distribution
                </h3>
                {currentCalculatedMarks !== null && (
                    <div className={`text-sm font-bold px-3 py-1 rounded-full ${currentCalculatedMarks === totalMarks ? 'bg-green-100 text-green-700' : 'bg-orange-100 text-orange-700'}`}>
                        Current: {currentCalculatedMarks} / {totalMarks} Marks
                    </div>
                )}
                {currentCalculatedMarks === null && (
                     <div className="text-sm font-bold px-3 py-1 rounded-full bg-gray-100 text-gray-500">
                        Total Pending...
                     </div>
                )}
            </div>

            <div className="grid grid-cols-2 md:grid-cols-3 gap-6 mb-6">
              {QUESTION_SPECS.map((item) => {
                const isError = !!errors[item.key];
                return (
                    <div key={item.key} className="relative">
                        <div className={`p-3 rounded-lg border ${isError ? 'bg-red-50 border-red-200' : 'bg-gray-50 border-gray-100'} transition-colors`}>
                            <label className={`block text-xs font-bold uppercase mb-1 ${isError ? 'text-red-700' : 'text-gray-700'}`}>
                                {item.label}
                            </label>
                            <input
                                type="number"
                                min="0"
                                placeholder="Enter number of questions"
                                className={`w-full px-3 py-1.5 rounded border bg-white focus:ring-1 outline-none text-gray-900 placeholder:text-gray-400 text-sm
                                    ${isError 
                                        ? 'border-red-500 focus:border-red-500 focus:ring-red-200' 
                                        : 'border-gray-200 focus:border-indigo-500 focus:ring-indigo-500'}`}
                                value={counts[item.key]}
                                onChange={(e) => handleCountChange(item.key, e.target.value)}
                                onBlur={() => handleBlur(item.key)}
                            />
                            <p className="text-xs text-gray-500 mt-1">{item.marks} Mark{item.marks > 1 ? 's' : ''} each</p>
                        </div>
                        {errors[item.key] && (
                            <p className="absolute -bottom-5 left-0 text-xs font-bold text-red-500 animate-fade-in">
                                {errors[item.key]}
                            </p>
                        )}
                    </div>
                );
              })}
            </div>

            {/* Detailed Summary Table */}
            <div className="overflow-hidden border border-gray-200 rounded-lg shadow-sm mt-8">
                <table className="min-w-full text-sm">
                    <thead className="bg-gray-50 text-gray-700 border-b border-gray-200">
                        <tr>
                            <th className="px-4 py-2 text-left font-semibold">Question Type</th>
                            <th className="px-4 py-2 text-center font-semibold">Marks/Q</th>
                            <th className="px-4 py-2 text-center font-semibold">Count</th>
                            <th className="px-4 py-2 text-right font-semibold">Total</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-100">
                        {QUESTION_SPECS.map((spec) => (
                            <tr key={spec.key} className="bg-white hover:bg-gray-50 transition-colors">
                                <td className="px-4 py-2 text-gray-800 font-medium">{spec.label}</td>
                                <td className="px-4 py-2 text-center text-gray-600">{spec.marks}</td>
                                <td className="px-4 py-2 text-center text-gray-600 font-medium">
                                    {counts[spec.key] === '' ? '-' : counts[spec.key]}
                                </td>
                                <td className="px-4 py-2 text-right font-semibold text-gray-800">
                                    {counts[spec.key] === '' ? '-' : (parseInt(counts[spec.key]) * spec.marks)}
                                </td>
                            </tr>
                        ))}
                        <tr className="bg-indigo-50 font-bold border-t-2 border-indigo-100">
                            <td className="px-4 py-3 text-indigo-900">Grand Total</td>
                            <td className="px-4 py-3 text-center">-</td>
                            <td className="px-4 py-3 text-center text-indigo-900">
                                {currentCalculatedMarks === null ? '-' : QUESTION_SPECS.reduce((acc, spec) => acc + (parseInt(counts[spec.key]) || 0), 0)}
                            </td>
                            <td className={`px-4 py-3 text-right text-lg ${currentCalculatedMarks !== totalMarks ? 'text-orange-600' : 'text-indigo-900'}`}>
                                {currentCalculatedMarks === null ? 'Pending...' : currentCalculatedMarks}
                            </td>
                        </tr>
                    </tbody>
                </table>
            </div>
            {currentCalculatedMarks !== null && currentCalculatedMarks !== totalMarks && (
                <p className="text-xs text-orange-600 mt-2 text-right font-medium">
                    * Total does not match required marks. Please adjust counts or use Auto Distribute.
                </p>
            )}
            {currentCalculatedMarks === null && (
                 <p className="text-xs text-red-600 mt-2 text-right font-medium">
                    * Please fill in all question fields to calculate totals.
                </p>
            )}
          </div>

          {/* Actions */}
          <div className="flex justify-end gap-3 pt-4">
            <button
              type="button"
              onClick={onCancel}
              className="px-6 py-2.5 rounded-lg text-gray-600 font-medium hover:bg-gray-100 transition-colors"
              disabled={isGenerating}
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={isGenerating || currentCalculatedMarks === null || currentCalculatedMarks === 0}
              className={`px-8 py-2.5 rounded-lg text-white font-bold shadow-lg transition-all flex items-center gap-2
                ${isGenerating || currentCalculatedMarks === null || currentCalculatedMarks === 0
                  ? 'bg-indigo-400 cursor-not-allowed' 
                  : 'bg-indigo-600 hover:bg-indigo-700 hover:shadow-indigo-500/30 active:scale-95'
                }`}
            >
              {isGenerating ? (
                <>
                  <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                  Generating...
                </>
              ) : (
                'Generate Paper'
              )}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

