import React, { useState, useEffect } from 'react';
import { PaperConfig, QuestionCounts } from '../types';
import { CBSE_CURRICULUM, GRADES } from '../constants';

// Defined Weights and Specs
const QUESTION_SPECS: { label: string; key: keyof QuestionCounts; marks: number }[] = [
  { label: "MCQs", key: "mcq", marks: 1 },
  { label: "Assertion-Reason", key: "ar", marks: 1 },
  { label: "Very Short (VSAQ)", key: "vsaq", marks: 2 },
  { label: "Short Answer (SAQ)", key: "saq", marks: 3 },
  { label: "Case Study", key: "caseStudy", marks: 4 },
  { label: "Long Answer (LAQ)", key: "laq", marks: 5 },
];

interface PaperFormProps {
  onGenerate: (config: PaperConfig) => void;
  onCancel: () => void;
  isGenerating: boolean;
}

const PaperForm: React.FC<PaperFormProps> = ({ onGenerate, onCancel, isGenerating }) => {
  const [schoolName, setSchoolName] = useState('');
  const [schoolNameError, setSchoolNameError] = useState<string | null>(null);

  const [schoolLogo, setSchoolLogo] = useState<string | null>(null);
  const [logoPlacement, setLogoPlacement] = useState<'left' | 'center' | 'right'>('left');
  const [logoError, setLogoError] = useState<string | null>(null);

  const [selectedClass, setSelectedClass] = useState('');
  const [selectedSubject, setSelectedSubject] = useState('');
  const [selectedTopic, setSelectedTopic] = useState('');

  const [totalMarks, setTotalMarks] = useState(50);
  const [difficulty, setDifficulty] = useState<'Easy' | 'Medium' | 'Hard'>('Medium');

  // State for counts is now Record<Key, string> to allow empty values
  const [counts, setCounts] = useState<Record<keyof QuestionCounts, string>>({
    mcq: '',
    ar: '',
    vsaq: '',
    saq: '',
    laq: '',
    caseStudy: '',
  });

  const [errors, setErrors] = useState<Record<keyof QuestionCounts, string | null>>({
    mcq: null,
    ar: null,
    vsaq: null,
    saq: null,
    laq: null,
    caseStudy: null,
  });

  const [currentCalculatedMarks, setCurrentCalculatedMarks] = useState<number | null>(null);

  // Update calculation whenever counts change
  useEffect(() => {
    const allFieldsFilled = QUESTION_SPECS.every(spec => counts[spec.key] !== '');

    if (allFieldsFilled) {
      const total = QUESTION_SPECS.reduce((acc, spec) => {
        const val = parseInt(counts[spec.key]) || 0;
        return acc + (val * spec.marks);
      }, 0);
      setCurrentCalculatedMarks(total);
    } else {
      setCurrentCalculatedMarks(null);
    }
  }, [counts]);

  const validateField = (key: keyof QuestionCounts, value: string) => {
    if (value === '') {
      return 'This field is required';
    }
    const num = parseInt(value);
    if (isNaN(num) || num < 0) {
      return 'Invalid number';
    }
    return null;
  };

  const handleSchoolNameChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setSchoolName(e.target.value);
    if (e.target.value.trim() !== '') {
        setSchoolNameError(null);
    }
  };

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    // Reset errors
    setLogoError(null);

    // Validate Size (2MB)
    if (file.size > 2 * 1024 * 1024) {
      setLogoError("File size exceeds 2MB limit.");
      return;
    }

    // Validate Type
    if (!['image/png', 'image/jpeg', 'image/jpg'].includes(file.type)) {
      setLogoError("Only PNG and JPG formats are allowed.");
      return;
    }

    const reader = new FileReader();
    reader.onload = (event) => {
      setSchoolLogo(event.target?.result as string);
    };
    reader.readAsDataURL(file);
  };

  const handleRemoveLogo = () => {
    setSchoolLogo(null);
    setLogoError(null);
    const input = document.getElementById('logo-upload') as HTMLInputElement;
    if (input) input.value = '';
  };

  const handleCountChange = (key: keyof QuestionCounts, value: string) => {
    // Prevent non-numeric characters (except empty string)
    if (value !== '' && !/^\d+$/.test(value)) return;

    setCounts(prev => ({ ...prev, [key]: value }));

    // Clear error immediately if valid, or validate if it was previously errored
    if (value !== '') {
        setErrors(prev => ({ ...prev, [key]: null }));
    }
  };

  const handleBlur = (key: keyof QuestionCounts) => {
    const error = validateField(key, counts[key]);
    setErrors(prev => ({ ...prev, [key]: error }));
  };

  const handleClassChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    setSelectedClass(e.target.value);
    setSelectedSubject('');
    setSelectedTopic('');
  };

  const handleSubjectChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    setSelectedSubject(e.target.value);
    setSelectedTopic('');
  };

  const handleAutoDistribute = () => {
    let newCounts: Record<keyof QuestionCounts, number> = { mcq: 0, ar: 0, vsaq: 0, saq: 0, laq: 0, caseStudy: 0 };
    let currentSum = 0;

    // 1. Minimum 1 each if mathematically possible
    for (const spec of QUESTION_SPECS) {
        if (currentSum + spec.marks <= totalMarks) {
            newCounts[spec.key]++;
            currentSum += spec.marks;
        }
    }

    // 2. Distribute remainder
    while (currentSum < totalMarks) {
        const candidates = QUESTION_SPECS.filter(spec => currentSum + spec.marks <= totalMarks);
        if (candidates.length === 0) break;

        // Sort candidates by current count (ascending) to maintain balance
        candidates.sort((a, b) => newCounts[a.key] - newCounts[b.key]);

        const bestSpec = candidates[0];
        newCounts[bestSpec.key]++;
        currentSum += bestSpec.marks;
    }

    // Convert to strings for state
    const stringCounts: any = {};
    QUESTION_SPECS.forEach(spec => {
        stringCounts[spec.key] = newCounts[spec.key].toString();
    });

    setCounts(stringCounts);
    // Clear all errors
    setErrors({ mcq: null, ar: null, vsaq: null, saq: null, laq: null, caseStudy: null });
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    let hasErrors = false;

    // Validate School Name
    if (schoolName.trim() === '') {
        setSchoolNameError('This field is required');
        hasErrors = true;
    }

    // Validate all fields
    const newErrors: any = {};

    QUESTION_SPECS.forEach(spec => {
        const error = validateField(spec.key, counts[spec.key]);
        if (error) {
            hasErrors = true;
            newErrors[spec.key] = error;
        }
    });

    if (hasErrors) {
        setErrors(newErrors);
        return;
    }

    // Convert strings to final QuestionCounts number object
    const finalCounts: any = {};
    QUESTION_SPECS.forEach(spec => {
        finalCounts[spec.key] = parseInt(counts[spec.key]);
    });

    let fullSubject = selectedSubject;
    let fullTopic = '';

    if (selectedTopic === 'All Topics') {
        const allChapters = CBSE_CURRICULUM[selectedClass][selectedSubject].join(', ');
        fullSubject = `${selectedSubject} - All Topics`;
        fullTopic = `Covering: ${allChapters}`;
    } else if (selectedTopic) {
        fullSubject = `${selectedSubject}`;
        fullTopic = selectedTopic;
    }

    // Combine for the prompt config
    const finalSubjectString = `${fullSubject}: ${fullTopic}`;

    onGenerate({
      schoolName: schoolName.trim(),
      schoolLogo: schoolLogo || undefined,
      logoPlacement,
      subject: finalSubjectString,
      grade: selectedClass,
      totalMarks,
      difficulty,
      counts: finalCounts as QuestionCounts
    });
  };

  // Get subjects based on selected class
  const availableSubjects = selectedClass ? Object.keys(CBSE_CURRICULUM[selectedClass] || {}) : [];

  // Get topics based on selected class and subject
  const availableTopics = (selectedClass && selectedSubject) 
    ? CBSE_CURRICULUM[selectedClass][selectedSubject] || [] 
    : [];

  return (
    <div className="max-w-3xl mx-auto p-6">
      <div className="bg-white rounded-2xl shadow-lg border border-gray-100 overflow-hidden">
        <div className="p-6 bg-indigo-50 border-b border-indigo-100">
            <h2 className="text-2xl font-bold text-indigo-900">Configure Paper</h2>
            <p className="text-indigo-600 text-sm mt-1">Define the parameters for your AI-generated assessment.</p>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-8">

          {/* Header Configuration (School Name & Logo) */}
          <div className="bg-gray-50 p-6 rounded-xl border border-gray-200 space-y-6">
             <h3 className="text-lg font-bold text-gray-800 border-b pb-2 mb-4">Header Branding</h3>

             {/* School Name */}
             <div>
                <label className="block text-sm font-bold text-gray-800 mb-2">School Name <span className="text-red-500">*</span></label>
                <input
                    type="text"
                    className={`w-full px-4 py-3 rounded-lg border bg-white focus:ring-2 outline-none transition-all text-gray-900 placeholder:text-gray-400
                        ${schoolNameError ? 'border-red-500 focus:ring-red-200 focus:border-red-500' : 'border-gray-300 focus:ring-indigo-500 focus:border-indigo-500'}`}
                    placeholder="Enter the full name of the School / Institution"
                    value={schoolName}
                    onChange={handleSchoolNameChange}
                />
                {schoolNameError && (
                    <p className="text-red-600 text-sm font-bold mt-1.5 animate-fade-in">{schoolNameError}</p>
                )}
             </div>

             {/* Logo Section */}
             <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                    <label className="block text-sm font-bold text-gray-800 mb-2">Upload School Logo <span className="text-gray-400 font-normal">(Optional)</span></label>
                    <div className="relative border-2 border-dashed border-gray-300 rounded-lg p-4 bg-white hover:border-indigo-400 transition-colors text-center">
                        {!schoolLogo ? (
                            <>
                                <input 
                                    type="file" 
                                    id="logo-upload"
                                    accept="image/png, image/jpeg, image/jpg"
                                    onChange={handleLogoUpload}
                                    className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                                />
                                <div className="flex flex-col items-center justify-center text-gray-500 py-2">
                                    <svg className="w-8 h-8 mb-2 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"></path>
                                    </svg>
                                    <span className="text-sm font-medium">Click to upload logo</span>
                                    <span className="text-xs text-gray-400 mt-1">PNG, JPG (Max 2MB)</span>
                                </div>
                            </>
                        ) : (
                            <div className="flex items-center gap-4">
                                <div className="w-16 h-16 relative border rounded bg-gray-100 flex items-center justify-center overflow-hidden">
                                    <img src={schoolLogo} alt="Preview" className="w-full h-full object-contain" />
                                </div>
                                <div className="text-left flex-1">
