import React from 'react';

interface MarkdownRendererProps {
  content: string;
  className?: string;
  headingFont?: string;
  bodyFont?: string;
}

// A simple parser to handle basic Markdown structures used in the papers
// This avoids needing 'react-markdown' or other heavy libs in this specific environment
const MarkdownRenderer: React.FC<MarkdownRendererProps> = ({ 
    content, 
    className,
    headingFont = 'inherit',
    bodyFont = 'inherit'
}) => {
  const lines = content.split('\n');

  return (
    <div className={`space-y-3 ${className}`}>
      {lines.map((line, index) => {
        // Headers
        if (line.startsWith('### ')) {
          return <h3 key={index} style={{ fontFamily: headingFont }} className="text-lg font-bold mt-4 mb-2">{line.replace('### ', '')}</h3>;
        }
        if (line.startsWith('## ')) {
          return <h2 key={index} style={{ fontFamily: headingFont }} className="text-xl font-bold mt-6 mb-3 border-b pb-1">{line.replace('## ', '')}</h2>;
        }
        if (line.startsWith('# ')) {
          return <h1 key={index} style={{ fontFamily: headingFont }} className="text-2xl font-bold mt-8 mb-4 text-center uppercase">{line.replace('# ', '')}</h1>;
        }

        // Implicit Headers (common in the plain text output like "SECTION A")
        if (line.trim().match(/^SECTION\s+[A-Z0-9]+:/i) || line.trim().match(/^PART\s+[A-Z0-9]+:/i)) {
             return <h3 key={index} style={{ fontFamily: headingFont }} className="text-lg font-bold mt-6 mb-2 uppercase">{line}</h3>;
        }

        // Horizontal Rules
        if (line.trim() === '---' || line.trim() === '***') {
          return <hr key={index} className="my-6 border-gray-300" />;
        }

        // List Items (Simple)
        if (line.trim().match(/^(\d+\.|-|\*)\s/)) {
            // Very basic bold handling: **text** -> <b>text</b>
            const parts = line.split(/(\*\*.*?\*\*)/g);
            return (
                <div key={index} className="ml-4 flex" style={{ fontFamily: bodyFont }}>
                    <span className="mr-2">{line.trim().charAt(0) === '-' || line.trim().charAt(0) === '*' ? '•' : ''}</span>
                    <p className="whitespace-pre-wrap">
                        {parts.map((part, i) => {
                             if (part.startsWith('**') && part.endsWith('**')) {
                                 return <strong key={i}>{part.slice(2, -2)}</strong>;
                             }
                             return part;
                        })}
                    </p>
                </div>
            )
        }

        // Empty lines
        if (line.trim() === '') {
          return <div key={index} className="h-2"></div>;
        }

        // Paragraphs with Bold support
        const parts = line.split(/(\*\*.*?\*\*)/g);
        return (
          <p key={index} style={{ fontFamily: bodyFont }} className="whitespace-pre-wrap leading-relaxed text-gray-800">
            {parts.map((part, i) => {
              if (part.startsWith('**') && part.endsWith('**')) {
                return <strong key={i}>{part.slice(2, -2)}</strong>;
              }
              return part;
            })}
          </p>
        );
      })}
    </div>
  );
};

