import React, { useState, useRef } from 'react';
import { GeneratedPaper } from '../types';
import MarkdownRenderer from './MarkdownRenderer';
import { FONT_OPTIONS } from '../constants';

interface PaperPreviewProps {
  paper: GeneratedPaper;
  onBack: () => void;
}

const PaperPreview: React.FC<PaperPreviewProps> = ({ paper, onBack }) => {
  const [showAnswerKey, setShowAnswerKey] = useState(false);
  const [downloadFormat, setDownloadFormat] = useState<'pdf' | 'word' | 'txt'>('pdf');
  const printRef = useRef<HTMLDivElement>(null);

  const { schoolName, schoolLogo, logoPlacement, headingFont, bodyFont, generalInstructions } = paper.config;

  // Defaults if not set (backwards compatibility for old records)
  const timeAllowed = paper.config.timeAllowed || '2 Hours';
  const effectiveHeadingFont = headingFont || FONT_OPTIONS[0].value;
  const effectiveBodyFont = bodyFont || FONT_OPTIONS[1].value;

  // --- Export Handlers ---

  const handleDownload = () => {
    switch (downloadFormat) {
      case 'txt':
        exportToText();
        break;
      case 'pdf':
        exportToPdf();
        break;
      case 'word':
        exportToWord();
        break;
    }
  };

  const exportToText = () => {
    // Generate instruction text for download file
    const instructionsText = generalInstructions 
        ? `\nGeneral Instructions:\n${generalInstructions}\n`
        : `\nGeneral Instructions:\n- All questions are compulsory.\n- The question paper has been divided into multiple sections.\n- Calculators are not permitted unless specified.\n`;

    const cleanTitleBlock = `
${paper.title}
Time Allowed: ${timeAllowed} | Total Marks: ${paper.config.totalMarks}
`;

    const fileContent = `
${paper.config.schoolName.toUpperCase()}
${cleanTitleBlock}
${instructionsText}
${paper.content}

========================================
ANSWER KEY
========================================

${paper.answerKey}
    `;

    const blob = new Blob([fileContent], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${paper.title.replace(/\s+/g, '_')}_${showAnswerKey ? 'Key' : 'Paper'}.txt`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const exportToPdf = () => {
    if (!printRef.current) return;

    // We clone the element to modify it slightly for PDF if needed, 
    // but usually direct export is fine.
    const element = printRef.current;

    const opt = {
      margin: [0.5, 0.5, 0.5, 0.5], // top, left, bottom, right
      filename: `${paper.title.replace(/\s+/g, '_')}_${showAnswerKey ? 'AnswerKey' : 'QuestionPaper'}.pdf`,
      image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { scale: 2, useCORS: true },
      jsPDF: { unit: 'in', format: 'a4', orientation: 'portrait' }
    };

    // Use html2pdf from window
    (window as any).html2pdf().set(opt).from(element).save();
  };

  const exportToWord = () => {
    if (!printRef.current) return;

    // Construct a simple HTML document for Word
    const preHtml = `<html xmlns:o='urn:schemas-microsoft-com:office:office' 
xmlns:w='urn:schemas-microsoft-com:office:word' 
xmlns='http://www.w3.org/TR/REC-html40'>
<head><meta charset='utf-8'><title>${paper.title}</title>
<style>
body { font-family: sans-serif; }
</style>
</head><body>`;
    const postHtml = "</body></html>";

    // Get the inner HTML of the paper container
    const html = preHtml + printRef.current.innerHTML + postHtml;

    const blob = new Blob(['\ufeff', html], {
        type: 'application/msword'
    });

    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    // Note: saving as .doc is more reliable for HTML-based Word docs than .docx to avoid XML warnings
    a.download = `${paper.title.replace(/\s+/g, '_')}_${showAnswerKey ? 'AnswerKey' : 'QuestionPaper'}.doc`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };


  // Logic to determine layout class based on placement
  let headerLayoutClass = "flex flex-row items-center justify-center gap-6"; // Default Left
  let textAlignClass = "text-center"; // Default text align

  if (logoPlacement === 'center') {
      headerLayoutClass = "flex flex-col items-center justify-center gap-4";
  } else if (logoPlacement === 'right') {
      headerLayoutClass = "flex flex-row-reverse items-center justify-center gap-6";
  }

  return (
    <div className="max-w-5xl mx-auto p-4 sm:p-8 animate-fade-in pb-20">

      {/* Top Controls */}
      <div className="flex flex-col md:flex-row justify-between items-center mb-8 gap-4 sticky top-0 bg-white/90 backdrop-blur-sm p-4 rounded-xl shadow-sm z-10 border border-gray-100">
        <button 
          onClick={onBack}
          className="text-gray-600 hover:text-gray-900 flex items-center gap-2 font-medium"
        >
          ← Back to Dashboard
        </button>

        <div className="flex flex-wrap gap-3 items-center justify-end">
          <button 
            onClick={() => setShowAnswerKey(!showAnswerKey)}
            className="px-4 py-2 border border-indigo-200 text-indigo-700 rounded-lg hover:bg-indigo-50 font-medium transition-colors text-sm"
          >
            {showAnswerKey ? 'Show Question Paper' : 'Show Answer Key'}
          </button>

          <div className="flex items-center gap-2 bg-indigo-50 p-1 rounded-lg border border-indigo-100">
              <select 
                value={downloadFormat}
                onChange={(e) => setDownloadFormat(e.target.value as any)}
                className="bg-white border-0 text-gray-800 text-sm rounded-md focus:ring-2 focus:ring-indigo-500 py-1.5 pl-3 pr-8 shadow-sm cursor-pointer hover:bg-gray-50"
              >
                <option value="pdf">PDF (.pdf)</option>
                <option value="word">Word (.doc)</option>
                <option value="txt">Text (.txt)</option>
              </select>
              <button 
                onClick={handleDownload}
                className="px-4 py-1.5 bg-indigo-600 text-white rounded-md hover:bg-indigo-700 shadow-sm transition-all font-bold text-sm flex items-center gap-2"
              >
                Download
              </button>
          </div>
        </div>
      </div>

      {/* Paper View Container - This is what gets printed/exported */}
      <div 
        ref={printRef}
        className="bg-white shadow-xl shadow-gray-200/50 rounded-lg overflow-hidden min-h-[800px] border border-gray-200"
      >
        {/* Header Section representing a real paper header */}
        <div className="bg-white p-8 sm:p-12 border-b-2 border-gray-800">

            {/* Logo + School Name Container */}
            <div className={headerLayoutClass}>
                {schoolLogo && (
                    <div className="flex-shrink-0">
                        <img 
                            src={schoolLogo} 
                            alt="School Logo" 
                            className="h-20 w-auto object-contain max-w-[150px]" 
                        />
                    </div>
                )}

                <div className={textAlignClass}>
                     {schoolName && (
                        <h2 style={{ fontFamily: effectiveHeadingFont }} className="text-4xl font-bold text-gray-900 uppercase tracking-widest leading-tight">
                            {schoolName}
                        </h2>
                    )}
                </div>
            </div>

            {/* Exam Details - Clean Format */}
            <div className="text-center mt-8">
                <h1 style={{ fontFamily: effectiveHeadingFont }} className="text-2xl font-bold text-gray-800 mb-2">
                    {paper.title}
                </h1>

                {/* Time | Marks Line */}
                <p style={{ fontFamily: effectiveBodyFont }} className="text-lg text-gray-800 font-medium mt-1">
                    Time Allowed: {timeAllowed} &nbsp;|&nbsp; Total Marks: {paper.config.totalMarks}
                </p>
            </div>
        </div>

        <div className="p-8 sm:p-16">
            {showAnswerKey ? (
                <div className="animate-fade-in">
                    <div className="bg-yellow-50 border-l-4 border-yellow-400 p-4 mb-8">
                        <h2 className="text-yellow-800 font-bold uppercase tracking-wide text-sm">Confidential: Marking Scheme & Answer Key</h2>
                    </div>
                    <MarkdownRenderer 
                        content={paper.answerKey} 
                        headingFont={effectiveHeadingFont} 
                        bodyFont={effectiveBodyFont} 
                    />
                </div>
            ) : (
                <div className="animate-fade-in">
                    <div className="text-sm text-gray-800 mb-8 p-4 bg-gray-50 rounded border border-gray-200">
                        <strong className="block mb-2 text-gray-900 uppercase tracking-wide text-xs">General Instructions:</strong>
                        {generalInstructions ? (
                            <div style={{ fontFamily: effectiveBodyFont, whiteSpace: 'pre-wrap' }} className="text-gray-800 leading-relaxed">
                                {generalInstructions}
                            </div>
                        ) : (
                            <ul className="list-disc ml-5 space-y-1" style={{ fontFamily: effectiveBodyFont }}>
                                <li>All questions are compulsory.</li>
                                <li>The question paper has been divided into multiple sections based on the format requested.</li>
                                <li>Calculators are not permitted unless specified.</li>
                            </ul>
                        )}
                    </div>
                    <MarkdownRenderer 
                        content={paper.content} 
                        headingFont={effectiveHeadingFont} 
                        bodyFont={effectiveBodyFont} 
                    />
                </div>
            )}
        </div>
      </div>
    </div>
  );
};

export default PaperPreview;

import React, { useState, useEffect } from 'react';
import { PaperConfig, QuestionCounts } from '../types';
import { CBSE_CURRICULUM, GRADES, FONT_OPTIONS } from '../constants';

// Defined Weights and Specs
const QUESTION_SPECS: { label: string; key: keyof QuestionCounts; marks: number }[] = [
  { label: "MCQs", key: "mcq", marks: 1 },
  { label: "Assertion-Reason", key: "ar", marks: 1 },
  { label: "Very Short (VSAQ)", key: "vsaq", marks: 2 },
  { label: "Short Answer (SAQ)", key: "saq", marks: 3 },
  { label: "Case Study", key: "caseStudy", marks: 4 },
  { label: "Long Answer (LAQ)", key: "laq", marks: 5 },
];

interface PaperFormProps {
  onGenerate: (config: PaperConfig) => void;
  onCancel: () => void;
  isGenerating: boolean;
}

const PaperForm: React.FC<PaperFormProps> = ({ onGenerate, onCancel, isGenerating }) => {
  const [schoolName, setSchoolName] = useState('');
  const [schoolNameError, setSchoolNameError] = useState<string | null>(null);

  const [schoolLogo, setSchoolLogo] = useState<string | null>(null);
  const [logoPlacement, setLogoPlacement] = useState<'left' | 'center' | 'right'>('left');
  const [logoError, setLogoError] = useState<string | null>(null);

  // Typography State
  const [headingFont, setHeadingFont] = useState(FONT_OPTIONS[0].value);
  const [bodyFont, setBodyFont] = useState(FONT_OPTIONS[1].value);

  // General Instructions State
  const [generalInstructions, setGeneralInstructions] = useState('');
  const MAX_INSTRUCTION_CHARS = 500;

  const [selectedClass, setSelectedClass] = useState('');
  const [selectedSubject, setSelectedSubject] = useState('');
  const [selectedTopic, setSelectedTopic] = useState('');

  // Time Allowed State
  const [timeAllowed, setTimeAllowed] = useState('2 Hours');
  const [timePreset, setTimePreset] = useState('2 Hours');
  const [customTime, setCustomTime] = useState('');
  const [timeAllowedError, setTimeAllowedError] = useState<string | null>(null);

  const [totalMarks, setTotalMarks] = useState(50);
  const [difficulty, setDifficulty] = useState<'Easy' | 'Medium' | 'Hard'>('Medium');

  // State for counts is now Record<Key, string> to allow empty values
  const [counts, setCounts] = useState<Record<keyof QuestionCounts, string>>({
    mcq: '',
    ar: '',
    vsaq: '',
    saq: '',
    laq: '',
    caseStudy: '',
  });

  const [errors, setErrors] = useState<Record<keyof QuestionCounts, string | null>>({
    mcq: null,
    ar: null,
    vsaq: null,
    saq: null,
    laq: null,
    caseStudy: null,
  });

  const [currentCalculatedMarks, setCurrentCalculatedMarks] = useState<number | null>(null);

  // Update calculation whenever counts change
  useEffect(() => {
    const allFieldsFilled = QUESTION_SPECS.every(spec => counts[spec.key] !== '');

    if (allFieldsFilled) {
      const total = QUESTION_SPECS.reduce((acc, spec) => {
        const val = parseInt(counts[spec.key]) || 0;
        return acc + (val * spec.marks);
      }, 0);
      setCurrentCalculatedMarks(total);
    } else {
      setCurrentCalculatedMarks(null);
    }
  }, [counts]);

  const validateField = (key: keyof QuestionCounts, value: string) => {
    if (value === '') {
      return 'This field is required';
    }
    const num = parseInt(value);
    if (isNaN(num) || num < 0) {
      return 'Invalid number';
    }
    return null;
  };

  const handleSchoolNameChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setSchoolName(e.target.value);
    if (e.target.value.trim() !== '') {
        setSchoolNameError(null);
    }
  };

  const handlePresetChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const val = e.target.value;
    setTimePreset(val);

    if (val === 'Custom') {
        setTimeAllowed(customTime);
        // Do not clear error immediately if custom is empty, wait for typing or submit
    } else {
        setTimeAllowed(val);
        setTimeAllowedError(null);
    }
  };

  const handleCustomTimeChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      const val = e.target.value;
      setCustomTime(val);
      if (timePreset === 'Custom') {
        setTimeAllowed(val);
        if (val.trim() !== '') {
            setTimeAllowedError(null);
        }
      }
  };

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    // Reset errors
    setLogoError(null);

    // Validate Size (2MB)
    if (file.size > 2 * 1024 * 1024) {
      setLogoError("File size exceeds 2MB limit.");
      return;
    }

    // Validate Type
    if (!['image/png', 'image/jpeg', 'image/jpg'].includes(file.type)) {
      setLogoError("Only PNG and JPG formats are allowed.");
      return;
    }

    const reader = new FileReader();
    reader.onload = (event) => {
      setSchoolLogo(event.target?.result as string);
    };
    reader.readAsDataURL(file);
  };

  const handleRemoveLogo = () => {
    setSchoolLogo(null);
    setLogoError(null);
    const input = document.getElementById('logo-upload') as HTMLInputElement;
    if (input) input.value = '';
  };

  const handleCountChange = (key: keyof QuestionCounts, value: string) => {
    // Prevent non-numeric characters (except empty string)
    if (value !== '' && !/^\d+$/.test(value)) return;

    setCounts(prev => ({ ...prev, [key]: value }));

    // Clear error immediately if valid, or validate if it was previously errored
    if (value !== '') {
        setErrors(prev => ({ ...prev, [key]: null }));
    }
  };

  const handleBlur = (key: keyof QuestionCounts) => {
    const error = validateField(key, counts[key]);
    setErrors(prev => ({ ...prev, [key]: error }));
  };

  const handleClassChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    setSelectedClass(e.target.value);
    setSelectedSubject('');
    setSelectedTopic('');
  };

  const handleSubjectChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    setSelectedSubject(e.target.value);
    setSelectedTopic('');
  };

  const handleAutoDistribute = () => {
    let newCounts: Record<keyof QuestionCounts, number> = { mcq: 0, ar: 0, vsaq: 0, saq: 0, laq: 0, caseStudy: 0 };
    let currentSum = 0;

    // 1. Minimum 1 each if mathematically possible
    for (const spec of QUESTION_SPECS) {
        if (currentSum + spec.marks <= totalMarks) {
            newCounts[spec.key]++;
            currentSum += spec.marks;
        }
    }

    // 2. Distribute remainder
    while (currentSum < totalMarks) {
        const candidates = QUESTION_SPECS.filter(spec => currentSum + spec.marks <= totalMarks);
        if (candidates.length === 0) break;

        // Sort candidates by current count (ascending) to maintain balance
        candidates.sort((a, b) => newCounts[a.key] - newCounts[b.key]);

        const bestSpec = candidates[0];
        newCounts[bestSpec.key]++;
        currentSum += bestSpec.marks;
    }

    // Convert to strings for state
    const stringCounts: any = {};
    QUESTION_SPECS.forEach(spec => {
        stringCounts[spec.key] = newCounts[spec.key].toString();
    });

    setCounts(stringCounts);
    // Clear all errors
    setErrors({ mcq: null, ar: null, vsaq: null, saq: null, laq: null, caseStudy: null });
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    let hasErrors = false;

    // Validate School Name
    if (schoolName.trim() === '') {
        setSchoolNameError('This field is required');
        hasErrors = true;
    }

    // Validate Time Allowed
    if (timeAllowed.trim() === '') {
        setTimeAllowedError('This field is required');
        hasErrors = true;
    } else if (!/\d/.test(timeAllowed)) {
        setTimeAllowedError('Time must contain a number (e.g., 30 Minutes)');
        hasErrors = true;
    }

    // Validate all fields
    const newErrors: any = {};

    QUESTION_SPECS.forEach(spec => {
        const error = validateField(spec.key, counts[spec.key]);
        if (error) {
            hasErrors = true;
            newErrors[spec.key] = error;
        }
    });

    if (hasErrors) {
        setErrors(newErrors);
        return;
    }

    // Convert strings to final QuestionCounts number object
    const finalCounts: any = {};
    QUESTION_SPECS.forEach(spec => {
        finalCounts[spec.key] = parseInt(counts[spec.key]);
    });

    let fullSubject = selectedSubject;
    let fullTopic = '';

    if (selectedTopic === 'All Topics') {
        const allChapters = CBSE_CURRICULUM[selectedClass][selectedSubject].join(', ');
        fullSubject = `${selectedSubject} - All Topics`;
        fullTopic = `Covering: ${allChapters}`;
    } else if (selectedTopic) {
        fullSubject = `${selectedSubject}`;
        fullTopic = selectedTopic;
    }

    // Combine for the prompt config
    const finalSubjectString = `${fullSubject}: ${fullTopic}`;

    onGenerate({
      schoolName: schoolName.trim(),
      schoolLogo: schoolLogo || undefined,
      logoPlacement,
      headingFont,
      bodyFont,
      generalInstructions: generalInstructions.trim() || undefined,
      subject: finalSubjectString,
      grade: selectedClass,
      timeAllowed: timeAllowed.trim(),
      totalMarks,
      difficulty,
      counts: finalCounts as QuestionCounts
    });
  };

  // Get subjects based on selected class
  const availableSubjects = selectedClass ? Object.keys(CBSE_CURRICULUM[selectedClass] || {}) : [];

  // Get topics based on selected class and subject
  const availableTopics = (selectedClass && selectedSubject) 
    ? CBSE_CURRICULUM[selectedClass][selectedSubject] || [] 
    : [];

  return (
    <div className="max-w-3xl mx-auto p-6">
      <div className="bg-white rounded-2xl shadow-lg border border-gray-100 overflow-hidden">
        <div className="p-6 bg-indigo-50 border-b border-indigo-100">
            <h2 className="text-2xl font-bold text-indigo-900">Configure Paper</h2>
            <p className="text-indigo-600 text-sm mt-1">Define the parameters for your AI-generated assessment.</p>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-8">

          {/* Header Configuration (School Name & Logo) */}
          <div className="bg-gray-50 p-6 rounded-xl border border-gray-200 space-y-6">
             <h3 className="text-lg font-bold text-gray-800 border-b pb-2 mb-4">Header Branding & Typography</h3>

             {/* School Name */}
             <div>
                <label className="block text-sm font-bold text-gray-800 mb-2">School Name <span className="text-red-500">*</span></label>
                <input
                    type="text"
                    className={`w-full px-4 py-3 rounded-lg border bg-white focus:ring-2 outline-none transition-all text-gray-900 placeholder:text-gray-400
                        ${schoolNameError ? 'border-red-500 focus:ring-red-200 focus:border-red-500' : 'border-gray-300 focus:ring-indigo-500 focus:border-indigo-500'}`}
                    placeholder="Enter the full name of the School / Institution"
                    value={schoolName}
                    onChange={handleSchoolNameChange}
                />
                {schoolNameError && (
                    <p className="text-red-600 text-sm font-bold mt-1.5 animate-fade-in">{schoolNameError}</p>
                )}
             </div>

             {/* Logo Section */}
             <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                    <label className="block text-sm font-bold text-gray-800 mb-2">Upload School Logo <span className="text-gray-400 font-normal">(Optional)</span></label>
                    <div className="relative border-2 border-dashed border-gray-300 rounded-lg p-4 bg-white hover:border-indigo-400 transition-colors text-center">
                        {!schoolLogo ? (
                            <>
                                <input 
                                    type="file" 
                                    id="logo-upload"
                                    accept="image/png, image/jpeg, image/jpg"
                                    onChange={handleLogoUpload}
                                    className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                                />
                                <div className="flex flex-col items-center justify-center text-gray-500 py-2">
                                    <svg className="w-8 h-8 mb-2 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"></path>
                                    </svg>
                                    <span className="text-sm font-medium">Click to upload logo</span>
                                    <span className="text-xs text-gray-400 mt-1">PNG, JPG (Max 2MB)</span>
                                </div>
                            </>
                        ) : (
                            <div className="flex items-center gap-4">
                                <div className="w-16 h-16 relative border rounded bg-gray-100 flex items-center justify-center overflow-hidden">
                                    <img src={schoolLogo} alt="Preview" className="w-full h-full object-contain" />
                                </div>
                                <div className="text-left flex-1">
                                    <p className="text-sm font-bold text-green-600">Logo Uploaded</p>
                                    <button 
                                        type="button" 
                                        onClick={handleRemoveLogo}
                                        className="text-xs text-red-500 hover:text-red-700 underline mt-1"
                                    >
                                        Remove Logo
                                    </button>
                                </div>
                            </div>
                        )}
                    </div>
                    {logoError && <p className="text-red-600 text-xs font-bold mt-1.5">{logoError}</p>}
                </div>

                {/* Logo Placement */}
                <div>
                     <label className={`block text-sm font-bold mb-2 ${!schoolLogo ? 'text-gray-400' : 'text-gray-800'}`}>
                        Logo Placement
                     </label>
                     <div className="flex gap-2 mb-6">
                         {[
                             { id: 'left', label: 'Left', icon: 'M10 4H4v16h6V4zm2 0h8v2h-8V4zm0 4h8v2h-8V8zm0 4h8v2h-8zm0 4h8v2h-8v-2z' },
                             { id: 'center', label: 'Center', icon: 'M8 4h8v4H8V4zm-4 6h16v2H4v-2zm0 4h16v2H4v-2zm0 4h16v2H4v-2zm0 4h16v2H4v-2z' },
                             { id: 'right', label: 'Right', icon: 'M14 4h6v16h-6V4zM4 4h8v2H4V4zm0 4h8v2H4V8zm0 4h8v2H4v-2z' }
                         ].map((opt) => (
                             <label 
                                key={opt.id}
                                className={`flex-1 flex flex-col items-center justify-center p-2 rounded border cursor-pointer transition-all
                                    ${!schoolLogo ? 'opacity-50 pointer-events-none bg-gray-50 border-gray-100' : ''}
                                    ${logoPlacement === opt.id 
                                        ? 'bg-indigo-50 border-indigo-500 text-indigo-700' 
                                        : 'bg-white border-gray-200 text-gray-500 hover:bg-gray-50'
                                    }`}
                             >
                                 <input 
                                    type="radio" 
                                    name="logoPlacement" 
                                    value={opt.id}
                                    checked={logoPlacement === opt.id}
                                    onChange={(e) => setLogoPlacement(e.target.value as any)}
                                    className="sr-only"
                                    disabled={!schoolLogo}
                                 />
                                 <svg className="w-6 h-6 mb-1 opacity-70" fill="currentColor" viewBox="0 0 24 24">
                                     <path d={opt.icon}></path>
                                 </svg>
                                 <span className="text-xs font-semibold">{opt.label}</span>
                             </label>
                         ))}
                     </div>
                </div>
             </div>

             {/* Typography Selection */}
             <div className="grid grid-cols-1 md:grid-cols-2 gap-6 pt-4 border-t border-gray-200">
                <div>
                    <label className="block text-sm font-bold text-gray-800 mb-2">Heading Font</label>
                    <select
                        className="w-full px-4 py-2 rounded-lg border border-gray-300 bg-white focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all text-gray-900"
                        value={headingFont}
                        onChange={(e) => setHeadingFont(e.target.value)}
                    >
                        {FONT_OPTIONS.map((font) => (
                            <option key={font.value} value={font.value} style={{ fontFamily: font.value }}>{font.label}</option>
                        ))}
                    </select>
                </div>
                <div>
                    <label className="block text-sm font-bold text-gray-800 mb-2">Body Font</label>
                    <select
                        className="w-full px-4 py-2 rounded-lg border border-gray-300 bg-white focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all text-gray-900"
                        value={bodyFont}
                        onChange={(e) => setBodyFont(e.target.value)}
                    >
                        {FONT_OPTIONS.map((font) => (
                            <option key={font.value} value={font.value} style={{ fontFamily: font.value }}>{font.label}</option>
                        ))}
                    </select>
                </div>
             </div>
          </div>

          {/* General Instructions Input */}
          <div className="bg-gray-50 p-6 rounded-xl border border-gray-200">
             <div className="flex justify-between items-center mb-2">
                <label className="block text-sm font-bold text-gray-800">General Instructions</label>
                <span className={`text-xs font-medium ${generalInstructions.length > MAX_INSTRUCTION_CHARS ? 'text-red-500' : 'text-gray-500'}`}>
                    {generalInstructions.length} / {MAX_INSTRUCTION_CHARS}
                </span>
             </div>
             <textarea
                className="w-full px-4 py-3 rounded-lg border border-gray-300 bg-white focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all text-gray-900 placeholder:text-gray-400 h-28 resize-y"
                placeholder="Enter general instructions for the question paper (e.g., Answer all questions, Use of calculator allowed, etc.)"
                value={generalInstructions}
                onChange={(e) => {
                    if (e.target.value.length <= MAX_INSTRUCTION_CHARS) {
                        setGeneralInstructions(e.target.value);
                    }
                }}
             />
             <p className="text-xs text-gray-500 mt-2">These instructions will appear at the top of the generated paper.</p>
          </div>

          {/* General Info */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">

            {/* Class Dropdown */}
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">Class / Grade</label>
              <select
                required
                className="w-full px-4 py-2 rounded-lg border border-gray-300 bg-white focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all text-gray-900"
                value={selectedClass}
                onChange={handleClassChange}
              >
                <option value="" disabled>Select Class</option>
                {GRADES.map((grade) => (
                  <option key={grade} value={grade} className="text-gray-900">{grade}</option>
                ))}
              </select>
            </div>

            {/* Subject Dropdown (Dependent) */}
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">Subject</label>
              <select
                required
                disabled={!selectedClass}
                className="w-full px-4 py-2 rounded-lg border border-gray-300 bg-white focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all text-gray-900 disabled:bg-gray-100 disabled:text-gray-400"
                value={selectedSubject}
                onChange={handleSubjectChange}
              >
                <option value="" disabled>
                    {!selectedClass ? 'Select Class first' : 'Select Subject'}
                </option>
                {availableSubjects.map((subj) => (
                  <option key={subj} value={subj} className="text-gray-900">{subj}</option>
                ))}
              </select>
            </div>

            {/* Topic Dropdown (Dependent) */}
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">Topic / Chapter</label>
              <select
                required
                disabled={!selectedSubject}
                className="w-full px-4 py-2 rounded-lg border border-gray-300 bg-white focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all text-gray-900 disabled:bg-gray-100 disabled:text-gray-400"
                value={selectedTopic}
                onChange={(e) => setSelectedTopic(e.target.value)}
              >
                <option value="" disabled>
                    {!selectedSubject ? 'Select Subject first' : 'Select Topic'}
                </option>
                {selectedSubject && (
                    <option value="All Topics" className="text-gray-900 font-bold bg-gray-50">
                        All Topics (Entire Syllabus)
                    </option>
                )}
                {availableTopics.map((topic) => (
                  <option key={topic} value={topic} className="text-gray-900">{topic}</option>
                ))}
              </select>
            </div>

            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">Difficulty</label>
              <select
                className="w-full px-4 py-2 rounded-lg border border-gray-300 bg-white focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all text-gray-900"
                value={difficulty}
                onChange={(e) => setDifficulty(e.target.value as any)}
              >
                <option value="Easy" className="text-gray-900 bg-white">Easy</option>
                <option value="Medium" className="text-gray-900 bg-white">Medium</option>
                <option value="Hard" className="text-gray-900 bg-white">Hard</option>
              </select>
            </div>

            {/* Time Allowed Input */}
            <div>
              <label className="block text-sm font-bold text-gray-800 mb-2">Time Allowed <span className="text-red-500">*</span></label>
              <div className="flex flex-col sm:flex-row gap-4">
                  <div className="relative w-full sm:w-1/2">
                    <select
                        value={timePreset}
                        onChange={handlePresetChange}
                        className={`w-full px-4 py-2 rounded-lg border appearance-none bg-white focus:ring-2 outline-none transition-all text-gray-900 cursor-pointer
                            ${timeAllowedError && timePreset !== 'Custom' ? 'border-red-500 focus:border-red-500 focus:ring-red-200' : 'border-gray-300 focus:ring-indigo-500 focus:border-indigo-500'}`}
                    >
                        <option value="30 Minutes">30 Minutes</option>
                        <option value="40 Minutes">40 Minutes</option>
                        <option value="45 Minutes">45 Minutes</option>
                        <option value="1 Hour">1 Hour</option>
                        <option value="1.5 Hours">1.5 Hours</option>
                        <option value="2 Hours">2 Hours</option>
                        <option value="2.5 Hours">2.5 Hours</option>
                        <option value="3 Hours">3 Hours</option>
                        <option value="Custom">Custom</option>
                    </select>
                    {/* Dropdown arrow */}
                    <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-3 text-gray-500">
                        <svg className="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7"></path></svg>
                    </div>
                  </div>

                  {timePreset === 'Custom' && (
                    <input
                        type="text"
                        className={`w-full sm:w-1/2 px-4 py-2 rounded-lg border bg-white focus:ring-2 outline-none transition-all text-gray-900 placeholder:text-gray-400 animate-fade-in
                            ${timeAllowedError ? 'border-red-500 focus:ring-red-200 focus:border-red-500' : 'border-gray-300 focus:ring-indigo-500 focus:border-indigo-500'}`}
                        placeholder="e.g. 90 Minutes"
                        value={customTime}
                        onChange={handleCustomTimeChange}
                    />
                  )}
              </div>
              {timeAllowedError && (
                  <p className="text-red-600 text-sm font-bold mt-1.5 animate-fade-in">{timeAllowedError}</p>
              )}
            </div>

            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">Total Marks</label>
              <div className="flex gap-2">
                  <input
                    type="number"
                    min="10"
                    max="100"
                    className="w-full px-4 py-2 rounded-lg border border-gray-300 bg-white focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all text-gray-900"
                    value={totalMarks}
                    onChange={(e) => setTotalMarks(parseInt(e.target.value))}
                  />
                  <button
                    type="button"
                    onClick={handleAutoDistribute}
                    className="px-3 py-2 bg-indigo-100 text-indigo-700 rounded-lg hover:bg-indigo-200 transition-colors text-sm font-semibold whitespace-nowrap"
                    title="Automatically distribute marks evenly"
                  >
                    Auto Distribute
                  </button>
              </div>
            </div>
          </div>

          <hr className="border-gray-100" />

          {/* Question Distribution */}
          <div>
            <div className="flex justify-between items-center mb-4">
                <h3 className="text-lg font-semibold text-gray-800 flex items-center gap-2">
                  <span className="w-1 h-6 bg-indigo-500 rounded-full"></span>
                  Question Distribution
                </h3>
                {currentCalculatedMarks !== null && (
                    <div className={`text-sm font-bold px-3 py-1 rounded-full ${currentCalculatedMarks === totalMarks ? 'bg-green-100 text-green-700' : 'bg-orange-100 text-orange-700'}`}>
                        Current: {currentCalculatedMarks} / {totalMarks} Marks
                    </div>
                )}
                {currentCalculatedMarks === null && (
                     <div className="text-sm font-bold px-3 py-1 rounded-full bg-gray-100 text-gray-500">
                        Total Pending...
                     </div>
                )}
            </div>

            <div className="grid grid-cols-2 md:grid-cols-3 gap-6 mb-6">
              {QUESTION_SPECS.map((item) => {
                const isError = !!errors[item.key];
                return (
                    <div key={item.key} className="relative">
                        <div className={`p-3 rounded-lg border ${isError ? 'bg-red-50 border-red-200' : 'bg-gray-50 border-gray-100'} transition-colors`}>
                            <label className={`block text-xs font-bold uppercase mb-1 ${isError ? 'text-red-700' : 'text-gray-700'}`}>
                                {item.label}
                            </label>
                            <input
                                type="number"
                                min="0"
                                placeholder="Enter count"
                                className={`w-full px-3 py-1.5 rounded border bg-white focus:ring-1 outline-none text-gray-900 placeholder:text-gray-400 text-sm
                                    ${isError 
                                        ? 'border-red-500 focus:border-red-500 focus:ring-red-200' 
                                        : 'border-gray-200 focus:border-indigo-500 focus:ring-indigo-500'}`}
                                value={counts[item.key]}
                                onChange={(e) => handleCountChange(item.key, e.target.value)}
                                onBlur={() => handleBlur(item.key)}
                            />
                            <p className="text-xs text-gray-500 mt-1">{item.marks} Mark{item.marks > 1 ? 's' : ''} each</p>
                        </div>
                        {errors[item.key] && (
                            <p className="absolute -bottom-5 left-0 text-xs font-bold text-red-500 animate-fade-in">
                                {errors[item.key]}
                            </p>
                        )}
                    </div>
                );
              })}
            </div>

            {/* Detailed Summary Table */}
            <div className="overflow-hidden border border-gray-200 rounded-lg shadow-sm mt-8">
                <table className="min-w-full text-sm">
                    <thead className="bg-gray-50 text-gray-700 border-b border-gray-200">
                        <tr>
                            <th className="px-4 py-2 text-left font-semibold">Question Type</th>
                            <th className="px-4 py-2 text-center font-semibold">Marks/Q</th>
                            <th className="px-4 py-2 text-center font-semibold">Count</th>
                            <th className="px-4 py-2 text-right font-semibold">Total</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-100">
                        {QUESTION_SPECS.map((spec) => (
                            <tr key={spec.key} className="bg-white hover:bg-gray-50 transition-colors">
                                <td className="px-4 py-2 text-gray-800 font-medium">{spec.label}</td>
                                <td className="px-4 py-2 text-center text-gray-600">{spec.marks}</td>
                                <td className="px-4 py-2 text-center text-gray-600 font-medium">
                                    {counts[spec.key] === '' ? '-' : counts[spec.key]}
                                </td>
                                <td className="px-4 py-2 text-right font-semibold text-gray-800">
                                    {counts[spec.key] === '' ? '-' : (parseInt(counts[spec.key]) * spec.marks)}
                                </td>
                            </tr>
                        ))}
                        <tr className="bg-indigo-50 font-bold border-t-2 border-indigo-100">
                            <td className="px-4 py-3 text-indigo-900">Grand Total</td>
                            <td className="px-4 py-3 text-center">-</td>
                            <td className="px-4 py-3 text-center text-indigo-900">
                                {currentCalculatedMarks === null ? '-' : QUESTION_SPECS.reduce((acc, spec) => acc + (parseInt(counts[spec.key]) || 0), 0)}
                            </td>
                            <td className={`px-4 py-3 text-right text-lg ${currentCalculatedMarks !== totalMarks ? 'text-orange-600' : 'text-indigo-900'}`}>
                                {currentCalculatedMarks === null ? 'Pending...' : currentCalculatedMarks}
                            </td>
                        </tr>
                    </tbody>
                </table>
            </div>
            {currentCalculatedMarks !== null && currentCalculatedMarks !== totalMarks && (
                <p className="text-xs text-orange-600 mt-2 text-right font-medium">
                    * Total does not match required marks. Please adjust counts or use Auto Distribute.
                </p>
            )}
            {currentCalculatedMarks === null && (
                 <p className="text-xs text-red-600 mt-2 text-right font-medium">
                    * Please fill in all question fields to calculate totals.
                </p>
            )}
          </div>

          {/* Actions */}
          <div className="flex justify-end gap-3 pt-4">
            <button
              type="button"
              onClick={onCancel}
              className="px-6 py-2.5 rounded-lg text-gray-600 font-medium hover:bg-gray-100 transition-colors"
              disabled={isGenerating}
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={isGenerating || currentCalculatedMarks === null || currentCalculatedMarks === 0}
              className={`px-8 py-2.5 rounded-lg text-white font-bold shadow-lg transition-all flex items-center gap-2
                ${isGenerating || currentCalculatedMarks === null || currentCalculatedMarks === 0
                  ? 'bg-indigo-400 cursor-not-allowed' 
                  : 'bg-indigo-600 hover:bg-indigo-700 hover:shadow-indigo-500/30 active:scale-95'
                }`}
            >
              {isGenerating ? (
                <>
                  <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                  Generating...
                </>
              ) : (
                'Generate Paper'
              )}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

