  // Typography State
  const [headingFont, setHeadingFont] = useState(FONT_OPTIONS[0].value);
  const [bodyFont, setBodyFont] = useState(FONT_OPTIONS[1].value);

  // General Instructions State
  const [generalInstructions, setGeneralInstructions] = useState('');
  const MAX_INSTRUCTION_CHARS = 500;

  const [selectedClass, setSelectedClass] = useState('');
  const [selectedSubject, setSelectedSubject] = useState('');
  const [selectedTopic, setSelectedTopic] = useState('');

  // Time Allowed State
  const [timeAllowed, setTimeAllowed] = useState('2 Hours');
  const [timePreset, setTimePreset] = useState('2 Hours');
  const [customTime, setCustomTime] = useState('');
  const [timeAllowedError, setTimeAllowedError] = useState<string | null>(null);

  const [totalMarks, setTotalMarks] = useState(50);
  const [difficulty, setDifficulty] = useState<'Easy' | 'Medium' | 'Hard'>('Medium');

  // State for counts
  const [counts, setCounts] = useState<Record<keyof QuestionCounts, string>>({
    mcq: '',
    ar: '',
    vsaq: '',
    saq: '',
    laq: '',
    caseStudy: '',
  });

  const [errors, setErrors] = useState<Record<keyof QuestionCounts, string | null>>({
    mcq: null,
    ar: null,
    vsaq: null,
    saq: null,
    laq: null,
    caseStudy: null,
  });

  const [currentCalculatedMarks, setCurrentCalculatedMarks] = useState<number | null>(null);

  // Update calculation whenever counts change
  useEffect(() => {
    const allFieldsFilled = QUESTION_SPECS.every(spec => counts[spec.key] !== '');

    if (allFieldsFilled) {
      const total = QUESTION_SPECS.reduce((acc, spec) => {
        const val = parseInt(counts[spec.key]) || 0;
        return acc + (val * spec.marks);
      }, 0);
      setCurrentCalculatedMarks(total);
    } else {
      setCurrentCalculatedMarks(null);
    }
  }, [counts]);

  const validateField = (key: keyof QuestionCounts, value: string) => {
    if (value === '') {
      return 'Required';
    }
    const num = parseInt(value);
    if (isNaN(num) || num < 0) {
      return 'Invalid';
    }
    return null;
  };

  const handleSchoolNameChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setSchoolName(e.target.value);
    if (e.target.value.trim() !== '') {
        setSchoolNameError(null);
    }
  };

  const handlePresetChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const val = e.target.value;
    setTimePreset(val);

    if (val === 'Custom') {
        setTimeAllowed(customTime);
    } else {
        setTimeAllowed(val);
        setTimeAllowedError(null);
    }
  };

  const handleCustomTimeChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      const val = e.target.value;
      setCustomTime(val);
      if (timePreset === 'Custom') {
        setTimeAllowed(val);
        if (val.trim() !== '') {
            setTimeAllowedError(null);
        }
      }
  };

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setLogoError(null);

    // Validate Size (2MB)
    if (file.size > 2 * 1024 * 1024) {
      setLogoError("File size exceeds 2MB limit.");
      return;
    }

    // Validate Type
    if (!['image/png', 'image/jpeg', 'image/jpg'].includes(file.type)) {
      setLogoError("Only PNG and JPG formats are allowed.");
      return;
    }

    const reader = new FileReader();
    reader.onload = (event) => {
      setSchoolLogo(event.target?.result as string);
    };
    reader.readAsDataURL(file);
  };

  const handleRemoveLogo = () => {
    setSchoolLogo(null);
    setLogoError(null);
    const input = document.getElementById('logo-upload') as HTMLInputElement;
    if (input) input.value = '';
  };

  const handleCountChange = (key: keyof QuestionCounts, value: string) => {
    if (value !== '' && !/^\d+$/.test(value)) return;

    setCounts(prev => ({ ...prev, [key]: value }));

    if (value !== '') {
        setErrors(prev => ({ ...prev, [key]: null }));
    }
  };

  const handleBlur = (key: keyof QuestionCounts) => {
    const error = validateField(key, counts[key]);
    setErrors(prev => ({ ...prev, [key]: error }));
  };

  const handleClassChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    setSelectedClass(e.target.value);
    setSelectedSubject('');
    setSelectedTopic('');
  };

  const handleSubjectChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    setSelectedSubject(e.target.value);
    setSelectedTopic('');
  };

  const handleAutoDistribute = () => {
    let newCounts: Record<keyof QuestionCounts, number> = { mcq: 0, ar: 0, vsaq: 0, saq: 0, laq: 0, caseStudy: 0 };
    let currentSum = 0;

    // 1. Minimum 1 each if mathematically possible
    for (const spec of QUESTION_SPECS) {
        if (currentSum + spec.marks <= totalMarks) {
            newCounts[spec.key]++;
            currentSum += spec.marks;
        }
    }

    // 2. Distribute remainder
    while (currentSum < totalMarks) {
        const candidates = QUESTION_SPECS.filter(spec => currentSum + spec.marks <= totalMarks);
        if (candidates.length === 0) break;
        candidates.sort((a, b) => newCounts[a.key] - newCounts[b.key]);
        const bestSpec = candidates[0];
        newCounts[bestSpec.key]++;
        currentSum += bestSpec.marks;
    }

    const stringCounts: any = {};
    QUESTION_SPECS.forEach(spec => {
        stringCounts[spec.key] = newCounts[spec.key].toString();
    });

    setCounts(stringCounts);
    setErrors({ mcq: null, ar: null, vsaq: null, saq: null, laq: null, caseStudy: null });
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    let hasErrors = false;

    if (schoolName.trim() === '') {
        setSchoolNameError('This field is required');
        hasErrors = true;
    }

    if (timeAllowed.trim() === '') {
        setTimeAllowedError('Required');
        hasErrors = true;
    } else if (!/\d/.test(timeAllowed)) {
        setTimeAllowedError('Must contain number');
        hasErrors = true;
    }

    const newErrors: any = {};
    QUESTION_SPECS.forEach(spec => {
        const error = validateField(spec.key, counts[spec.key]);
        if (error) {
            hasErrors = true;
            newErrors[spec.key] = error;
        }
    });

    if (hasErrors) {
        setErrors(newErrors);
        return;
    }

    const finalCounts: any = {};
    QUESTION_SPECS.forEach(spec => {
        finalCounts[spec.key] = parseInt(counts[spec.key]);
    });

    let fullSubject = selectedSubject;
    let fullTopic = '';

    if (selectedTopic === 'All Topics') {
        const allChapters = CBSE_CURRICULUM[selectedClass][selectedSubject].join(', ');
        fullSubject = `${selectedSubject} - All Topics`;
        fullTopic = `Covering: ${allChapters}`;
    } else if (selectedTopic) {
        fullSubject = `${selectedSubject}`;
        fullTopic = selectedTopic;
    }

    const finalSubjectString = `${fullSubject}: ${fullTopic}`;

    onGenerate({
      schoolName: schoolName.trim(),
      schoolLogo: schoolLogo || undefined,
      logoPlacement,
      headingFont,
      bodyFont,
      generalInstructions: generalInstructions.trim() || undefined,
      subject: finalSubjectString,
      grade: selectedClass,
      timeAllowed: timeAllowed.trim(),
      totalMarks,
      difficulty,
      counts: finalCounts as QuestionCounts
    });
  };

  const availableSubjects = selectedClass ? Object.keys(CBSE_CURRICULUM[selectedClass] || {}) : [];
  const availableTopics = (selectedClass && selectedSubject) 
    ? CBSE_CURRICULUM[selectedClass][selectedSubject] || [] 
    : [];

  return (
    <div className="max-w-4xl mx-auto">
      <div className="glass-panel rounded-2xl overflow-hidden animate-fade-in">
        <div className="p-6 border-b border-gray-100/50 bg-white/40">
            <h2 className="text-2xl font-bold text-gray-800">Configure Paper</h2>
            <p className="text-gray-500 text-sm mt-1">Define the parameters for your AI-generated assessment.</p>
        </div>

        <form onSubmit={handleSubmit} className="p-6 md:p-8 space-y-10">

          {/* Header Configuration */}
          <div className="bg-white/50 p-6 rounded-xl border border-white/60 space-y-6 shadow-sm">
             <h3 className="text-sm font-bold text-gray-500 uppercase tracking-wide border-b border-gray-200/60 pb-2 mb-4">Header Branding & Typography</h3>

             {/* School Name */}
             <div>
                <label className="block text-sm font-bold text-gray-700 mb-2">School Name <span className="text-red-500">*</span></label>
                <input
                    type="text"
                    className={`w-full px-4 py-3 rounded-lg border bg-white/80 focus:ring-2 outline-none transition-all text-gray-900 placeholder:text-gray-400
                        ${schoolNameError ? 'border-red-500 focus:ring-red-200' : 'border-gray-200 focus:ring-[#8A2CB0] focus:border-[#8A2CB0]'}`}
                    placeholder="Enter the full name of the School / Institution"
                    value={schoolName}
                    onChange={handleSchoolNameChange}
                />
                {schoolNameError && <p className="text-red-600 text-sm font-bold mt-1.5">{schoolNameError}</p>}
             </div>

             {/* Logo Section */}
             <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div>
                    <label className="block text-sm font-bold text-gray-700 mb-2">Upload School Logo <span className="text-gray-400 font-normal">(Optional)</span></label>
                    <div className="relative border-2 border-dashed border-gray-300 rounded-xl p-6 bg-white/60 hover:bg-white/90 hover:border-[#8A2CB0] transition-all text-center cursor-pointer">
                        {!schoolLogo ? (
                            <>
                                <input 
                                    type="file" 
                                    id="logo-upload"
                                    accept="image/png, image/jpeg, image/jpg"
                                    onChange={handleLogoUpload}
                                    className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                                />
                                <div className="flex flex-col items-center justify-center text-gray-400 py-2">
                                    <span className="text-sm font-medium text-[#8A2CB0]">Click to upload logo</span>
                                    <span className="text-xs text-gray-400 mt-1">PNG, JPG (Max 2MB)</span>
                                </div>
                            </>
                        ) : (
                            <div className="flex items-center gap-4">
                                <div className="w-16 h-16 relative border rounded bg-white flex items-center justify-center overflow-hidden shadow-sm">
                                    <img src={schoolLogo} alt="Preview" className="w-full h-full object-contain" />
                                </div>
                                <div className="text-left flex-1">
                                    <p className="text-sm font-bold text-green-600">Logo Uploaded</p>
                                    <button 
                                        type="button" 
                                        onClick={handleRemoveLogo}
                                        className="text-xs text-red-500 hover:text-red-700 underline mt-1"
                                    >
                                        Remove
                                    </button>
                                </div>
                            </div>
                        )}
                    </div>
                    {logoError && <p className="text-red-600 text-xs font-bold mt-1.5">{logoError}</p>}
                </div>

                {/* Logo Placement */}
                <div>
                     <label className={`block text-sm font-bold mb-2 ${!schoolLogo ? 'text-gray-400' : 'text-gray-700'}`}>
                        Logo Placement
                     </label>
                     <div className="flex gap-3 mb-6">
                         {[
                             { id: 'left', label: 'Left' },
                             { id: 'center', label: 'Center' },
                             { id: 'right', label: 'Right' }
                         ].map((opt) => (
                             <label 
                                key={opt.id}
                                className={`flex-1 flex flex-col items-center justify-center py-3 rounded-lg border cursor-pointer transition-all text-sm font-semibold
                                    ${!schoolLogo ? 'opacity-50 pointer-events-none bg-gray-50 border-gray-100' : ''}
                                    ${logoPlacement === opt.id 
                                        ? 'bg-[#f3e8ff] border-[#8A2CB0] text-[#3C128D] shadow-sm' 
                                        : 'bg-white border-gray-200 text-gray-500 hover:bg-gray-50'
                                    }`}
                             >
                                 <input 
                                    type="radio" 
                                    name="logoPlacement" 
                                    value={opt.id}
                                    checked={logoPlacement === opt.id}
                                    onChange={(e) => setLogoPlacement(e.target.value as any)}
                                    className="sr-only"
                                    disabled={!schoolLogo}
                                 />
                                 {opt.label}
                             </label>
                         ))}
                     </div>
                </div>
             </div>

             <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                    <label className="block text-sm font-bold text-gray-700 mb-2">Heading Font</label>
                    <select
                        className="w-full px-4 py-2.5 rounded-lg border border-gray-200 bg-white focus:ring-2 focus:ring-[#8A2CB0] outline-none"
                        value={headingFont}
                        onChange={(e) => setHeadingFont(e.target.value)}
                    >
                        {FONT_OPTIONS.map((font) => (
                            <option key={font.value} value={font.value}>{font.label}</option>
                        ))}
                    </select>
                </div>
                <div>
                    <label className="block text-sm font-bold text-gray-700 mb-2">Body Font</label>
                    <select
                        className="w-full px-4 py-2.5 rounded-lg border border-gray-200 bg-white focus:ring-2 focus:ring-[#8A2CB0] outline-none"
                        value={bodyFont}
                        onChange={(e) => setBodyFont(e.target.value)}
                    >
                        {FONT_OPTIONS.map((font) => (
                            <option key={font.value} value={font.value}>{font.label}</option>
                        ))}
                    </select>
                </div>
             </div>
          </div>

          {/* General Info & Paper Specs */}
          <div className="space-y-6">
             <h3 className="text-sm font-bold text-gray-500 uppercase tracking-wide border-b border-gray-200/50 pb-2">Paper Specification</h3>

             <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className="block text-sm font-semibold text-gray-700 mb-2">Class</label>
                  <select
                    required
                    className="w-full px-4 py-2.5 rounded-lg border border-gray-200 bg-white focus:ring-2 focus:ring-[#8A2CB0] outline-none"
                    value={selectedClass}
                    onChange={handleClassChange}
                  >
                    <option value="" disabled>Select Class</option>
                    {GRADES.map((grade) => (
                      <option key={grade} value={grade}>{grade}</option>
                    ))}
                  </select>
                </div>

                <div>
                  <label className="block text-sm font-semibold text-gray-700 mb-2">Subject</label>
                  <select
                    required
                    disabled={!selectedClass}
                    className="w-full px-4 py-2.5 rounded-lg border border-gray-200 bg-white focus:ring-2 focus:ring-[#8A2CB0] outline-none disabled:bg-gray-100 disabled:text-gray-400"
                    value={selectedSubject}
                    onChange={handleSubjectChange}
                  >
                    <option value="" disabled>
                        {!selectedClass ? 'Select Class first' : 'Select Subject'}
                    </option>
                    {availableSubjects.map((subj) => (
                      <option key={subj} value={subj}>{subj}</option>
                    ))}
                  </select>
                </div>

                <div className="md:col-span-2">
                  <label className="block text-sm font-semibold text-gray-700 mb-2">Topic</label>
                  <select
                    required
                    disabled={!selectedSubject}
                    className="w-full px-4 py-2.5 rounded-lg border border-gray-200 bg-white focus:ring-2 focus:ring-[#8A2CB0] outline-none disabled:bg-gray-100 disabled:text-gray-400"
                    value={selectedTopic}
                    onChange={(e) => setSelectedTopic(e.target.value)}
                  >
                    <option value="" disabled>
                        {!selectedSubject ? 'Select Subject first' : 'Select Topic'}
                    </option>
                    {selectedSubject && (
                        <option value="All Topics" className="font-bold bg-[#f3e8ff] text-[#3C128D]">
                            All Topics (Entire Syllabus)
                        </option>
                    )}
                    {availableTopics.map((topic) => (
                      <option key={topic} value={topic}>{topic}</option>
                    ))}
                  </select>
                </div>

                <div>
                  <label className="block text-sm font-semibold text-gray-700 mb-2">Difficulty</label>
                  <select
                    className="w-full px-4 py-2.5 rounded-lg border border-gray-200 bg-white focus:ring-2 focus:ring-[#8A2CB0] outline-none"
                    value={difficulty}
                    onChange={(e) => setDifficulty(e.target.value as any)}
                  >
                    <option value="Easy">Easy</option>
                    <option value="Medium">Medium</option>
                    <option value="Hard">Hard</option>
                  </select>
                </div>

                <div>
                    <label className="block text-sm font-semibold text-gray-700 mb-2">Total Marks</label>
                    <div className="flex gap-2">
                        <input
                            type="number"
                            min="10"
                            max="100"
                            className="w-full px-4 py-2.5 rounded-lg border border-gray-200 bg-white focus:ring-2 focus:ring-[#8A2CB0] outline-none"
                            value={totalMarks}
                            onChange={(e) => setTotalMarks(parseInt(e.target.value))}
                        />
                        <button
                            type="button"
                            onClick={handleAutoDistribute}
                            className="px-4 py-2 bg-[#f3e8ff] text-[#3C128D] border border-[#d8b4fe] rounded-lg hover:bg-[#e9d5ff] transition-colors text-sm font-semibold whitespace-nowrap"
                        >
                            Auto Distribute
                        </button>
                    </div>
                </div>

                <div className="md:col-span-2">
                    <label className="block text-sm font-semibold text-gray-700 mb-2">Time Allowed <span className="text-red-500">*</span></label>
                    <div className="flex gap-4">
                         <div className="relative w-full md:w-1/2">
                            <select
                                value={timePreset}
                                onChange={handlePresetChange}
                                className={`w-full px-4 py-2.5 rounded-lg border bg-white focus:ring-2 outline-none appearance-none
                                    ${timeAllowedError && timePreset !== 'Custom' ? 'border-red-500' : 'border-gray-200 focus:ring-[#8A2CB0]'}`}
                            >
                                <option value="30 Minutes">30 Minutes</option>
                                <option value="40 Minutes">40 Minutes</option>
                                <option value="45 Minutes">45 Minutes</option>
                                <option value="1 Hour">1 Hour</option>
                                <option value="1.5 Hours">1.5 Hours</option>
                                <option value="2 Hours">2 Hours</option>
                                <option value="2.5 Hours">2.5 Hours</option>
                                <option value="3 Hours">3 Hours</option>
                                <option value="Custom">Custom</option>
                            </select>
                             <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-3 text-gray-500">
                                <svg className="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7"></path></svg>
                            </div>
                         </div>
                         {timePreset === 'Custom' && (
                             <input
                                type="text"
                                className="w-full md:w-1/2 px-4 py-2.5 rounded-lg border border-gray-200 bg-white focus:ring-2 focus:ring-[#8A2CB0] outline-none animate-fade-in"
                                placeholder="e.g. 90 Minutes"
                                value={customTime}
                                onChange={handleCustomTimeChange}
                             />
                         )}
                    </div>
                    {timeAllowedError && <p className="text-red-600 text-sm font-bold mt-1.5">{timeAllowedError}</p>}
                </div>
             </div>
          </div>

          {/* Instructions */}
          <div className="bg-white/50 p-6 rounded-xl border border-white/60">
             <div className="flex justify-between items-center mb-2">
                <label className="block text-sm font-bold text-gray-700">General Instructions</label>
                <span className="text-xs text-gray-400">Optional</span>
             </div>
             <textarea
                className="w-full px-4 py-3 rounded-lg border border-gray-200 bg-white/80 focus:ring-2 focus:ring-[#8A2CB0] outline-none transition-all h-24 resize-y text-sm"
                placeholder="Enter general instructions..."
                value={generalInstructions}
                onChange={(e) => {
                    if (e.target.value.length <= MAX_INSTRUCTION_CHARS) {
                        setGeneralInstructions(e.target.value);
                    }
                }}
             />
          </div>

          <hr className="border-gray-200/50" />

          {/* Question Distribution Table */}
          <div>
            <div className="flex justify-between items-center mb-4">
                <h3 className="text-lg font-semibold text-gray-800">Question Distribution</h3>
                {currentCalculatedMarks !== null && (
                    <span className={`text-sm font-bold px-3 py-1 rounded-full ${currentCalculatedMarks === totalMarks ? 'bg-green-100 text-green-700' : 'bg-orange-100 text-orange-700'}`}>
                        Total: {currentCalculatedMarks} / {totalMarks}
                    </span>
                )}
            </div>

            <div className="overflow-hidden border border-gray-200 rounded-xl shadow-sm bg-white">
                <table className="min-w-full text-sm">
                    <thead className="bg-gray-50/80 text-gray-600 font-semibold border-b border-gray-200">
                        <tr>
                            <th className="px-4 py-3 text-left">Type</th>
                            <th className="px-4 py-3 text-center">Marks/Q</th>
                            <th className="px-4 py-3 text-center">Count</th>
                            <th className="px-4 py-3 text-right">Total</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-100">
                        {QUESTION_SPECS.map((spec) => (
                            <tr key={spec.key} className="hover:bg-gray-50/50 transition-colors">
                                <td className="px-4 py-3 text-gray-800 font-medium">{spec.label}</td>
                                <td className="px-4 py-3 text-center text-gray-500">{spec.marks}</td>
                                <td className="px-4 py-2 text-center">
                                    <input
                                        type="number"
                                        min="0"
                                        className={`w-16 text-center px-2 py-1 rounded border outline-none focus:ring-1 focus:border-[#8A2CB0]
                                            ${errors[spec.key] ? 'border-red-500 bg-red-50' : 'border-gray-200 bg-white'}`}
                                        value={counts[spec.key]}
                                        onChange={(e) => handleCountChange(spec.key, e.target.value)}
                                        onBlur={() => handleBlur(spec.key)}
                                    />
                                </td>
                                <td className="px-4 py-3 text-right font-semibold text-gray-700">
                                    {counts[spec.key] === '' ? '-' : (parseInt(counts[spec.key]) * spec.marks)}
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
          </div>

          {/* Action Buttons */}
          <div className="flex justify-end gap-4 pt-2">
            <button
              type="button"
              onClick={onCancel}
              className="px-6 py-3 rounded-xl text-gray-600 font-medium hover:bg-gray-100 transition-colors"
              disabled={isGenerating}
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={isGenerating || currentCalculatedMarks === null || currentCalculatedMarks === 0}
              className={`px-8 py-3 rounded-xl text-white font-bold shadow-lg shadow-[#3C128D]/20 transition-all flex items-center gap-2 transform active:scale-95
                ${isGenerating || currentCalculatedMarks === null || currentCalculatedMarks === 0
                  ? 'bg-gray-400 cursor-not-allowed' 
                  : 'bg-gradient-to-r from-[#8A2CB0] to-[#3C128D] hover:from-[#7c269e] hover:to-[#2e0e6b]'
                }`}
            >
              {isGenerating ? (
                <>
                  <svg className="animate-spin h-5 w-5 text-white" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                  Generating Paper...
                </>
              ) : (
                'Generate Paper'
              )}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default PaperForm;

import React, { useState } from 'react';
import { QuestionBank } from '../types';
import { CBSE_CURRICULUM, GRADES } from '../constants';
import MarkdownRenderer from './MarkdownRenderer';
import { generateQuestionBankUpdate } from '../services/geminiService';

interface QuestionBankProps {
  banks: QuestionBank[];
  onUpdateBank: (bank: QuestionBank) => void;
  onBack: () => void;
}

const QuestionBankView: React.FC<QuestionBankProps> = ({ banks, onUpdateBank, onBack }) => {
  const [selectedClass, setSelectedClass] = useState<string>('');
  const [selectedSubject, setSelectedSubject] = useState<string>('');
  const [isUpdating, setIsUpdating] = useState(false);

  // Find existing bank for selected subject
  const currentBank = banks.find(b => b.subject === selectedSubject && b.grade === selectedClass);

  const handleUpdate = async () => {
    if (!selectedSubject || !selectedClass) return;

    setIsUpdating(true);
    try {
      const newContent = await generateQuestionBankUpdate(selectedSubject, selectedClass);

      const updatedBank: QuestionBank = currentBank 
        ? {
            ...currentBank,
            lastUpdated: Date.now(),
            content: `### Update: ${new Date().toLocaleDateString()} ${new Date().toLocaleTimeString()}\n\n${newContent}\n\n---\n\n${currentBank.content}`
          }
        : {
            id: crypto.randomUUID(),
            subject: selectedSubject,
            grade: selectedClass,
            lastUpdated: Date.now(),
            content: `### Question Bank: ${selectedSubject} (${selectedClass})\n\n${newContent}`
          };

      onUpdateBank(updatedBank);
    } catch (error) {
      console.error(error);
      alert("Failed to update question bank. Please check your connection or API limit.");
    } finally {
      setIsUpdating(false);
    }
  };

  const handleDownload = () => {
    if (!currentBank) return;
    const blob = new Blob([currentBank.content], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `QuestionBank_${currentBank.subject}_${currentBank.grade}.txt`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleClassChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    setSelectedClass(e.target.value);
    setSelectedSubject('');
  };

  // Get subjects based on selected class
  const availableSubjects = selectedClass ? Object.keys(CBSE_CURRICULUM[selectedClass] || {}) : [];

  return (
    <div className="max-w-6xl mx-auto p-4 sm:p-6 animate-fade-in pb-20">
      {/* Header */}
      <div className="flex justify-between items-center mb-6">
        <button 
          onClick={onBack}
          className="text-white hover:text-white/80 flex items-center gap-2 font-medium drop-shadow-sm transition-colors"
        >
          ← Back to Dashboard
        </button>
        <h1 className="text-2xl font-bold text-white drop-shadow-md">Master Question Bank</h1>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">

        {/* Controls Sidebar */}
        <div className="lg:col-span-1 space-y-4">
          <div className="glass-panel p-5 rounded-xl">
            <h3 className="font-bold text-gray-700 mb-4 border-b border-gray-200/50 pb-2">Select Context</h3>

            <div className="space-y-4">
              <div>
                <label className="block text-xs font-bold text-gray-500 mb-1 uppercase tracking-wide">Class / Grade</label>
                <select 
                  className="w-full px-3 py-2.5 rounded-lg border border-gray-200 bg-white/80 text-sm focus:ring-2 focus:ring-[#8A2CB0] outline-none"
                  value={selectedClass}
                  onChange={handleClassChange}
                >
                  <option value="">Select Class</option>
                  {GRADES.map(grade => (
                    <option key={grade} value={grade}>{grade}</option>
                  ))}
                </select>
              </div>

              <div>
                <label className="block text-xs font-bold text-gray-500 mb-1 uppercase tracking-wide">Subject</label>
                <select 
                  className="w-full px-3 py-2.5 rounded-lg border border-gray-200 bg-white/80 text-sm focus:ring-2 focus:ring-[#8A2CB0] outline-none disabled:opacity-50"
                  value={selectedSubject}
                  onChange={(e) => setSelectedSubject(e.target.value)}
                  disabled={!selectedClass}
                >
                  <option value="">
                    {!selectedClass ? 'Select Class first' : 'Select Subject'}
                  </option>
                  {availableSubjects.map(subj => (
                    <option key={subj} value={subj}>{subj}</option>
                  ))}
                </select>
              </div>
            </div>

            <button
              onClick={handleUpdate}
              disabled={!selectedSubject || !selectedClass || isUpdating}
              className={`w-full mt-6 py-2.5 rounded-lg font-bold text-white shadow-lg transition-all flex items-center justify-center gap-2
                ${(!selectedSubject || !selectedClass || isUpdating) 
                    ? 'bg-gray-300 cursor-not-allowed shadow-none' 
                    : 'bg-gradient-to-r from-[#8A2CB0] to-[#3C128D] hover:from-[#7c269e] hover:to-[#2e0e6b] active:scale-95'
                }
              `}
            >
              {isUpdating ? (
                 <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                   <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                   <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                 </svg>
              ) : (
                currentBank ? 'Add Questions' : 'Create Bank'
              )}
            </button>
          </div>

          {currentBank && (
            <div className="glass-panel p-4 rounded-xl border-l-4 border-[#8A2CB0] text-sm">
               <p className="font-bold text-[#3C128D] mb-1">Status: Active</p>
               <p className="text-gray-600 text-xs">Last updated: {new Date(currentBank.lastUpdated).toLocaleDateString()}</p>
               <button 
                 onClick={handleDownload}
                 className="mt-3 text-xs font-bold text-[#8A2CB0] hover:text-[#3C128D] underline"
               >
                 Download Content (.txt)
               </button>
            </div>
          )}
        </div>

        {/* Content Area */}
        <div className="lg:col-span-3">
          <div className="glass-panel rounded-xl min-h-[600px] flex flex-col overflow-hidden bg-white">
            {currentBank ? (
              <div className="p-8 paper-font overflow-y-auto max-h-[800px]">
                <MarkdownRenderer content={currentBank.content} />
              </div>
            ) : (
              <div className="flex-1 flex flex-col items-center justify-center text-gray-400 p-8 text-center">
                <div className="w-20 h-20 bg-gray-50 rounded-full flex items-center justify-center mb-4">
                    <svg className="w-10 h-10 opacity-30" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M19 11H5m14 0a2 2 0 0 1 2 2v6a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-6a2 2 0 0 1 2-2m14 0V9a2 2 0 0 0-2-2M5 11V9a2 2 0 0 1 2-2m0 0V5a2 2 0 0 1 2-2h6a2 2 0 0 1 2 2v2M7 7h10"></path>
                    </svg>
                </div>
                <h3 className="text-lg font-semibold text-gray-600">Question Bank Empty</h3>
                <p className="max-w-md mt-2 text-sm">Select a Class and Subject from the sidebar and click "Create Bank" to start generating your repository.</p>
              </div>
            )}
          </div>
        </div>

      </div>
    </div>
  );
};

export default QuestionBankView;

export interface QuestionCounts {
  mcq: number;
  ar: number; // Assertion-Reason
  vsaq: number; // Very Short Answer
  saq: number; // Short Answer
  laq: number; // Long Answer
  caseStudy: number;
}

export interface PaperConfig {
  board: string; // Added Board/Curriculum
  schoolName: string;
  schoolLogo?: string; // Base64 data URL
  logoPlacement?: 'left' | 'center' | 'right';
  headingFont?: string;
  bodyFont?: string;
  generalInstructions?: string;
  subject: string;
  grade: string;
  timeAllowed: string; // New field for Exam Duration
  totalMarks: number;
  difficulty: 'Easy' | 'Medium' | 'Hard';
  counts: QuestionCounts;
}

export interface GeneratedPaper {
  id: string;
  timestamp: number;
  config: PaperConfig;
  title: string;
  content: string; // Markdown content of the question paper
  answerKey: string; // Markdown content of the answer key
}

export interface QuestionBank {
  id: string;
  board?: string; // Added Board/Curriculum (optional for backward compatibility)
  subject: string;
  grade: string;
  lastUpdated: number;
  content: string; // Markdown content, appended over time
}

export interface HistoryStats {
  totalGenerated: number;
  topics: string[];
}

import React, { useState, useEffect } from 'react';
import { PaperConfig, QuestionCounts } from '../types';
import { CURRICULUM_DATA, GRADES, FONT_OPTIONS, BOARDS } from '../constants';

// Defined Weights and Specs
const QUESTION_SPECS: { label: string; key: keyof QuestionCounts; marks: number }[] = [
  { label: "MCQs", key: "mcq", marks: 1 },
  { label: "Assertion-Reason", key: "ar", marks: 1 },
  { label: "Very Short (VSAQ)", key: "vsaq", marks: 2 },
  { label: "Short Answer (SAQ)", key: "saq", marks: 3 },
  { label: "Case Study", key: "caseStudy", marks: 4 },
  { label: "Long Answer (LAQ)", key: "laq", marks: 5 },
];

interface PaperFormProps {
  onGenerate: (config: PaperConfig) => void;
  onCancel: () => void;
  isGenerating: boolean;
}

const PaperForm: React.FC<PaperFormProps> = ({ onGenerate, onCancel, isGenerating }) => {
  const [schoolName, setSchoolName] = useState('');
  const [schoolNameError, setSchoolNameError] = useState<string | null>(null);

  const [schoolLogo, setSchoolLogo] = useState<string | null>(null);
  const [logoPlacement, setLogoPlacement] = useState<'left' | 'center' | 'right'>('left');
  const [logoError, setLogoError] = useState<string | null>(null);

  // Typography State
  const [headingFont, setHeadingFont] = useState(FONT_OPTIONS[0].value);
  const [bodyFont, setBodyFont] = useState(FONT_OPTIONS[1].value);

  // General Instructions State
  const [generalInstructions, setGeneralInstructions] = useState('');
  const MAX_INSTRUCTION_CHARS = 500;

  // Curriculum State
  const [selectedBoard, setSelectedBoard] = useState(BOARDS[0]);
  const [selectedClass, setSelectedClass] = useState('');
  const [selectedSubject, setSelectedSubject] = useState('');
  const [selectedTopic, setSelectedTopic] = useState('');

  // Time Allowed State
  const [timeAllowed, setTimeAllowed] = useState('2 Hours');
  const [timePreset, setTimePreset] = useState('2 Hours');
  const [customTime, setCustomTime] = useState('');
  const [timeAllowedError, setTimeAllowedError] = useState<string | null>(null);

  const [totalMarks, setTotalMarks] = useState(50);
  const [difficulty, setDifficulty] = useState<'Easy' | 'Medium' | 'Hard'>('Medium');

  // State for counts
  const [counts, setCounts] = useState<Record<keyof QuestionCounts, string>>({
    mcq: '',
    ar: '',
    vsaq: '',
    saq: '',
    laq: '',
    caseStudy: '',
  });

  const [errors, setErrors] = useState<Record<keyof QuestionCounts, string | null>>({
    mcq: null,
    ar: null,
    vsaq: null,
    saq: null,
    laq: null,
    caseStudy: null,
  });

  const [currentCalculatedMarks, setCurrentCalculatedMarks] = useState<number | null>(null);

  // Update calculation whenever counts change
  useEffect(() => {
    const allFieldsFilled = QUESTION_SPECS.every(spec => counts[spec.key] !== '');

    if (allFieldsFilled) {
      const total = QUESTION_SPECS.reduce((acc, spec) => {
        const val = parseInt(counts[spec.key]) || 0;
        return acc + (val * spec.marks);
      }, 0);
      setCurrentCalculatedMarks(total);
    } else {
      setCurrentCalculatedMarks(null);
    }
  }, [counts]);

  const validateField = (key: keyof QuestionCounts, value: string) => {
    if (value === '') {
      return 'Required';
    }
    const num = parseInt(value);
    if (isNaN(num) || num < 0) {
      return 'Invalid';
    }
    return null;
  };

  const handleSchoolNameChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setSchoolName(e.target.value);
    if (e.target.value.trim() !== '') {
        setSchoolNameError(null);
    }
  };

  const handlePresetChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const val = e.target.value;
    setTimePreset(val);

    if (val === 'Custom') {
        setTimeAllowed(customTime);
    } else {
        setTimeAllowed(val);
        setTimeAllowedError(null);
    }
  };

  const handleCustomTimeChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      const val = e.target.value;
      setCustomTime(val);
      if (timePreset === 'Custom') {
        setTimeAllowed(val);
        if (val.trim() !== '') {
            setTimeAllowedError(null);
        }
      }
  };

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setLogoError(null);

    // Validate Size (2MB)
    if (file.size > 2 * 1024 * 1024) {
      setLogoError("File size exceeds 2MB limit.");
      return;
    }

    // Validate Type
    if (!['image/png', 'image/jpeg', 'image/jpg'].includes(file.type)) {
      setLogoError("Only PNG and JPG formats are allowed.");
      return;
    }

    const reader = new FileReader();
    reader.onload = (event) => {
      setSchoolLogo(event.target?.result as string);
    };
    reader.readAsDataURL(file);
  };

  const handleRemoveLogo = () => {
    setSchoolLogo(null);
    setLogoError(null);
    const input = document.getElementById('logo-upload') as HTMLInputElement;
    if (input) input.value = '';
  };

  const handleCountChange = (key: keyof QuestionCounts, value: string) => {
    if (value !== '' && !/^\d+$/.test(value)) return;

    setCounts(prev => ({ ...prev, [key]: value }));

    if (value !== '') {
        setErrors(prev => ({ ...prev, [key]: null }));
    }
  };

  const handleBlur = (key: keyof QuestionCounts) => {
    const error = validateField(key, counts[key]);
    setErrors(prev => ({ ...prev, [key]: error }));
  };

  const handleBoardChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    setSelectedBoard(e.target.value);
    setSelectedClass('');
    setSelectedSubject('');
    setSelectedTopic('');
  };

  const handleClassChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    setSelectedClass(e.target.value);
    setSelectedSubject('');
    setSelectedTopic('');
  };

  const handleSubjectChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    setSelectedSubject(e.target.value);
    setSelectedTopic('');
  };

  const handleAutoDistribute = () => {
    let newCounts: Record<keyof QuestionCounts, number> = { mcq: 0, ar: 0, vsaq: 0, saq: 0, laq: 0, caseStudy: 0 };
    let currentSum = 0;

    // 1. Minimum 1 each if mathematically possible
    for (const spec of QUESTION_SPECS) {
        if (currentSum + spec.marks <= totalMarks) {
            newCounts[spec.key]++;
            currentSum += spec.marks;
        }
    }

    // 2. Distribute remainder
    while (currentSum < totalMarks) {
        const candidates = QUESTION_SPECS.filter(spec => currentSum + spec.marks <= totalMarks);
        if (candidates.length === 0) break;
        candidates.sort((a, b) => newCounts[a.key] - newCounts[b.key]);
        const bestSpec = candidates[0];
        newCounts[bestSpec.key]++;
        currentSum += bestSpec.marks;
    }

    const stringCounts: any = {};
    QUESTION_SPECS.forEach(spec => {
        stringCounts[spec.key] = newCounts[spec.key].toString();
    });

    setCounts(stringCounts);
    setErrors({ mcq: null, ar: null, vsaq: null, saq: null, laq: null, caseStudy: null });
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    let hasErrors = false;

    if (schoolName.trim() === '') {
        setSchoolNameError('This field is required');
        hasErrors = true;
    }

    if (timeAllowed.trim() === '') {
        setTimeAllowedError('Required');
        hasErrors = true;
    } else if (!/\d/.test(timeAllowed)) {
        setTimeAllowedError('Must contain number');
        hasErrors = true;
    }

    const newErrors: any = {};
    QUESTION_SPECS.forEach(spec => {
        const error = validateField(spec.key, counts[spec.key]);
        if (error) {
            hasErrors = true;
            newErrors[spec.key] = error;
        }
    });

    if (hasErrors) {
        setErrors(newErrors);
        return;
    }

    const finalCounts: any = {};
    QUESTION_SPECS.forEach(spec => {
        finalCounts[spec.key] = parseInt(counts[spec.key]);
    });

    let fullSubject = selectedSubject;
    let fullTopic = '';

    const boardData = CURRICULUM_DATA[selectedBoard]?.[selectedClass];
    const subjectChapters = boardData?.[selectedSubject] || [];

    if (selectedTopic === 'All Topics') {
        const allChapters = subjectChapters.join(', ');
        fullSubject = `${selectedSubject} - All Topics`;
        fullTopic = `Covering: ${allChapters}`;
    } else if (selectedTopic) {
        fullSubject = `${selectedSubject}`;
        fullTopic = selectedTopic;
    }

    const finalSubjectString = `${fullSubject}: ${fullTopic}`;

    onGenerate({
      board: selectedBoard,
      schoolName: schoolName.trim(),
      schoolLogo: schoolLogo || undefined,
      logoPlacement,
      headingFont,
      bodyFont,
      generalInstructions: generalInstructions.trim() || undefined,
      subject: finalSubjectString,
      grade: selectedClass,
      timeAllowed: timeAllowed.trim(),
      totalMarks,
      difficulty,
      counts: finalCounts as QuestionCounts
    });
  };

  // Logic to fetch available subjects/topics based on Board -> Class
  const boardData = CURRICULUM_DATA[selectedBoard];
  const classData = boardData ? boardData[selectedClass] : null;

  const availableSubjects = classData ? Object.keys(classData) : [];
  const availableTopics = (classData && selectedSubject) 
    ? classData[selectedSubject] || [] 
    : [];

  return (
    <div className="max-w-4xl mx-auto">
      <div className="glass-panel rounded-2xl overflow-hidden animate-fade-in">
        <div className="p-6 border-b border-gray-100/50 bg-white/40">
            <h2 className="text-2xl font-bold text-gray-800">Configure Paper</h2>
            <p className="text-gray-500 text-sm mt-1">Define the parameters for your AI-generated assessment.</p>
        </div>

        <form onSubmit={handleSubmit} className="p-6 md:p-8 space-y-10">

          {/* Header Configuration */}
          <div className="bg-white/50 p-6 rounded-xl border border-white/60 space-y-6 shadow-sm">
             <h3 className="text-sm font-bold text-gray-500 uppercase tracking-wide border-b border-gray-200/60 pb-2 mb-4">Header Branding & Typography</h3>

             {/* School Name */}
             <div>
                <label className="block text-sm font-bold text-gray-700 mb-2">School Name <span className="text-red-500">*</span></label>
                <input
                    type="text"
                    className={`w-full px-4 py-3 rounded-lg border bg-white/80 focus:ring-2 outline-none transition-all text-gray-900 placeholder:text-gray-400
                        ${schoolNameError ? 'border-red-500 focus:ring-red-200' : 'border-gray-200 focus:ring-[#8A2CB0] focus:border-[#8A2CB0]'}`}
                    placeholder="Enter the full name of the School / Institution"
                    value={schoolName}
                    onChange={handleSchoolNameChange}
                />
                {schoolNameError && <p className="text-red-600 text-sm font-bold mt-1.5">{schoolNameError}</p>}
             </div>

             {/* Logo Section */}
             <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div>
                    <label className="block text-sm font-bold text-gray-700 mb-2">Upload School Logo <span className="text-gray-400 font-normal">(Optional)</span></label>
                    <div className="relative border-2 border-dashed border-gray-300 rounded-xl p-6 bg-white/60 hover:bg-white/90 hover:border-[#8A2CB0] transition-all text-center cursor-pointer">
                        {!schoolLogo ? (
                            <>
                                <input 
                                    type="file" 
                                    id="logo-upload"
                                    accept="image/png, image/jpeg, image/jpg"
                                    onChange={handleLogoUpload}
                                    className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                                />
                                <div className="flex flex-col items-center justify-center text-gray-400 py-2">
                                    <span className="text-sm font-medium text-[#8A2CB0]">Click to upload logo</span>
                                    <span className="text-xs text-gray-400 mt-1">PNG, JPG (Max 2MB)</span>
                                </div>
                            </>
                        ) : (
                            <div className="flex items-center gap-4">
                                <div className="w-16 h-16 relative border rounded bg-white flex items-center justify-center overflow-hidden shadow-sm">
                                    <img src={schoolLogo} alt="Preview" className="w-full h-full object-contain" />
                                </div>
                                <div className="text-left flex-1">
                                    <p className="text-sm font-bold text-green-600">Logo Uploaded</p>
                                    <button 
                                        type="button" 
                                        onClick={handleRemoveLogo}
                                        className="text-xs text-red-500 hover:text-red-700 underline mt-1"
                                    >
                                        Remove
                                    </button>
                                </div>
                            </div>
                        )}
                    </div>
                    {logoError && <p className="text-red-600 text-xs font-bold mt-1.5">{logoError}</p>}
                </div>

                {/* Logo Placement */}
                <div>
                     <label className={`block text-sm font-bold mb-2 ${!schoolLogo ? 'text-gray-400' : 'text-gray-700'}`}>
                        Logo Placement
                     </label>
                     <div className="flex gap-3 mb-6">
                         {[
                             { id: 'left', label: 'Left' },
                             { id: 'center', label: 'Center' },
                             { id: 'right', label: 'Right' }
                         ].map((opt) => (
                             <label 
                                key={opt.id}
                                className={`flex-1 flex flex-col items-center justify-center py-3 rounded-lg border cursor-pointer transition-all text-sm font-semibold
                                    ${!schoolLogo ? 'opacity-50 pointer-events-none bg-gray-50 border-gray-100' : ''}
                                    ${logoPlacement === opt.id 
                                        ? 'bg-[#f3e8ff] border-[#8A2CB0] text-[#3C128D] shadow-sm' 
                                        : 'bg-white border-gray-200 text-gray-500 hover:bg-gray-50'
                                    }`}
                             >
                                 <input 
                                    type="radio" 
                                    name="logoPlacement" 
                                    value={opt.id}
                                    checked={logoPlacement === opt.id}
                                    onChange={(e) => setLogoPlacement(e.target.value as any)}
                                    className="sr-only"
                                    disabled={!schoolLogo}
                                 />
                                 {opt.label}
                             </label>
                         ))}
                     </div>
                </div>
             </div>

             <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                    <label className="block text-sm font-bold text-gray-700 mb-2">Heading Font</label>
                    <select
                        className="w-full px-4 py-2.5 rounded-lg border border-gray-200 bg-white focus:ring-2 focus:ring-[#8A2CB0] outline-none"
                        value={headingFont}
                        onChange={(e) => setHeadingFont(e.target.value)}
                    >
                        {FONT_OPTIONS.map((font) => (
                            <option key={font.value} value={font.value}>{font.label}</option>
                        ))}
                    </select>
                </div>
                <div>
                    <label className="block text-sm font-bold text-gray-700 mb-2">Body Font</label>
                    <select
                        className="w-full px-4 py-2.5 rounded-lg border border-gray-200 bg-white focus:ring-2 focus:ring-[#8A2CB0] outline-none"
                        value={bodyFont}
                        onChange={(e) => setBodyFont(e.target.value)}
                    >
                        {FONT_OPTIONS.map((font) => (
                            <option key={font.value} value={font.value}>{font.label}</option>
                        ))}
                    </select>
                </div>
             </div>
          </div>

          {/* General Info & Paper Specs */}
          <div className="space-y-6">
             <h3 className="text-sm font-bold text-gray-500 uppercase tracking-wide border-b border-gray-200/50 pb-2">Paper Specification</h3>

             <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className="block text-sm font-semibold text-gray-700 mb-2">Board / Curriculum</label>
                  <select
                    required
