import React, { useState } from 'react';
import { QuestionBank } from '../types';
import { CURRICULUM_DATA, GRADES, BOARDS } from '../constants';
import MarkdownRenderer from './MarkdownRenderer';
import { generateQuestionBankUpdate } from '../services/geminiService';

interface QuestionBankProps {
  banks: QuestionBank[];
  onUpdateBank: (bank: QuestionBank) => void;
  onBack: () => void;
}

const QuestionBankView: React.FC<QuestionBankProps> = ({ banks, onUpdateBank, onBack }) => {
  const [selectedBoard, setSelectedBoard] = useState<string>(BOARDS[0]);
  const [selectedClass, setSelectedClass] = useState<string>('');
  const [selectedSubject, setSelectedSubject] = useState<string>('');
  const [isUpdating, setIsUpdating] = useState(false);

  // Find existing bank for selected board, subject, and grade
  // Note: Handling banks created before 'board' property existed by assuming they are CBSE (first board) or strictly by subject/grade if board is undefined.
  const currentBank = banks.find(b => 
    b.subject === selectedSubject && 
    b.grade === selectedClass && 
    (b.board === selectedBoard || (!b.board && selectedBoard === BOARDS[0]))
  );

  const handleUpdate = async () => {
    if (!selectedSubject || !selectedClass) return;

    setIsUpdating(true);
    try {
      const newContent = await generateQuestionBankUpdate(selectedSubject, selectedClass, selectedBoard);

      const updatedBank: QuestionBank = currentBank 
        ? {
            ...currentBank,
            board: selectedBoard, // Ensure board is set on update
            lastUpdated: Date.now(),
            content: `### Update: ${new Date().toLocaleDateString()} ${new Date().toLocaleTimeString()}\n\n${newContent}\n\n---\n\n${currentBank.content}`
          }
        : {
            id: crypto.randomUUID(),
            board: selectedBoard,
            subject: selectedSubject,
            grade: selectedClass,
            lastUpdated: Date.now(),
            content: `### Question Bank: ${selectedSubject} (${selectedClass}) - ${selectedBoard}\n\n${newContent}`
          };

      onUpdateBank(updatedBank);
    } catch (error) {
      console.error(error);
      alert("Failed to update question bank. Please check your connection or API limit.");
    } finally {
      setIsUpdating(false);
    }
  };

  const handleDownload = () => {
    if (!currentBank) return;
    const blob = new Blob([currentBank.content], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `QuestionBank_${currentBank.subject}_${currentBank.grade}.txt`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleBoardChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    setSelectedBoard(e.target.value);
    setSelectedClass('');
    setSelectedSubject('');
  };

  const handleClassChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    setSelectedClass(e.target.value);
    setSelectedSubject('');
  };

  // Get subjects based on selected class and board
  const boardData = CURRICULUM_DATA[selectedBoard];
  const classData = boardData ? boardData[selectedClass] : null;
  const availableSubjects = classData ? Object.keys(classData) : [];

  return (
    <div className="max-w-6xl mx-auto p-4 sm:p-6 animate-fade-in pb-20">
      {/* Header */}
      <div className="flex justify-between items-center mb-6">
        <button 
          onClick={onBack}
          className="text-white hover:text-white/80 flex items-center gap-2 font-medium drop-shadow-sm transition-colors"
        >
          ← Back to Dashboard
        </button>
        <h1 className="text-2xl font-bold text-white drop-shadow-md">Master Question Bank</h1>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">

        {/* Controls Sidebar */}
        <div className="lg:col-span-1 space-y-4">
          <div className="glass-panel p-5 rounded-xl">
            <h3 className="font-bold text-gray-700 mb-4 border-b border-gray-200/50 pb-2">Select Context</h3>

            <div className="space-y-4">
              <div>
                <label className="block text-xs font-bold text-gray-500 mb-1 uppercase tracking-wide">Board / Curriculum</label>
                <select 
                  className="w-full px-3 py-2.5 rounded-lg border border-gray-200 bg-white/80 text-sm focus:ring-2 focus:ring-[#8A2CB0] outline-none"
                  value={selectedBoard}
                  onChange={handleBoardChange}
                >
                  {BOARDS.map(board => (
                    <option key={board} value={board}>{board}</option>
                  ))}
                </select>
              </div>

              <div>
                <label className="block text-xs font-bold text-gray-500 mb-1 uppercase tracking-wide">Class / Grade</label>
                <select 
                  className="w-full px-3 py-2.5 rounded-lg border border-gray-200 bg-white/80 text-sm focus:ring-2 focus:ring-[#8A2CB0] outline-none"
                  value={selectedClass}
                  onChange={handleClassChange}
                >
                  <option value="">Select Class</option>
                  {GRADES.map(grade => (
                    <option key={grade} value={grade}>{grade}</option>
                  ))}
                </select>
              </div>

              <div>
                <label className="block text-xs font-bold text-gray-500 mb-1 uppercase tracking-wide">Subject</label>
                <select 
                  className="w-full px-3 py-2.5 rounded-lg border border-gray-200 bg-white/80 text-sm focus:ring-2 focus:ring-[#8A2CB0] outline-none disabled:opacity-50"
                  value={selectedSubject}
                  onChange={(e) => setSelectedSubject(e.target.value)}
                  disabled={!selectedClass}
                >
                  <option value="">
                    {!selectedClass ? 'Select Class first' : 'Select Subject'}
                  </option>
                  {availableSubjects.map(subj => (
                    <option key={subj} value={subj}>{subj}</option>
                  ))}
                </select>
              </div>
            </div>

            <button
              onClick={handleUpdate}
              disabled={!selectedSubject || !selectedClass || isUpdating}
              className={`w-full mt-6 py-2.5 rounded-lg font-bold text-white shadow-lg transition-all flex items-center justify-center gap-2
                ${(!selectedSubject || !selectedClass || isUpdating) 
                    ? 'bg-gray-300 cursor-not-allowed shadow-none' 
                    : 'bg-gradient-to-r from-[#8A2CB0] to-[#3C128D] hover:from-[#7c269e] hover:to-[#2e0e6b] active:scale-95'
                }
              `}
            >
              {isUpdating ? (
                 <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                   <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                   <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                 </svg>
              ) : (
                currentBank ? 'Add Questions' : 'Create Bank'
              )}
            </button>
          </div>

          {currentBank && (
            <div className="glass-panel p-4 rounded-xl border-l-4 border-[#8A2CB0] text-sm">
               <p className="font-bold text-[#3C128D] mb-1">Status: Active</p>
               <p className="text-gray-600 text-xs">Last updated: {new Date(currentBank.lastUpdated).toLocaleDateString()}</p>
               <button 
                 onClick={handleDownload}
                 className="mt-3 text-xs font-bold text-[#8A2CB0] hover:text-[#3C128D] underline"
               >
                 Download Content (.txt)
               </button>
            </div>
          )}
        </div>

        {/* Content Area */}
        <div className="lg:col-span-3">
          <div className="glass-panel rounded-xl min-h-[600px] flex flex-col overflow-hidden bg-white">
            {currentBank ? (
              <div className="p-8 paper-font overflow-y-auto max-h-[800px]">
                <MarkdownRenderer content={currentBank.content} />
              </div>
            ) : (
              <div className="flex-1 flex flex-col items-center justify-center text-gray-400 p-8 text-center">
                <div className="w-20 h-20 bg-gray-50 rounded-full flex items-center justify-center mb-4">
                    <svg className="w-10 h-10 opacity-30" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M19 11H5m14 0a2 2 0 0 1 2 2v6a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-6a2 2 0 0 1 2-2m14 0V9a2 2 0 0 0-2-2M5 11V9a2 2 0 0 1 2-2m0 0V5a2 2 0 0 1 2-2h6a2 2 0 0 1 2 2v2M7 7h10"></path>
                    </svg>
                </div>
                <h3 className="text-lg font-semibold text-gray-600">Question Bank Empty</h3>
                <p className="max-w-md mt-2 text-sm">Select a Class and Subject from the sidebar and click "Create Bank" to start generating your repository.</p>
              </div>
            )}
          </div>
        </div>

      </div>
    </div>
  );
};

export default QuestionBankView;

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { PaperConfig, GeneratedPaper } from "../types";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

// Define the response schema strictly to ensure easy parsing
const paperResponseSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    title: {
      type: Type.STRING,
      description: "The formal title of the examination paper (e.g., 'Grade 10 Physics - Mid Term').",
    },
    questionPaper: {
      type: Type.STRING,
      description: "The full question paper text. IMPORTANT: Output CLEAN PLAIN TEXT ONLY. Do NOT use Markdown symbols (no #, no *, no **). Use actual blank lines for spacing. Format Sections clearly (e.g., SECTION A: ...).",
    },
    answerKey: {
      type: Type.STRING,
      description: "The comprehensive answer key and marking scheme in clean plain text format.",
    },
  },
  required: ["title", "questionPaper", "answerKey"],
};

export const generateQuestionPaper = async (config: PaperConfig): Promise<GeneratedPaper> => {
  if (!apiKey) {
    throw new Error("API Key is missing. Please check your environment configuration.");
  }

  const prompt = `
    Act as a senior academic curriculum developer for ${config.board} (India). 
    Generate a high-quality question paper based on the following specifications:

    Board/Curriculum: ${config.board}
    Subject: ${config.subject}
    Grade/Level: ${config.grade}
    Total Marks: ${config.totalMarks}
    Difficulty: ${config.difficulty}

    Structure the paper with the following question distribution:
    - Multiple Choice Questions (MCQ): ${config.counts.mcq}
    - Assertion-Reasoning (A/R): ${config.counts.ar} (Format: A is true, R is false, etc.)
    - Very Short Answer (VSAQ): ${config.counts.vsaq}
    - Short Answer (SAQ): ${config.counts.saq}
    - Long Answer (LAQ): ${config.counts.laq}
    - Case Study/Source-based: ${config.counts.caseStudy} (Provide a paragraph/source followed by sub-questions)

    Pedagogical Guidelines:
    1. Apply Bloom's Taxonomy. Ensure a mix of knowledge, understanding, application, and analysis based on the difficulty level '${config.difficulty}'.
    2. Questions must be strictly aligned with the syllabus of ${config.board} for ${config.grade} ${config.subject}.
    3. Questions should be clear, unambiguous, and grade-appropriate.
    4. Group questions into logical sections (e.g., SECTION A: OBJECTIVE TYPE, SECTION B: SHORT ANSWER, etc.).

    FORMATTING RULES (CRITICAL):
    1. **NO MARKDOWN**: Do NOT use hashtags (#) for headers or asterisks (**) for bolding. Output strictly plain text.
    2. **SPACING**: Leave exactly ONE blank line before and after every Section Heading. Leave ONE blank line between questions.
    3. **NUMBERING**: Number questions as "1.", "2.", "3.". 
    4. **OPTIONS**: For MCQs, place options on separate lines labeled "A)", "B)", "C)", "D)".
    5. **SECTION HEADERS**: Type section headers in UPPERCASE (e.g., "SECTION A: MULTIPLE CHOICE QUESTIONS").
    6. **CLEAN TEXT**: Do not use escape sequences like \\n in the visible output, use actual line breaks.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: paperResponseSchema,
        temperature: 0.4, // Lower temperature for more structured/academic output
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response received from AI.");

    const data = JSON.parse(text);

    return {
      id: crypto.randomUUID(),
      timestamp: Date.now(),
      config,
      title: data.title,
      content: data.questionPaper,
      answerKey: data.answerKey,
    };
  } catch (error) {
    console.error("Error generating paper:", error);
    throw error;
  }
};

export const generateQuestionBankUpdate = async (subject: string, grade: string, board: string = 'CBSE / NCERT'): Promise<string> => {
  if (!apiKey) {
    throw new Error("API Key is missing.");
  }

  const prompt = `
    Act as a Subject Matter Expert for ${board}. 

    TASK: Generate a fresh set of "Important Questions" for the Subject: "${subject}" and Grade: "${grade}".

    CONTEXT:
    - Syllabus: Strictly adhere to the ${board} syllabus for this grade.
    - Focus: Identify key topics and frequently asked questions in examinations.

    CONTENT REQUIREMENTS:
    - Provide 5 High-Probability MCQs with answers.
    - Provide 3 Important Short Answer Questions (Concept-based).
    - Provide 2 Critical Long Answer Questions (Application/Analysis based).
    - Provide 1 Case-Study/Competency-based Question.

    FORMATTING:
    - Output CLEAN PLAIN TEXT ONLY. 
    - NO Markdown symbols (no #, no *).
    - Use "SECTION:" to denote categories.
    - Number questions clearly.
    - Put answers at the end of the document.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        temperature: 0.5,
      },
    });

    return response.text || "Failed to generate questions.";
  } catch (error) {
    console.error("Error updating question bank:", error);
    throw error;
  }
};

