  },
  "Telangana SCERT": {
    "Class 3": { "Telugu": TELUGU_LOWER_COMMON },
    "Class 4": { "Telugu": TELUGU_LOWER_COMMON },
    "Class 5": { "Telugu": TELUGU_LOWER_COMMON },
    "Class 6": { "Telugu": ["Abhinandana", "Snehabandham", "Varsham", "Lekha", "Palle Velugu"] },
    "Class 7": { "Telugu": ["Chaduvu", "Nayakudu", "Amma Gnapakam", "Palle Andalu"] },
    "Class 8": { "Telugu": ["Tyaga Nirathi", "Samudhra Prayanam", "Bhandari Basavanna", "Amma Kosam"] },
