import React, { useState, useCallback, useEffect } from 'react';
import Dashboard from './components/Dashboard';
import PaperForm from './components/PaperForm';
import PaperPreview from './components/PaperPreview';
import QuestionBankView from './components/QuestionBank';
import { PaperConfig, GeneratedPaper, QuestionBank } from './types';
import { generateQuestionPaper } from './services/geminiService';

type View = 'dashboard' | 'create' | 'preview' | 'bank';

const App: React.FC = () => {
  const [view, setView] = useState<View>('dashboard');

  // Initialize history from localStorage
  const [history, setHistory] = useState<GeneratedPaper[]>(() => {
    if (typeof window !== 'undefined') {
      try {
        const saved = localStorage.getItem('genpaper_history');
        return saved ? JSON.parse(saved) : [];
      } catch (error) {
        console.error('Failed to parse history from localStorage:', error);
        return [];
      }
    }
    return [];
  });

  // Initialize Question Banks from localStorage
  const [questionBanks, setQuestionBanks] = useState<QuestionBank[]>(() => {
    if (typeof window !== 'undefined') {
        try {
          const saved = localStorage.getItem('genpaper_questionbanks');
          return saved ? JSON.parse(saved) : [];
        } catch (error) {
          console.error('Failed to parse banks from localStorage:', error);
          return [];
        }
      }
      return [];
  });

  const [currentPaper, setCurrentPaper] = useState<GeneratedPaper | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Persist history
  useEffect(() => {
    try {
      localStorage.setItem('genpaper_history', JSON.stringify(history));
    } catch (error) {
      console.error('Failed to save history to localStorage:', error);
    }
  }, [history]);

  // Persist banks
  useEffect(() => {
    try {
      localStorage.setItem('genpaper_questionbanks', JSON.stringify(questionBanks));
    } catch (error) {
        console.error('Failed to save banks to localStorage:', error);
    }
  }, [questionBanks]);

  const handleGenerate = async (config: PaperConfig) => {
    setIsGenerating(true);
    setError(null);
    try {
      const newPaper = await generateQuestionPaper(config);
      setHistory(prev => [...prev, newPaper]);
      setCurrentPaper(newPaper);
      setView('preview');
    } catch (err: any) {
      setError(err.message || "Failed to generate paper. Please try again.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleUpdateBank = (updatedBank: QuestionBank) => {
    setQuestionBanks(prev => {
        const index = prev.findIndex(b => b.id === updatedBank.id);
        if (index >= 0) {
            const newBanks = [...prev];
            newBanks[index] = updatedBank;
            return newBanks;
        } else {
            return [...prev, updatedBank];
        }
    });
  };

  const handleViewPaper = (paper: GeneratedPaper) => {
    setCurrentPaper(paper);
    setView('preview');
  };

  const handleCreateNew = useCallback(() => {
    setView('create');
    setError(null);
  }, []);

  const handleBackToDashboard = useCallback(() => {
    setView('dashboard');
    setCurrentPaper(null);
  }, []);

  const handleCancelCreate = useCallback(() => {
    setView('dashboard');
  }, []);

  return (
    <div className="min-h-screen relative font-sans text-gray-900 selection:bg-[#EEA727] selection:text-[#3C128D] overflow-x-hidden flex flex-col">

      {/* Premium Vibrant Background Elements */}
      <div className="premium-bg-wrapper">
        <div className="orb orb-1"></div>
        <div className="orb orb-2"></div>
        <div className="orb orb-3"></div>
        <div className="orb orb-4"></div>
        <div className="orb orb-5"></div>
      </div>

      {/* Top Navigation Bar - Glass Effect */}
      <nav className="glass-panel sticky top-0 z-50 px-6 py-4 flex justify-between items-center transition-all duration-300 border-b-0 border-t-0 rounded-b-2xl mx-2 mt-2">
        <div className="flex items-center gap-3" onClick={handleBackToDashboard} style={{cursor: 'pointer'}}>
            <div className="bg-gradient-to-br from-[#3C128D] to-[#8A2CB0] w-10 h-10 rounded-xl flex items-center justify-center text-white font-bold text-xl shadow-lg shadow-[#3C128D]/20 transform hover:scale-105 transition-transform">
                G
            </div>
            <span className="text-xl font-bold tracking-tight text-gray-900">GenPaper<span className="text-transparent bg-clip-text bg-gradient-to-r from-[#8A2CB0] to-[#EEA727]">AI</span></span>
        </div>
        <div className="flex gap-1 p-1 bg-white/50 rounded-xl backdrop-blur-md border border-white/40">
             <button 
                onClick={() => setView('dashboard')} 
                className={`px-5 py-2 rounded-lg text-sm font-semibold transition-all duration-300 ${view === 'dashboard' ? 'bg-white text-[#3C128D] shadow-sm scale-100' : 'text-gray-600 hover:text-gray-900 hover:bg-white/30'}`}
             >
                Dashboard
             </button>
             <button 
                onClick={() => setView('bank')} 
                className={`px-5 py-2 rounded-lg text-sm font-semibold transition-all duration-300 ${view === 'bank' ? 'bg-white text-[#3C128D] shadow-sm scale-100' : 'text-gray-600 hover:text-gray-900 hover:bg-white/30'}`}
             >
                Question Bank
             </button>
        </div>
      </nav>

      {/* Main Content Area */}
      <main className="container mx-auto py-8 px-4 relative z-10 flex-grow">
        {error && (
            <div className="max-w-4xl mx-auto mb-8 p-4 glass-panel border-l-4 border-rose-500 text-rose-700 rounded-xl shadow-lg flex justify-between items-center animate-fade-in">
                <span className="font-medium flex items-center gap-2">
                   <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
                   {error}
                </span>
                <button onClick={() => setError(null)} className="text-rose-500 font-bold hover:text-rose-800 p-1 rounded-md hover:bg-rose-50 transition-colors">&times;</button>
            </div>
        )}

        {view === 'dashboard' && (
          <Dashboard 
            history={history} 
            onCreateNew={handleCreateNew} 
            onViewPaper={handleViewPaper} 
            onViewBank={() => setView('bank')}
          />
        )}

        {view === 'create' && (
          <PaperForm 
            onGenerate={handleGenerate} 
            onCancel={handleCancelCreate} 
            isGenerating={isGenerating} 
          />
        )}

        {view === 'preview' && currentPaper && (
          <PaperPreview 
            paper={currentPaper} 
            onBack={handleBackToDashboard} 
          />
        )}

        {view === 'bank' && (
            <QuestionBankView
                banks={questionBanks}
                onUpdateBank={handleUpdateBank}
                onBack={handleBackToDashboard}
            />
        )}
      </main>

      {/* Application Footer */}
      <footer className="relative z-10 py-6 text-center">
        <p className="text-white/80 text-[10px] md:text-xs font-medium uppercase tracking-widest drop-shadow-sm">
            © All Rights Reserved. Made by Darshit, Sree Pendyala
        </p>
      </footer>
    </div>
  );
};

export default App;

