                G
            </div>
            <span className="text-xl font-bold tracking-tight text-gray-900 drop-shadow-sm">GenPaper<span className="text-transparent bg-clip-text bg-gradient-to-r from-[#8A2CB0] to-[#EEA727]">AI</span></span>
        </div>
        <div className="flex gap-2">
             <button 
                onClick={() => setView('dashboard')} 
                className={`px-5 py-2 rounded-lg text-sm font-bold transition-all duration-300 ${view === 'dashboard' ? 'bg-white text-[#3C128D] shadow-md scale-100 ring-1 ring-[#8A2CB0]/20' : 'text-gray-700 hover:text-gray-900 hover:bg-white/40'}`}
