                                        placeholder="e.g. Section A"
                                    />
                                </div>
                                <div className="md:col-span-4">
                                    <label className="block text-xs font-bold text-gray-500 mb-1">Question Type</label>
                                    <select
                                        value={section.type}
                                        onChange={(e) => handleUpdateSection(section.id, 'type', e.target.value)}
                                        className="w-full px-3 py-2 border rounded-lg text-sm bg-white focus:ring-2 focus:ring-[#8A2CB0] outline-none"
                                    >
                                        {QUESTION_TYPES_DROPDOWN.map(t => (
                                            <option key={t.value} value={t.value}>{t.label}</option>
                                        ))}
                                    </select>
                                </div>
                                <div className="md:col-span-2">
                                    <label className="block text-xs font-bold text-gray-500 mb-1">Count</label>
                                    <input 
