                                    />
                                </div>
                                <div className="md:col-span-2">
                                    <label className="block text-xs font-bold text-gray-500 mb-1">Marks/Q</label>
                                    <input 
                                        type="number" 
                                        min="0.5"
                                        step="0.5"
                                        value={section.marksPerQuestion}
                                        onChange={(e) => handleUpdateSection(section.id, 'marksPerQuestion', parseFloat(e.target.value) || 0)}
                                        className="w-full px-3 py-2 border rounded-lg text-sm text-center focus:ring-2 focus:ring-[#8A2CB0] outline-none"
                                    />
                                </div>
                                <div className="md:col-span-1 pb-2 text-right">
                                    <span className="text-sm font-bold text-[#8A2CB0]">
