            ) : (
                // --- STANDARD TABLE UI ---
                <div className="overflow-hidden border border-gray-200 rounded-xl shadow-sm bg-white animate-fade-in">
                    <table className="min-w-full text-sm">
                        <thead className="bg-gray-50/80 text-gray-600 font-semibold border-b border-gray-200">
                            <tr>
                                <th className="px-4 py-3 text-left">Type</th>
                                <th className="px-4 py-3 text-center">Marks/Q</th>
                                <th className="px-4 py-3 text-center">Count</th>
                                <th className="px-4 py-3 text-right">Total</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-100">
                            {QUESTION_SPECS.map((spec) => (
                                <tr key={spec.key} className="hover:bg-gray-50/50 transition-colors">
                                    <td className="px-4 py-3 text-gray-800 font-medium">{spec.label}</td>
                                    <td className="px-4 py-3 text-center text-gray-500">{spec.marks}</td>
                                    <td className="px-4 py-2 text-center">
                                        <input
                                            type="number"
                                            min="0"
                                            className={`w-16 text-center px-2 py-1 rounded border outline-none focus:ring-1 focus:border-[#8A2CB0]
                                                ${errors[spec.key] ? 'border-red-500 bg-red-50' : 'border-gray-200 bg-white'}`}
                                            value={counts[spec.key]}
                                            onChange={(e) => handleCountChange(spec.key, e.target.value)}
                                            onBlur={() => handleBlur(spec.key)}
                                        />
                                    </td>
                                    <td className="px-4 py-3 text-right font-semibold text-gray-700">
                                        {counts[spec.key] === '' ? '-' : (parseInt(counts[spec.key]) * spec.marks)}
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            )}
          </div>

          {/* Action Buttons */}
          <div className="flex justify-end gap-4 pt-2">
            <button
              type="button"
              onClick={onCancel}
              className="btn-glass btn-glass-secondary px-6 py-3 rounded-xl font-medium"
              disabled={isGenerating}
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={isGenerating || currentCalculatedMarks === null || currentCalculatedMarks === 0}
              className={`btn-glass btn-glass-primary px-8 py-3 rounded-xl font-bold flex items-center gap-2
                ${isGenerating || currentCalculatedMarks === null || currentCalculatedMarks === 0
                  ? 'opacity-60 cursor-not-allowed' 
                  : ''
                }`}
            >
              {isGenerating ? (
                <>
                  <svg className="animate-spin h-5 w-5 text-white" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                  Generating Paper...
                </>
              ) : (
                'Generate Paper'
              )}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default PaperForm;

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { PaperConfig, GeneratedPaper } from "../types";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

// Define the response schema strictly to ensure easy parsing
const paperResponseSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    title: {
      type: Type.STRING,
      description: "The formal title of the examination paper (e.g., 'Grade 10 Physics - Mid Term').",
    },
    questionPaper: {
      type: Type.STRING,
      description: "The full question paper text. IMPORTANT: Output CLEAN PLAIN TEXT ONLY. Do NOT use Markdown symbols (no #, no *, no **). Use actual blank lines for spacing. Format Sections clearly (e.g., SECTION A: ...).",
    },
    answerKey: {
      type: Type.STRING,
      description: "The comprehensive answer key and marking scheme in clean plain text format.",
    },
  },
  required: ["title", "questionPaper", "answerKey"],
};

export const generateQuestionPaper = async (config: PaperConfig): Promise<GeneratedPaper> => {
  if (!apiKey) {
    throw new Error("API Key is missing. Please check your environment configuration.");
  }

  let structurePrompt = '';

  // Use custom section structure if customSections are present, regardless of what the testType name is.
  if (config.customSections && config.customSections.length > 0) {
    // Build prompt for custom sections
    structurePrompt = `
    Generate the paper STRICTLY according to these defined sections:

    ${config.customSections.map((sec, idx) => `
    SECTION ${idx + 1}: ${sec.title}
    - Question Type: ${sec.type}
    - Number of Questions: ${sec.count}
    - Marks per Question: ${sec.marksPerQuestion}
    ${sec.instructions ? `- Instructions: ${sec.instructions}` : ''}
    `).join('\n')}

    Ensure the total marks sum up to ${config.totalMarks}.
    `;
  } else {
    // Build prompt for standard/legacy distribution
    structurePrompt = `
    Structure the paper with the following question distribution:
    - Multiple Choice Questions (MCQ): ${config.counts.mcq}
    - Assertion-Reasoning (A/R): ${config.counts.ar} (Format: A is true, R is false, etc.)
    - Very Short Answer (VSAQ): ${config.counts.vsaq}
    - Short Answer (SAQ): ${config.counts.saq}
    - Long Answer (LAQ): ${config.counts.laq}
    - Case Study/Source-based: ${config.counts.caseStudy} (Provide a paragraph/source followed by sub-questions)
    `;
  }

  const prompt = `
    Act as a senior academic curriculum developer for ${config.board} (India). 
    Generate a high-quality question paper based on the following specifications:

    Exam Type: ${config.testType}
    Board/Curriculum: ${config.board}
    Subject & Topics: ${config.subject}
    Grade/Level: ${config.grade}
    Total Marks: ${config.totalMarks}
    Difficulty: ${config.difficulty}

    ${structurePrompt}

    Pedagogical Guidelines:
    1. Apply Bloom's Taxonomy. Ensure a mix of knowledge, understanding, application, and analysis based on the difficulty level '${config.difficulty}'.
    2. Questions must be strictly aligned with the syllabus of ${config.board} for ${config.grade}.
    3. Questions should be clear, unambiguous, and grade-appropriate.
    4. Group questions into logical sections matching the structure defined above.
    5. **SCOPE**: Strictly restrict questions to the specific chapters/topics listed in the 'Subject & Topics' field. Do not ask questions from outside these topics.

    FORMATTING RULES (CRITICAL):
    1. **NO MARKDOWN**: Do NOT use hashtags (#) for headers or asterisks (**) for bolding. Output strictly plain text.
    2. **SPACING**: Leave exactly ONE blank line before and after every Section Heading. Leave ONE blank line between questions.
    3. **NUMBERING**: Number questions as "1.", "2.", "3.". 
    4. **OPTIONS**: For MCQs, place options on separate lines labeled "A)", "B)", "C)", "D)".
    5. **SECTION HEADERS**: Type section headers in UPPERCASE (e.g., "SECTION A: ...").
    6. **CLEAN TEXT**: Do not use escape sequences like \\n in the visible output, use actual line breaks.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: paperResponseSchema,
        temperature: 0.4, // Lower temperature for more structured/academic output
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response received from AI.");

    const data = JSON.parse(text);

    return {
      id: crypto.randomUUID(),
      timestamp: Date.now(),
      config,
      title: data.title,
      content: data.questionPaper,
      answerKey: data.answerKey,
    };
  } catch (error) {
    console.error("Error generating paper:", error);
    throw error;
  }
};

export const generateQuestionBankUpdate = async (subject: string, grade: string, board: string = 'CBSE / NCERT'): Promise<string> => {
  if (!apiKey) {
    throw new Error("API Key is missing.");
  }

  const prompt = `
    Act as a Subject Matter Expert for ${board}. 

    TASK: Generate a fresh set of "Important Questions" for the Subject: "${subject}" and Grade: "${grade}".

    CONTEXT:
    - Syllabus: Strictly adhere to the ${board} syllabus for this grade.
    - Focus: Identify key topics and frequently asked questions in examinations.

    CONTENT REQUIREMENTS:
    - Provide 5 High-Probability MCQs with answers.
    - Provide 3 Important Short Answer Questions (Concept-based).
    - Provide 2 Critical Long Answer Questions (Application/Analysis based).
    - Provide 1 Case-Study/Competency-based Question.

    FORMATTING:
    - Output CLEAN PLAIN TEXT ONLY. 
    - NO Markdown symbols (no #, no *).
    - Use "SECTION:" to denote categories.
    - Number questions clearly.
    - Put answers at the end of the document.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        temperature: 0.5,
      },
    });

    return response.text || "Failed to generate questions.";
  } catch (error) {
    console.error("Error updating question bank:", error);
    throw error;
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { PaperConfig, QuestionCounts, CustomSection } from '../types';
import { CURRICULUM_DATA, GRADES, FONT_OPTIONS, BOARDS, TEST_TYPES, QUESTION_TYPES_DROPDOWN } from '../constants';

// Defined Weights and Specs (Legacy/Standard Mode)
const QUESTION_SPECS: { label: string; key: keyof QuestionCounts; marks: number }[] = [
  { label: "MCQs", key: "mcq", marks: 1 },
  { label: "Assertion-Reason", key: "ar", marks: 1 },
  { label: "Very Short (VSAQ)", key: "vsaq", marks: 2 },
  { label: "Short Answer (SAQ)", key: "saq", marks: 3 },
  { label: "Case Study", key: "caseStudy", marks: 4 },
  { label: "Long Answer (LAQ)", key: "laq", marks: 5 },
];

interface PaperFormProps {
  onGenerate: (config: PaperConfig) => void;
  onCancel: () => void;
  isGenerating: boolean;
}

const PaperForm: React.FC<PaperFormProps> = ({ onGenerate, onCancel, isGenerating }) => {
  const [schoolName, setSchoolName] = useState('');
  const [schoolNameError, setSchoolNameError] = useState<string | null>(null);
  const schoolNameRef = useRef<HTMLInputElement>(null);

  const [schoolLogo, setSchoolLogo] = useState<string | null>(null);
  const [logoPlacement, setLogoPlacement] = useState<'left' | 'center' | 'right'>('left');
  const [logoError, setLogoError] = useState<string | null>(null);

  // Typography State
  const [headingFont, setHeadingFont] = useState(FONT_OPTIONS[0].value);
  const [bodyFont, setBodyFont] = useState(FONT_OPTIONS[1].value);

  // General Instructions State
  const [generalInstructions, setGeneralInstructions] = useState('');
  const MAX_INSTRUCTION_CHARS = 500;

  // Curriculum State
  const [selectedBoard, setSelectedBoard] = useState(BOARDS[0]);
  const [selectedClass, setSelectedClass] = useState('');
  const [selectedSubject, setSelectedSubject] = useState('');
  const [testType, setTestType] = useState(TEST_TYPES[0]);

  // Custom Test Name State
  const [customTestName, setCustomTestName] = useState('');
  const [customTestNameError, setCustomTestNameError] = useState<string | null>(null);

  // Chapter Selection State
  const [selectedChapters, setSelectedChapters] = useState<string[]>([]);
  const [chapterError, setChapterError] = useState<string | null>(null);

  // Time Allowed State
  const [timeAllowed, setTimeAllowed] = useState('2 Hours');
  const [timePreset, setTimePreset] = useState('2 Hours');
  const [customTime, setCustomTime] = useState('');
  const [timeAllowedError, setTimeAllowedError] = useState<string | null>(null);

  const [totalMarks, setTotalMarks] = useState(50);
  const [difficulty, setDifficulty] = useState<'Easy' | 'Medium' | 'Hard'>('Medium');

  // Legacy: State for standard counts
  const [counts, setCounts] = useState<Record<keyof QuestionCounts, string>>({
    mcq: '',
    ar: '',
    vsaq: '',
    saq: '',
    laq: '',
    caseStudy: '',
  });

  // Custom: State for custom sections
  const [customSections, setCustomSections] = useState<CustomSection[]>([]);
  const [customTotalMarks, setCustomTotalMarks] = useState(0);
  const [customTotalQuestions, setCustomTotalQuestions] = useState(0);

  const [errors, setErrors] = useState<Record<string, string | null>>({
    mcq: null,
    ar: null,
    vsaq: null,
    saq: null,
    laq: null,
    caseStudy: null,
  });

  const [currentCalculatedMarks, setCurrentCalculatedMarks] = useState<number | null>(null);

  // Logic to fetch available subjects/topics based on Board -> Class
  const boardData = CURRICULUM_DATA[selectedBoard];
  const classData = boardData ? boardData[selectedClass] : null;
  const availableSubjects = classData ? Object.keys(classData) : [];

  // Available Chapters based on selection
  const availableChapters = (classData && selectedSubject) 
    ? classData[selectedSubject] || [] 
    : [];

  const isCustomTest = testType === 'Custom Test';

  // Update calculation whenever counts change (Standard Mode)
  useEffect(() => {
    if (isCustomTest) return; // Skip for custom mode

    const allFieldsFilled = QUESTION_SPECS.every(spec => counts[spec.key] !== '');

    if (allFieldsFilled) {
      const total = QUESTION_SPECS.reduce((acc, spec) => {
        const val = parseInt(counts[spec.key]) || 0;
        return acc + (val * spec.marks);
      }, 0);
      setCurrentCalculatedMarks(total);
    } else {
      setCurrentCalculatedMarks(null);
    }
  }, [counts, isCustomTest]);

  // Update calculation whenever sections change (Custom Mode)
  useEffect(() => {
    if (!isCustomTest) return;

    const totalM = customSections.reduce((acc, sec) => acc + (sec.count * sec.marksPerQuestion), 0);
    const totalQ = customSections.reduce((acc, sec) => acc + sec.count, 0);

    setCustomTotalMarks(totalM);
    setCustomTotalQuestions(totalQ);
    setCurrentCalculatedMarks(totalM);

  }, [customSections, isCustomTest]);

  const validateField = (key: keyof QuestionCounts, value: string) => {
    if (value === '') {
      return 'Required';
    }
    const num = parseInt(value);
    if (isNaN(num) || num < 0) {
      return 'Invalid';
    }
    return null;
  };

  const handleSchoolNameChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setSchoolName(e.target.value);
    if (e.target.value.trim() !== '') {
        setSchoolNameError(null);
    }
  };

  const handlePresetChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const val = e.target.value;
    setTimePreset(val);

    if (val === 'Custom') {
        setTimeAllowed(customTime);
    } else {
        setTimeAllowed(val);
        setTimeAllowedError(null);
    }
  };

  const handleCustomTimeChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      const val = e.target.value;
      setCustomTime(val);
      if (timePreset === 'Custom') {
        setTimeAllowed(val);
        if (val.trim() !== '') {
            setTimeAllowedError(null);
        }
      }
  };

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setLogoError(null);

    // Validate Size (2MB)
    if (file.size > 2 * 1024 * 1024) {
      setLogoError("File size exceeds 2MB limit.");
      return;
    }

    // Validate Type
    if (!['image/png', 'image/jpeg', 'image/jpg'].includes(file.type)) {
      setLogoError("Only PNG and JPG formats are allowed.");
      return;
    }

    const reader = new FileReader();
    reader.onload = (event) => {
      setSchoolLogo(event.target?.result as string);
    };
    reader.readAsDataURL(file);
  };

  const handleRemoveLogo = () => {
    setSchoolLogo(null);
    setLogoError(null);
    const input = document.getElementById('logo-upload') as HTMLInputElement;
    if (input) input.value = '';
  };

  const handleCountChange = (key: keyof QuestionCounts, value: string) => {
    if (value !== '' && !/^\d+$/.test(value)) return;

    setCounts(prev => ({ ...prev, [key]: value }));

    if (value !== '') {
        setErrors(prev => ({ ...prev, [key]: null }));
    }
  };

  const handleBlur = (key: keyof QuestionCounts) => {
    const error = validateField(key, counts[key]);
    setErrors(prev => ({ ...prev, [key]: error }));
  };

  const handleBoardChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    setSelectedBoard(e.target.value);
    setSelectedClass('');
    setSelectedSubject('');
    setSelectedChapters([]);
  };

  const handleClassChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    setSelectedClass(e.target.value);
    setSelectedSubject('');
    setSelectedChapters([]);
  };

  const handleSubjectChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    setSelectedSubject(e.target.value);
    setSelectedChapters([]); // Reset chapters when subject changes
    setChapterError(null);
  };

  const handleTestTypeChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
      setTestType(e.target.value);
      setCustomTestNameError(null); // Clear error on change
  };

  const handleCustomTestNameChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      setCustomTestName(e.target.value);
      if (e.target.value.trim().length >= 3) {
          setCustomTestNameError(null);
      }
  };

  // --- Chapter Selection Logic ---

  const handleSelectAll = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.checked) {
        setSelectedChapters([...availableChapters]);
        setChapterError(null);
    } else {
        setSelectedChapters([]);
    }
  };

  const handleChapterToggle = (chapter: string) => {
    setSelectedChapters(prev => {
        const newSelection = prev.includes(chapter)
            ? prev.filter(c => c !== chapter)
            : [...prev, chapter];

        if (newSelection.length > 0) setChapterError(null);
        return newSelection;
    });
  };

  const isAllSelected = availableChapters.length > 0 && selectedChapters.length === availableChapters.length;
  const isIndeterminate = selectedChapters.length > 0 && selectedChapters.length < availableChapters.length;


  const handleAutoDistribute = () => {
    let newCounts: Record<keyof QuestionCounts, number> = { mcq: 0, ar: 0, vsaq: 0, saq: 0, laq: 0, caseStudy: 0 };
    let currentSum = 0;

    // 1. Minimum 1 each if mathematically possible
    for (const spec of QUESTION_SPECS) {
        if (currentSum + spec.marks <= totalMarks) {
            newCounts[spec.key]++;
            currentSum += spec.marks;
        }
    }

    // 2. Distribute remainder
    while (currentSum < totalMarks) {
        const candidates = QUESTION_SPECS.filter(spec => currentSum + spec.marks <= totalMarks);
        if (candidates.length === 0) break;
        candidates.sort((a, b) => newCounts[a.key] - newCounts[b.key]);
        const bestSpec = candidates[0];
        newCounts[bestSpec.key]++;
        currentSum += bestSpec.marks;
    }

    const stringCounts: any = {};
    QUESTION_SPECS.forEach(spec => {
        stringCounts[spec.key] = newCounts[spec.key].toString();
    });

    setCounts(stringCounts);
    setErrors({ mcq: null, ar: null, vsaq: null, saq: null, laq: null, caseStudy: null });
  };

  // --- Custom Section Logic ---

  const handleAddSection = () => {
    const newSection: CustomSection = {
        id: crypto.randomUUID(),
        title: `Section ${String.fromCharCode(65 + customSections.length)}`, // Section A, B, C...
        type: 'Multiple Choice Question (MCQ)',
        count: 5,
        marksPerQuestion: 1
    };
    setCustomSections([...customSections, newSection]);
  };

  const handleRemoveSection = (id: string) => {
    setCustomSections(prev => prev.filter(s => s.id !== id));
  };

  const handleUpdateSection = (id: string, field: keyof CustomSection, value: any) => {
    setCustomSections(prev => prev.map(s => {
        if (s.id === id) {
            return { ...s, [field]: value };
        }
        return s;
    }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    let hasErrors = false;

    if (schoolName.trim() === '') {
        setSchoolNameError('This field is required');
        hasErrors = true;
        // Auto Scroll and Focus on Error
        if (schoolNameRef.current) {
            schoolNameRef.current.scrollIntoView({ behavior: 'smooth', block: 'center' });
            schoolNameRef.current.focus();
        }
    }

    if (timeAllowed.trim() === '') {
        setTimeAllowedError('Required');
        hasErrors = true;
    } else if (!/\d/.test(timeAllowed)) {
        setTimeAllowedError('Must contain number');
        hasErrors = true;
    }

    if (selectedChapters.length === 0) {
        setChapterError("Please select at least one chapter to generate question paper.");
        hasErrors = true;
    }

    const newErrors: any = {};

    if (!isCustomTest) {
        QUESTION_SPECS.forEach(spec => {
            const error = validateField(spec.key, counts[spec.key]);
            if (error) {
                hasErrors = true;
                newErrors[spec.key] = error;
            }
        });
    } else {
        // Custom Test Validation
        if (!customTestName.trim()) {
            setCustomTestNameError("Please enter a name for your custom test.");
            hasErrors = true;
        } else if (customTestName.trim().length < 3) {
            setCustomTestNameError("Test name must be at least 3 characters.");
            hasErrors = true;
        }

        if (customSections.length === 0) {
            hasErrors = true;
            alert("Please add at least one section for the custom test.");
        }
        if (currentCalculatedMarks !== totalMarks) {
            hasErrors = true;
            // No alert needed, visual feedback exists
        }
    }

    if (hasErrors) {
        setErrors(newErrors);
        return;
    }

    let finalCounts: any = {};
    if (!isCustomTest) {
        QUESTION_SPECS.forEach(spec => {
            finalCounts[spec.key] = parseInt(counts[spec.key]);
        });
    }

    // Construct final subject string with specific chapters
    const chaptersString = selectedChapters.join(', ');
    const finalSubjectString = `${selectedSubject} (Chapters: ${chaptersString})`;

    // Use the custom name if custom test mode is active
    const finalTestType = isCustomTest ? customTestName.trim() : testType;

    onGenerate({
      board: selectedBoard,
      schoolName: schoolName.trim(),
      schoolLogo: schoolLogo || undefined,
      logoPlacement,
      headingFont,
      bodyFont,
      generalInstructions: generalInstructions.trim() || undefined,
      subject: finalSubjectString,
      grade: selectedClass,
      timeAllowed: timeAllowed.trim(),
      totalMarks,
      difficulty,
      testType: finalTestType,
      customSections: isCustomTest ? customSections : undefined,
      counts: finalCounts as QuestionCounts
    });
  };

  return (
    <div className="max-w-4xl mx-auto">
      <div className="glass-panel rounded-2xl overflow-hidden animate-fade-in">
        <div className="p-6 border-b border-gray-100/50 bg-white/40">
            <h2 className="text-2xl font-bold text-gray-800">Configure Paper</h2>
            <p className="text-gray-500 text-sm mt-1">Define the parameters for your AI-generated assessment.</p>
        </div>

        <form onSubmit={handleSubmit} className="p-6 md:p-8 space-y-10">

          {/* Header Configuration */}
          <div className="bg-white/50 p-6 rounded-xl border border-white/60 space-y-6 shadow-sm">
             <h3 className="text-sm font-bold text-gray-500 uppercase tracking-wide border-b border-gray-200/60 pb-2 mb-4">Header Branding & Typography</h3>

             {/* School Name */}
             <div>
                <label className="block text-sm font-bold text-gray-700 mb-2">School Name <span className="text-red-500">*</span></label>
                <input
                    ref={schoolNameRef}
                    type="text"
                    className={`w-full px-4 py-3 rounded-lg border bg-white/80 focus:ring-2 outline-none transition-all text-gray-900 placeholder:text-gray-400
                        ${schoolNameError ? 'border-red-500 focus:ring-red-200' : 'border-gray-200 focus:ring-[#8A2CB0] focus:border-[#8A2CB0]'}`}
                    placeholder="Enter the full name of the School / Institution"
                    value={schoolName}
                    onChange={handleSchoolNameChange}
                />
                {schoolNameError && <p className="text-red-600 text-sm font-bold mt-1.5">{schoolNameError}</p>}
             </div>

             {/* Logo Section */}
             <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div>
                    <label className="block text-sm font-bold text-gray-700 mb-2">Upload School Logo <span className="text-gray-400 font-normal">(Optional)</span></label>
                    <div className="relative border-2 border-dashed border-gray-300 rounded-xl p-6 bg-white/60 hover:bg-white/90 hover:border-[#8A2CB0] transition-all text-center cursor-pointer">
                        {!schoolLogo ? (
                            <>
                                <input 
                                    type="file" 
                                    id="logo-upload"
                                    accept="image/png, image/jpeg, image/jpg"
                                    onChange={handleLogoUpload}
                                    className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                                />
                                <div className="flex flex-col items-center justify-center text-gray-400 py-2">
                                    <span className="text-sm font-medium text-[#8A2CB0]">Click to upload logo</span>
                                    <span className="text-xs text-gray-400 mt-1">PNG, JPG (Max 2MB)</span>
                                </div>
                            </>
                        ) : (
                            <div className="flex items-center gap-4">
                                <div className="w-16 h-16 relative border rounded bg-white flex items-center justify-center overflow-hidden shadow-sm">
                                    <img src={schoolLogo} alt="Preview" className="w-full h-full object-contain" />
                                </div>
                                <div className="text-left flex-1">
                                    <p className="text-sm font-bold text-green-600">Logo Uploaded</p>
                                    <button 
                                        type="button" 
                                        onClick={handleRemoveLogo}
                                        className="text-xs text-red-500 hover:text-red-700 underline mt-1"
                                    >
                                        Remove
                                    </button>
                                </div>
                            </div>
                        )}
                    </div>
                    {logoError && <p className="text-red-600 text-xs font-bold mt-1.5">{logoError}</p>}
                </div>

                {/* Logo Placement */}
                <div>
                     <label className={`block text-sm font-bold mb-2 ${!schoolLogo ? 'text-gray-400' : 'text-gray-700'}`}>
                        Logo Placement
                     </label>
                     <div className="flex gap-3 mb-6">
                         {[
                             { id: 'left', label: 'Left' },
                             { id: 'center', label: 'Center' },
                             { id: 'right', label: 'Right' }
                         ].map((opt) => (
                             <label 
                                key={opt.id}
                                className={`flex-1 flex flex-col items-center justify-center py-3 rounded-lg border cursor-pointer transition-all text-sm font-semibold
                                    ${!schoolLogo ? 'opacity-50 pointer-events-none bg-gray-50 border-gray-100' : ''}
                                    ${logoPlacement === opt.id 
                                        ? 'bg-[#f3e8ff] border-[#8A2CB0] text-[#3C128D] shadow-sm' 
                                        : 'bg-white border-gray-200 text-gray-500 hover:bg-gray-50'
                                    }`}
                             >
                                 <input 
                                    type="radio" 
                                    name="logoPlacement" 
                                    value={opt.id}
                                    checked={logoPlacement === opt.id}
                                    onChange={(e) => setLogoPlacement(e.target.value as any)}
                                    className="sr-only"
                                    disabled={!schoolLogo}
                                 />
                                 {opt.label}
                             </label>
                         ))}
                     </div>
                </div>
             </div>

             <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                    <label className="block text-sm font-bold text-gray-700 mb-2">Heading Font</label>
                    <select
                        className="w-full px-4 py-2.5 rounded-lg border border-gray-200 bg-white focus:ring-2 focus:ring-[#8A2CB0] outline-none"
                        value={headingFont}
                        onChange={(e) => setHeadingFont(e.target.value)}
                    >
                        {FONT_OPTIONS.map((font) => (
                            <option key={font.value} value={font.value}>{font.label}</option>
                        ))}
                    </select>
                </div>
                <div>
                    <label className="block text-sm font-bold text-gray-700 mb-2">Body Font</label>
                    <select
                        className="w-full px-4 py-2.5 rounded-lg border border-gray-200 bg-white focus:ring-2 focus:ring-[#8A2CB0] outline-none"
                        value={bodyFont}
                        onChange={(e) => setBodyFont(e.target.value)}
                    >
                        {FONT_OPTIONS.map((font) => (
                            <option key={font.value} value={font.value}>{font.label}</option>
                        ))}
                    </select>
                </div>
             </div>
          </div>

          {/* General Info & Paper Specs */}
          <div className="space-y-6">
             <h3 className="text-sm font-bold text-gray-500 uppercase tracking-wide border-b border-gray-200/50 pb-2">Paper Specification</h3>

             <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className="block text-sm font-semibold text-gray-700 mb-2">Board / Curriculum</label>
                  <select
                    required
                    className="w-full px-4 py-2.5 rounded-lg border border-gray-200 bg-white focus:ring-2 focus:ring-[#8A2CB0] outline-none"
                    value={selectedBoard}
                    onChange={handleBoardChange}
                  >
                    {BOARDS.map((board) => (
                      <option key={board} value={board}>{board}</option>
                    ))}
                  </select>
                </div>

                <div>
                  <label className="block text-sm font-semibold text-gray-700 mb-2">Class</label>
                  <select
                    required
                    className="w-full px-4 py-2.5 rounded-lg border border-gray-200 bg-white focus:ring-2 focus:ring-[#8A2CB0] outline-none"
                    value={selectedClass}
                    onChange={handleClassChange}
                  >
                    <option value="" disabled>Select Class</option>
                    {GRADES.map((grade) => (
                      <option key={grade} value={grade}>{grade}</option>
                    ))}
                  </select>
                </div>

                <div className="md:col-span-2">
                  <label className="block text-sm font-semibold text-gray-700 mb-2">Subject</label>
                  <select
                    required
                    disabled={!selectedClass}
                    className="w-full px-4 py-2.5 rounded-lg border border-gray-200 bg-white focus:ring-2 focus:ring-[#8A2CB0] outline-none disabled:bg-gray-100 disabled:text-gray-400"
                    value={selectedSubject}
                    onChange={handleSubjectChange}
                  >
                    <option value="" disabled>
                        {!selectedClass ? 'Select Class first' : 'Select Subject'}
                    </option>
                    {availableSubjects.map((subj) => (
                      <option key={subj} value={subj}>
                         {subj}
                      </option>
                    ))}
                  </select>
                </div>

                {/* Chapter Selection Checklist */}
                {selectedSubject && availableChapters.length > 0 && (
                   <div className="md:col-span-2 bg-white/50 p-6 rounded-xl border border-white/60">
                      <div className="flex justify-between items-center mb-3">
                          <label className="block text-sm font-bold text-gray-700">
                             Chapter Selection <span className="text-red-500">*</span>
                          </label>
                          <label className="flex items-center gap-2 cursor-pointer select-none">
                              <input 
                                type="checkbox" 
                                checked={isAllSelected}
                                ref={input => {
                                    if (input) input.indeterminate = isIndeterminate;
                                }}
                                onChange={handleSelectAll}
                                className="w-4 h-4 text-[#8A2CB0] border-gray-300 rounded focus:ring-[#8A2CB0]"
                              />
                              <span className="text-sm font-semibold text-[#8A2CB0]">Select All</span>
                          </label>
                      </div>

                      <div className="max-h-64 overflow-y-auto pr-2 border border-gray-200 rounded-lg bg-white">
                          {availableChapters.map((chapter, index) => (
                              <label key={index} className="flex items-start gap-3 p-3 hover:bg-gray-50 border-b last:border-0 border-gray-100 cursor-pointer transition-colors">
                                  <input 
                                    type="checkbox"
                                    checked={selectedChapters.includes(chapter)}
                                    onChange={() => handleChapterToggle(chapter)}
                                    className="mt-1 w-4 h-4 text-[#8A2CB0] border-gray-300 rounded focus:ring-[#8A2CB0]"
                                  />
                                  <span className="text-sm text-gray-700">{chapter}</span>
                              </label>
                          ))}
                      </div>
                      {chapterError && (
                          <p className="text-red-600 text-sm font-bold mt-2 animate-fade-in">
                              {chapterError}
                          </p>
                      )}
                      <div className="mt-2 text-xs text-gray-500 text-right">
                          {selectedChapters.length} of {availableChapters.length} selected
                      </div>
                   </div>
                )}

                {selectedSubject && availableChapters.length === 0 && (
                     <div className="md:col-span-2 p-4 bg-orange-50 border border-orange-200 rounded-lg text-orange-700 text-sm">
                        No specific chapters found for this subject. The AI will generate based on general syllabus knowledge.
                     </div>
                )}

                <div>
                    <label className="block text-sm font-semibold text-gray-700 mb-2">Test Type</label>
                    <select
