             <button 
                onClick={() => setView('bank')} 
                className={`px-5 py-2 rounded-lg text-sm font-bold transition-all duration-300 ${view === 'bank' ? 'bg-white text-[#3C128D] shadow-md scale-100 ring-1 ring-[#8A2CB0]/20' : 'text-white hover:text-white/90 hover:bg-white/10'}`}
