                                            type="number"
                                            min="0"
                                            className={`w-16 text-center px-2 py-1 rounded border outline-none focus:ring-1 focus:border-[#8A2CB0]
                                                ${errors[spec.key] ? 'border-red-500 bg-red-50' : 'border-gray-200 bg-white'}`}
                                            value={counts[spec.key]}
                                            onChange={(e) => handleCountChange(spec.key, e.target.value)}
                                            onBlur={() => handleBlur(spec.key)}
                                        />
                                        {errors[spec.key] && <div className="text-[10px] text-red-500 mt-1">{errors[spec.key]}</div>}
                                    </td>
                                    <td className="px-4 py-3 text-right font-bold text-gray-700">
                                        {counts[spec.key] ? parseInt(counts[spec.key]) * spec.marks : 0}
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                        <tfoot className="bg-gray-50 border-t border-gray-200">
                            <tr>
                                <td colSpan={3} className="px-4 py-3 text-right font-bold text-gray-600">Total Marks</td>
                                <td className={`px-4 py-3 text-right font-bold ${currentCalculatedMarks === totalMarks ? 'text-green-600' : 'text-orange-600'}`}>
                                    {currentCalculatedMarks || 0} / {totalMarks}
                                </td>
                            </tr>
                        </tfoot>
                    </table>
                </div>
            )}
          </div>

          {/* Action Buttons */}
          <div className="flex gap-4 pt-4">
              <button
                type="button"
                onClick={onCancel}
                className="flex-1 py-3.5 border border-gray-300 rounded-xl font-bold text-gray-600 hover:bg-gray-50 transition-colors"
                disabled={isGenerating}
              >
                Cancel
              </button>

              <button
                type="submit"
                className="flex-1 btn-glass btn-glass-primary py-3.5 rounded-xl font-bold text-white shadow-lg flex items-center justify-center gap-2"
                disabled={isGenerating}
              >
                {isGenerating ? (
                    <>
                        <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                        </svg>
                        <span>Generating...</span>
                    </>
                ) : (
                    <span>Generate Paper ✨</span>
                )}
              </button>
          </div>

        </form>
      </div>
    </div>
  );
};

