import { GoogleGenAI, Type, Schema } from "@google/genai";
import { PaperConfig, GeneratedPaper } from "../types";
import { CBSE_EXAM_PATTERNS } from "../constants";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

// Define the response schema strictly to ensure easy parsing
const paperResponseSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    title: {
      type: Type.STRING,
      description: "The formal title of the examination paper (e.g., 'Grade 10 Physics - Mid Term').",
    },
    questionPaper: {
      type: Type.STRING,
      description: "The full question paper text. IMPORTANT: Output CLEAN PLAIN TEXT ONLY. Do NOT use Markdown symbols (no #, no *, no **). Use actual blank lines for spacing. Format Sections clearly (e.g., SECTION A: ...).",
    },
    answerKey: {
      type: Type.STRING,
      description: "The comprehensive answer key and marking scheme in clean plain text format.",
    },
  },
  required: ["title", "questionPaper", "answerKey"],
};

export const generateQuestionPaper = async (config: PaperConfig): Promise<GeneratedPaper> => {
  if (!apiKey) {
    throw new Error("API Key is missing. Please check your environment configuration.");
  }

  let structurePrompt = '';

  if (config.testType === 'CBSE Board Exam') {
    // 1. Handle CBSE Official Pattern
    // Remove chapter details from subject string to find the pure subject key
    // Format is like "Mathematics (Standard) (Chapters: Real Numbers, ...)"
    const pureSubject = config.subject.split(' (Chapters:')[0].trim();
    const pattern = CBSE_EXAM_PATTERNS[pureSubject];

    if (pattern) {
        structurePrompt = `
        STRICTLY FOLLOW THIS OFFICIAL CBSE EXAM PATTERN for Class 10:
        ${JSON.stringify(pattern, null, 2)}

        INSTRUCTIONS FOR PATTERN:
        - Maintain the exact number of sections, questions, and marks per question as defined in the JSON above.
        - Ensure internal choices are provided exactly where specified in the 'internal_choice' fields.
        - Do NOT deviate from this structure.
        `;
    } else {
        // Fallback if pattern not found (shouldn't happen with correct constants)
        structurePrompt = `Generate a standard CBSE Class 10 Board Exam paper for ${config.subject}.`;
    }

  } else if (config.customSections && config.customSections.length > 0) {
    // 2. Handle Custom Builder Sections
    structurePrompt = `
    Generate the paper STRICTLY according to these defined sections:

    ${config.customSections.map((sec, idx) => `
    SECTION ${idx + 1}: ${sec.title}
    - Question Type: ${sec.type}
    - Number of Questions: ${sec.count}
    - Marks per Question: ${sec.marksPerQuestion}
    ${sec.instructions ? `- Instructions: ${sec.instructions}` : ''}
    `).join('\n')}

    Ensure the total marks sum up to ${config.totalMarks}.
    `;
  } else {
    // 3. Handle Standard/Legacy Distribution
    structurePrompt = `
    Structure the paper with the following question distribution:
    - Multiple Choice Questions (MCQ): ${config.counts.mcq}
    - Assertion-Reasoning (A/R): ${config.counts.ar} (Format: A is true, R is false, etc.)
    - Very Short Answer (VSAQ): ${config.counts.vsaq}
    - Short Answer (SAQ): ${config.counts.saq}
    - Long Answer (LAQ): ${config.counts.laq}
    - Case Study/Source-based: ${config.counts.caseStudy} (Provide a paragraph/source followed by sub-questions)
    `;
  }

  const prompt = `
    Act as a senior academic curriculum developer for ${config.board} (India). 
    Generate a high-quality question paper based on the following specifications:

    Exam Type: ${config.testType}
    Board/Curriculum: ${config.board}
    Subject & Topics: ${config.subject}
    Grade/Level: ${config.grade}
    Total Marks: ${config.totalMarks}
    Difficulty: ${config.difficulty}

    ${structurePrompt}

    Pedagogical Guidelines:
    1. Apply Bloom's Taxonomy. Ensure a mix of knowledge, understanding, application, and analysis based on the difficulty level '${config.difficulty}'.
    2. Questions must be strictly aligned with the syllabus of ${config.board} for ${config.grade}.
    3. Questions should be clear, unambiguous, and grade-appropriate.
    4. Group questions into logical sections matching the structure defined above.
    5. **SCOPE**: Strictly restrict questions to the specific chapters/topics listed in the 'Subject & Topics' field. Do not ask questions from outside these topics.

    FORMATTING RULES (CRITICAL):
    1. **NO MARKDOWN BOLDING**: Do NOT use hashtags (#) for headers or asterisks (**) for bolding.
    2. **MATH NOTATION**: For ANY mathematical expression (algebra, fractions, roots, exponents), YOU MUST use LaTeX formatting enclosed in '$' symbols.
       - Example: $x^2 + 5x + 6$
       - Example: $\\frac{1}{2}$
       - Example: $\\sqrt{x}$
       - Example: $\\pi r^2$
       - Do NOT use plain text caret (^) or slash (/) for complex math.
       - For Currency: Use "Rs." or "INR", NEVER use '$' for money to avoid conflict.
    3. **SPACING**: Leave exactly ONE blank line before and after every Section Heading. Leave ONE blank line between questions.
    4. **NUMBERING**: Number questions as "1.", "2.", "3.". 
    5. **MCQ FORMATTING (MANDATORY)**: 
       - For every Multiple Choice Question, you MUST provide 4 options.
       - Place each option on a NEW LINE.
       - Label them exactly as "A)", "B)", "C)", "D)".
       - Example:
         1. What is the capital of India?
         A) Mumbai
         B) New Delhi
         C) Kolkata
         D) Chennai
       - NEVER put options on the same line.
    6. **SECTION HEADERS**: Type section headers in UPPERCASE (e.g., "SECTION A: ...").
    7. **CLEAN TEXT**: Do not use escape sequences like \\n in the visible output, use actual line breaks in the string.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: paperResponseSchema,
        temperature: 0.4, // Lower temperature for more structured/academic output
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response received from AI.");

    const data = JSON.parse(text);

    return {
      id: crypto.randomUUID(),
      timestamp: Date.now(),
      config,
      title: data.title,
      content: data.questionPaper,
      answerKey: data.answerKey,
    };
  } catch (error) {
    console.error("Error generating paper:", error);
    throw error;
  }
};

export const generateQuestionBankUpdate = async (subject: string, grade: string, board: string = 'CBSE / NCERT'): Promise<string> => {
  if (!apiKey) {
    throw new Error("API Key is missing.");
  }

  const prompt = `
    Act as a Subject Matter Expert for ${board}. 

    TASK: Generate a fresh set of "Important Questions" for the Subject: "${subject}" and Grade: "${grade}".

    CONTEXT:
    - Syllabus: Strictly adhere to the ${board} syllabus for this grade.
    - Focus: Identify key topics and frequently asked questions in examinations.

    CONTENT REQUIREMENTS:
    - Provide 5 High-Probability MCQs with answers.
    - Provide 3 Important Short Answer Questions (Concept-based).
    - Provide 2 Critical Long Answer Questions (Application/Analysis based).
    - Provide 1 Case-Study/Competency-based Question.

    FORMATTING:
    - Output CLEAN PLAIN TEXT ONLY. 
    - NO Markdown symbols (no #, no *).
    - Use "SECTION:" to denote categories.
    - Number questions clearly.
    - Put answers at the end of the document.
    - **MATH**: Use LaTeX enclosed in '$' for all math formulas (e.g., $x^2$).
    - **MCQ**: Options A), B), C), D) must be on separate lines.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        temperature: 0.5,
      },
    });

    return response.text || "Failed to generate questions.";
  } catch (error) {
    console.error("Error updating question bank:", error);
    throw error;
  }
};

import React, { useState, useRef } from 'react';
import { GeneratedPaper } from '../types';
import MarkdownRenderer from './MarkdownRenderer';
import { FONT_OPTIONS } from '../constants';

interface PaperPreviewProps {
  paper: GeneratedPaper;
  onBack: () => void;
}

const PaperPreview: React.FC<PaperPreviewProps> = ({ paper, onBack }) => {
  const [showAnswerKey, setShowAnswerKey] = useState(false);
  const [downloadFormat, setDownloadFormat] = useState<'pdf' | 'word' | 'txt'>('pdf');
  const printRef = useRef<HTMLDivElement>(null);

  const { schoolName, schoolLogo, logoPlacement, headingFont, bodyFont, generalInstructions } = paper.config;

  // Defaults if not set (backwards compatibility for old records)
  const timeAllowed = paper.config.timeAllowed || '2 Hours';
  const effectiveHeadingFont = headingFont || FONT_OPTIONS[0].value;
  const effectiveBodyFont = bodyFont || FONT_OPTIONS[1].value;

  // --- Export Handlers ---

  const handleDownload = () => {
    switch (downloadFormat) {
      case 'txt':
        exportToText();
        break;
      case 'pdf':
        exportToPdf();
        break;
      case 'word':
        exportToWord();
        break;
    }
  };

  const exportToText = () => {
    // Generate instruction text for download file
    const instructionsText = generalInstructions 
        ? `\nGeneral Instructions:\n${generalInstructions}\n`
        : `\nGeneral Instructions:\n- All questions are compulsory.\n- The question paper has been divided into multiple sections.\n- Calculators are not permitted unless specified.\n`;

    const cleanTitleBlock = `
${paper.title}
Time Allowed: ${timeAllowed} | Total Marks: ${paper.config.totalMarks}
`;

    const fileContent = `
${paper.config.schoolName.toUpperCase()}
${cleanTitleBlock}
${instructionsText}
${paper.content}

========================================
ANSWER KEY
========================================

${paper.answerKey}

© All Rights Reserved. Made by Darshit, Sree Pendyala
    `;

    const blob = new Blob([fileContent], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${paper.title.replace(/\s+/g, '_')}_${showAnswerKey ? 'Key' : 'Paper'}.txt`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const exportToPdf = () => {
    if (!printRef.current) return;

    // We clone the element to modify it slightly for PDF if needed, 
    // but usually direct export is fine.
    const element = printRef.current;

    const opt = {
      margin: [0.5, 0.5, 0.5, 0.5], // top, left, bottom, right
      filename: `${paper.title.replace(/\s+/g, '_')}_${showAnswerKey ? 'AnswerKey' : 'QuestionPaper'}.pdf`,
      image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { scale: 2, useCORS: true },
      jsPDF: { unit: 'in', format: 'a4', orientation: 'portrait' }
    };

    // Use html2pdf from window
    (window as any).html2pdf().set(opt).from(element).save();
  };

  const exportToWord = () => {
    if (!printRef.current) return;

    // Construct a simple HTML document for Word with minimal CSS mapping for Tailwind classes
    const preHtml = `<html xmlns:o='urn:schemas-microsoft-com:office:office' 
xmlns:w='urn:schemas-microsoft-com:office:word' 
xmlns='http://www.w3.org/TR/REC-html40'>
<head><meta charset='utf-8'><title>${paper.title}</title>
<style>
body { font-family: sans-serif; line-height: 1.5; color: #000; }
.text-center { text-align: center; }
.text-right { text-align: right; }
.font-bold { font-weight: bold; }
.uppercase { text-transform: uppercase; }
.text-4xl { font-size: 24pt; }
.text-2xl { font-size: 18pt; }
.text-lg { font-size: 14pt; }
.text-sm { font-size: 10pt; }
.mb-2 { margin-bottom: 0.5em; }
.mb-8 { margin-bottom: 2em; }
.mt-8 { margin-top: 2em; }
.p-8 { padding: 2em; }
.border-b-2 { border-bottom: 2px solid #000; }
.flex { display: flex; } /* Note: Word support for Flex is limited, table fallback might be better but simple layout works */
img { max-width: 150px; height: auto; }
</style>
</head><body>`;
    const postHtml = "</body></html>";

    // Get the inner HTML of the paper container
    const html = preHtml + printRef.current.innerHTML + postHtml;

    const blob = new Blob(['\ufeff', html], {
        type: 'application/msword'
    });

    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    // Note: saving as .doc is more reliable for HTML-based Word docs than .docx to avoid XML warnings
    a.download = `${paper.title.replace(/\s+/g, '_')}_${showAnswerKey ? 'AnswerKey' : 'QuestionPaper'}.doc`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };


  // Logic to determine layout class based on placement
  let headerLayoutClass = "flex flex-row items-center justify-center gap-6"; // Default Left
  let textAlignClass = "text-center"; // Default text align

  if (logoPlacement === 'center') {
      headerLayoutClass = "flex flex-col items-center justify-center gap-4";
  } else if (logoPlacement === 'right') {
      headerLayoutClass = "flex flex-row-reverse items-center justify-center gap-6";
  }

  return (
    <div className="max-w-5xl mx-auto p-4 sm:p-8 animate-fade-in pb-20">

      {/* Top Controls */}
      <div className="flex flex-col md:flex-row justify-between items-center mb-8 gap-4 sticky top-0 bg-white/90 backdrop-blur-sm p-4 rounded-xl shadow-sm z-10 border border-gray-100">
        <button 
          onClick={onBack}
          className="text-gray-600 hover:text-gray-900 flex items-center gap-2 font-medium transition-colors"
        >
          ← Back to Dashboard
        </button>

        <div className="flex flex-wrap gap-3 items-center justify-end">
          <button 
            onClick={() => setShowAnswerKey(!showAnswerKey)}
            className="btn-glass btn-glass-secondary px-4 py-2 rounded-lg text-sm"
          >
            {showAnswerKey ? 'Show Question Paper' : 'Show Answer Key'}
          </button>

          <div className="flex items-center gap-2 bg-indigo-50 p-1 rounded-lg border border-indigo-100">
              <select 
                value={downloadFormat}
                onChange={(e) => setDownloadFormat(e.target.value as any)}
                className="bg-white border-0 text-gray-800 text-sm rounded-md focus:ring-2 focus:ring-indigo-500 py-1.5 pl-3 pr-8 shadow-sm cursor-pointer hover:bg-gray-50"
              >
                <option value="pdf">PDF (.pdf)</option>
                <option value="word">Word (.doc)</option>
                <option value="txt">Text (.txt)</option>
              </select>
              <button 
                onClick={handleDownload}
                className="btn-glass btn-glass-primary px-4 py-1.5 rounded-md text-sm flex items-center gap-2"
              >
                Download
              </button>
          </div>
        </div>
      </div>

      {/* Paper View Container - This is what gets printed/exported */}
      <div 
        ref={printRef}
        className="bg-white shadow-xl shadow-gray-200/50 rounded-lg min-h-[800px] border border-gray-200 flex flex-col"
        /* REMOVED overflow-hidden to prevent cutting off content in PDF */
      >
        {/* Header Section representing a real paper header */}
        <div className="bg-white p-8 sm:p-12 border-b-2 border-gray-800">

            {/* Logo + School Name Container */}
            <div className={headerLayoutClass}>
                {schoolLogo && (
                    <div className="flex-shrink-0">
                        <img 
                            src={schoolLogo} 
                            alt="School Logo" 
                            className="h-20 w-auto object-contain max-w-[150px]" 
                        />
                    </div>
                )}

                <div className={textAlignClass}>
                     {schoolName && (
                        <h2 style={{ fontFamily: effectiveHeadingFont }} className="text-4xl font-bold text-gray-900 uppercase tracking-widest leading-tight">
                            {schoolName}
                        </h2>
                    )}
                </div>
            </div>

            {/* Exam Details - Clean Format */}
            <div className="text-center mt-8">
                <h1 style={{ fontFamily: effectiveHeadingFont }} className="text-2xl font-bold text-gray-800 mb-2">
                    {paper.title}
                </h1>

                {/* Time | Marks Line */}
                <p style={{ fontFamily: effectiveBodyFont }} className="text-lg text-gray-800 font-medium mt-1">
                    Time Allowed: {timeAllowed} &nbsp;|&nbsp; Total Marks: {paper.config.totalMarks}
                </p>
            </div>
        </div>

        <div className="p-8 sm:p-16 flex-grow">
            {showAnswerKey ? (
                <div className="animate-fade-in">
                    <div className="bg-yellow-50 border-l-4 border-yellow-400 p-4 mb-8">
                        <h2 className="text-yellow-800 font-bold uppercase tracking-wide text-sm">Confidential: Marking Scheme & Answer Key</h2>
                    </div>
                    <MarkdownRenderer 
                        content={paper.answerKey} 
                        headingFont={effectiveHeadingFont} 
                        bodyFont={effectiveBodyFont} 
                    />
                </div>
            ) : (
                <div className="animate-fade-in">
                    <div className="text-sm text-gray-800 mb-8 p-4 bg-gray-50 rounded border border-gray-200">
                        <strong className="block mb-2 text-gray-900 uppercase tracking-wide text-xs">General Instructions:</strong>
                        {generalInstructions ? (
                            <div style={{ fontFamily: effectiveBodyFont, whiteSpace: 'pre-wrap' }} className="text-gray-800 leading-relaxed">
                                {generalInstructions}
                            </div>
                        ) : (
                            <ul className="list-disc ml-5 space-y-1" style={{ fontFamily: effectiveBodyFont }}>
                                <li>All questions are compulsory.</li>
                                <li>The question paper has been divided into multiple sections based on the format requested.</li>
                                <li>Calculators are not permitted unless specified.</li>
                            </ul>
                        )}
                    </div>
                    <MarkdownRenderer 
                        content={paper.content} 
                        headingFont={effectiveHeadingFont} 
                        bodyFont={effectiveBodyFont} 
                    />
                </div>
            )}
        </div>

        {/* Copyright Footer */}
        <div className="mt-auto py-8 text-center border-t border-gray-100 mx-8 sm:mx-16">
            <p className="text-gray-400 text-[10px] font-medium uppercase tracking-widest">
                © All Rights Reserved. Made by Darshit, Sree Pendyala
            </p>
        </div>
      </div>
    </div>
  );
};

