import React from 'react';
import katex from 'katex';

interface MarkdownRendererProps {
  content: string;
  className?: string;
  headingFont?: string;
  bodyFont?: string;
}

// Helper to parse text and render Math using KaTeX
const renderTextWithMath = (text: string) => {
  // Regex looks for substrings enclosed in $, e.g., $x^2$
  // The capturing group `(\$[^\$]+\$)` keeps the delimiters in the split result so we can identify them.
  const parts = text.split(/(\$[^\$]+\$)/g);

  return parts.map((part, index) => {
    if (part.startsWith('$') && part.endsWith('$') && part.length > 2) {
      // Strip delimiters
      const math = part.slice(1, -1);
      try {
        const html = katex.renderToString(math, {
          throwOnError: false,
          output: 'html', // Generate HTML output
          displayMode: false // Inline math
        });
        // Render math as HTML
        return <span key={index} dangerouslySetInnerHTML={{ __html: html }} />;
      } catch (e) {
        // Fallback to raw text if parsing fails
        return <span key={index} className="text-red-500">{part}</span>;
      }
    }
    // Return regular text
    return <span key={index}>{part}</span>;
  });
};

// Renaming the component logic to "TextRenderer" conceptually, but keeping the name to match imports.
// This component now strictly handles Clean Plain Text output with Math support.
const MarkdownRenderer: React.FC<MarkdownRendererProps> = ({ 
    content, 
    className,
    headingFont = 'inherit',
    bodyFont = 'inherit'
}) => {
  // Normalize line endings and split
  const lines = content.replace(/\r\n/g, '\n').split('\n');

  return (
    <div className={`space-y-1 ${className}`}>
      {lines.map((line, index) => {
        const trimmed = line.trim();

        // Empty lines - Preserve explicit spacing
        if (trimmed === '') {
          return <div key={index} className="h-4"></div>; // Explicit height for blank lines
        }

        // HEURISTIC: Section Headers
        // If a line starts with "SECTION" or "PART", or is short and all uppercase (likely a title), treat as Header
        // IMPORTANT: Explicitly EXCLUDE MCQ options like "A)", "B)", "(a)", etc. from being treated as headers
        const isMcqOption = /^[A-Ea-e][\)\.]\s+/.test(trimmed) || /^\([A-Ea-e]\)\s+/.test(trimmed);

        const isSectionHeader = 
            !isMcqOption && (
                trimmed.match(/^(SECTION|PART)\s+[A-Z0-9]+/i) || 
                (trimmed === trimmed.toUpperCase() && trimmed.length < 50 && trimmed.length > 3 && !trimmed.match(/^\d+\./))
            );

        // CLEANUP: Strip unexpected markdown artifacts if the AI slips up
        const cleanLine = line.replace(/\*\*/g, '').replace(/###/g, '').replace(/##/g, '');

        if (isSectionHeader) {
          return (
            <h3 key={index} style={{ fontFamily: headingFont }} className="text-lg font-bold mt-6 mb-3 uppercase tracking-wide text-gray-900">
                {renderTextWithMath(cleanLine)}
            </h3>
          );
        }

        // Horizontal Rules (Manual text dividers)
        if (trimmed.match(/^(-{3,}|={3,}|_{3,})$/)) {
            return <hr key={index} className="my-6 border-gray-300" />;
        }

        // Normal Text (Questions, Options, Instructions)
        // Use pre-wrap to preserve spaces (indentation for options etc)
        return (
          <p key={index} style={{ fontFamily: bodyFont }} className="whitespace-pre-wrap leading-relaxed text-gray-800 text-base">
            {renderTextWithMath(cleanLine)}
          </p>
        );
      })}
    </div>
  );
};

export default MarkdownRenderer;

