  } catch (error) {
    console.error("Error updating question bank:", error);
    throw error;
  }
};

import React from 'react';

interface MarkdownRendererProps {
  content: string;
  className?: string;
  headingFont?: string;
  bodyFont?: string;
}

// Helper to parse text and render Math / Custom Fractions
const renderTextWithMath = (text: string) => {
  // Regex looks for:
  // 1. Fractions: [[num|den]]
  // 2. Math/LaTeX markers: $...$ (Legacy support, though explicitly avoided now)

  // We split by fraction syntax first
  const parts = text.split(/(\[\[.*?\|.*?\]\])/g);

  return parts.map((part, index) => {
    // Handle Custom Vertical Fraction: [[a|b]]
    const fractionMatch = part.match(/^\[\[(.*?)\|(.*?)\]\]$/);
    if (fractionMatch) {
      const [, numerator, denominator] = fractionMatch;
      return (
        <span key={index} className="inline-flex flex-col items-center align-middle mx-1.5 align-middle" style={{ verticalAlign: 'middle' }}>
          <span className="border-b border-black leading-none px-1 text-sm font-medium pb-[1px]">{numerator}</span>
          <span className="leading-none px-1 text-sm font-medium pt-[1px]">{denominator}</span>
        </span>
      );
    }

    // Return regular text
    return <span key={index}>{part}</span>;
  });
};

const MarkdownRenderer: React.FC<MarkdownRendererProps> = ({ 
    content, 
    className,
    headingFont = 'inherit',
    bodyFont = 'inherit'
}) => {
  // Normalize line endings and split
  const lines = content.replace(/\r\n/g, '\n').split('\n');

  return (
    <div className={`space-y-1 ${className}`}>
      {lines.map((line, index) => {
        const trimmed = line.trim();

        // Empty lines
        if (trimmed === '') {
          return <div key={index} className="h-4"></div>;
        }

        // HEURISTIC: Section Headers
        const isMcqOption = /^[A-Ea-e][\)\.]\s+/.test(trimmed) || /^\([A-Ea-e]\)\s+/.test(trimmed);
        const isSectionHeader = 
            !isMcqOption && (
                trimmed.match(/^(SECTION|PART)\s+[A-Z0-9]+/i) || 
                (trimmed === trimmed.toUpperCase() && trimmed.length < 50 && trimmed.length > 3 && !trimmed.match(/^\d+\./))
            );

        // CLEANUP: Strip unexpected artifacts
        const cleanLine = line.replace(/\*\*/g, '').replace(/###/g, '').replace(/##/g, '');

        if (isSectionHeader) {
          return (
            <h3 key={index} style={{ fontFamily: headingFont }} className="text-lg font-bold mt-6 mb-3 uppercase tracking-wide text-gray-900">
                {renderTextWithMath(cleanLine)}
            </h3>
          );
        }

        // Horizontal Rules
        if (trimmed.match(/^(-{3,}|={3,}|_{3,})$/)) {
            return <hr key={index} className="my-6 border-gray-300" />;
        }

        // Normal Text (Questions, Options)
        return (
          <p key={index} style={{ fontFamily: bodyFont }} className="whitespace-pre-wrap leading-relaxed text-gray-800 text-base">
            {renderTextWithMath(cleanLine)}
          </p>
        );
      })}
    </div>
  );
};

export default MarkdownRenderer;

import React, { useState, useRef } from 'react';
import { GeneratedPaper } from '../types';
import MarkdownRenderer from './MarkdownRenderer';
import { FONT_OPTIONS } from '../constants';

interface PaperPreviewProps {
  paper: GeneratedPaper;
  onBack: () => void;
}

const PaperPreview: React.FC<PaperPreviewProps> = ({ paper, onBack }) => {
  const [showAnswerKey, setShowAnswerKey] = useState(false);
  const [downloadFormat, setDownloadFormat] = useState<'pdf' | 'word' | 'txt'>('pdf');
  const printRef = useRef<HTMLDivElement>(null);

  const { schoolName, schoolLogo, logoPlacement, headingFont, bodyFont, generalInstructions } = paper.config;

  const timeAllowed = paper.config.timeAllowed || '2 Hours';
  const effectiveHeadingFont = headingFont || FONT_OPTIONS[0].value;
  const effectiveBodyFont = bodyFont || FONT_OPTIONS[1].value;

  // --- Helper: Ensure Math is Cleaned & Ready for Token Processing ---
  const preProcessMath = (text: string): string => {
    let content = text;
    // 1. Triangle Fix
    content = content.replace(/\\Delta/g, 'Δ');
    content = content.replace(/\bDelta\s+([A-Z])/g, 'Δ$1');
    content = content.replace(/\btriangle\s+([A-Z])/g, 'Δ$1');
    // 2. Multiplication Fix
    content = content.replace(/(\d)\*(\d)/g, '$1×$2');
    content = content.replace(/\s\*\s/g, ' × ');
    // 3. Superscripts
    const superscripts: Record<string, string> = {
      '0': '⁰', '1': '¹', '2': '²', '3': '³', '4': '⁴',
      '5': '⁵', '6': '⁶', '7': '⁷', '8': '⁸', '9': '⁹',
      'n': 'ⁿ', 'x': 'ˣ', '+': '⁺', '-': '⁻'
    };
    content = content.replace(/\^([0-9nx])/g, (_, match) => superscripts[match] || match);
    return content;
  };

  // --- Text Export Processor (Fraction -> Inline Division) ---
  const processForTextExport = (text: string): string => {
    let content = preProcessMath(text);
    // Convert [[a|b]] to (a ÷ b) for plain text readability
    content = content.replace(/\[\[(.*?)\|(.*?)\]\]/g, '($1 ÷ $2)');
    return content;
  };

  // --- Word Export Processor (Fraction -> OMML) ---
  const processForWordExport = (text: string): string => {
    let content = preProcessMath(text);
    // Use Regex to handle text, but leave tokens intact for the HTML generation phase?
    // Actually, we need to return HTML string where tokens are replaced by OMML tags.
    // NOTE: This function returns "Safe Text" that might still contain tokens if we handle them in generation,
    // BUT here we want to replace them directly with OMML xml strings if we are building the word doc.
    // However, inserting XML tags into a text string that will be placed in HTML is tricky.
    // Strategy: We will do replacement during `generateWordContent`.
    return content; 
  };

  // --- Generate Word HTML Content with OMML ---
  const generateWordContent = (rawContent: string) => {
      // Pre-process basic math symbols
      const processedRaw = preProcessMath(rawContent);

      const lines = processedRaw.replace(/\r\n/g, '\n').split('\n');
      let html = '';

      lines.forEach(line => {
          const trimmed = line.trim();
          if (!trimmed) {
              html += '<p>&nbsp;</p>';
              return;
          }

          // Header Detection
          const isMcqOption = /^[A-Ea-e][\)\.]\s+/.test(trimmed) || /^\([A-Ea-e]\)\s+/.test(trimmed);
          const isSectionHeader = !isMcqOption && (
              trimmed.match(/^(SECTION|PART)\s+[A-Z0-9]+/i) || 
              (trimmed === trimmed.toUpperCase() && trimmed.length < 50 && trimmed.length > 3 && !trimmed.match(/^\d+\./))
          );

          // --- OMML CONVERSION ---
          // Replace [[a|b]] with OMML XML
          // We use <m:oMathPara> or <m:oMath> (inline)
          let lineHtml = trimmed.replace(/\[\[(.*?)\|(.*?)\]\]/g, (match, num, den) => {
             return `<m:oMath>
                <m:f>
                    <m:num><m:r><m:t>${num}</m:t></m:r></m:num>
                    <m:den><m:r><m:t>${den}</m:t></m:r></m:den>
                </m:f>
             </m:oMath>`;
          });

          // Check if line contains Math symbols for font application
          const hasMath = /[Δπθ×÷√²³⁰¹⁴-⁹≤≥≠∞≈±]/.test(lineHtml) || lineHtml.includes('<m:oMath>');
          const fontFamily = hasMath 
            ? "'Cambria Math', 'Times New Roman', serif" 
            : "'Times New Roman', serif";

          const style = `font-family: ${fontFamily}; font-size: 11pt; line-height: 1.5; color: #000;`;

          if (isSectionHeader) {
              // Strip OMML from headers if any (unlikely but safe)
              const cleanHeader = trimmed.replace(/\[\[.*?\]\]/g, ''); 
              html += `<h3 style="font-size:14pt; font-weight:bold; text-transform:uppercase; margin-top:12pt; margin-bottom:6pt; font-family: 'Times New Roman', serif;">${cleanHeader}</h3>`;
          } else if (trimmed.match(/^(-{3,}|={3,}|_{3,})$/)) {
               html += `<hr style="border-top:1px solid #000;"/>`;
          } else {
               html += `<p style="${style}">${lineHtml}</p>`;
          }
      });
      return html;
  };

  const handleDownload = () => {
    switch (downloadFormat) {
      case 'txt': exportToText(); break;
      case 'pdf': exportToPdf(); break;
      case 'word': exportToWord(); break;
    }
  };

  const exportToText = () => {
    const instructionsText = generalInstructions ? `\nGeneral Instructions:\n${generalInstructions}\n` : `\nGeneral Instructions:\n- All questions are compulsory.\n`;
    const cleanTitleBlock = `\n${paper.title}\nTime Allowed: ${timeAllowed} | Total Marks: ${paper.config.totalMarks}\n`;

    // Process content to replace [[a|b]] with (a ÷ b)
    const processedContent = processForTextExport(paper.content);
    const processedKey = processForTextExport(paper.answerKey);

    const fileContent = `${paper.config.schoolName.toUpperCase()}${cleanTitleBlock}${instructionsText}\n${processedContent}\n\n========================================\nANSWER KEY\n========================================\n\n${processedKey}\n\n© All Rights Reserved. Made by GenPaper AI`;

    const blob = new Blob([fileContent], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${paper.title.replace(/\s+/g, '_')}_${showAnswerKey ? 'Key' : 'Paper'}.txt`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const exportToPdf = () => {
    if (!printRef.current) return;
    const opt = {
      margin: [0.5, 0.5, 0.5, 0.5],
      filename: `${paper.title.replace(/\s+/g, '_')}_${showAnswerKey ? 'AnswerKey' : 'QuestionPaper'}.pdf`,
      image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { scale: 2, useCORS: true },
      jsPDF: { unit: 'in', format: 'a4', orientation: 'portrait' }
    };
    (window as any).html2pdf().set(opt).from(printRef.current).save();
  };

  const exportToWord = () => {
    const targetContent = showAnswerKey ? paper.answerKey : paper.content;
    const bodyHtml = generateWordContent(targetContent);

    const instructionsHtml = generalInstructions 
