  return (
    <div className="max-w-5xl mx-auto p-4 sm:p-8 animate-fade-in pb-20">
      <div className="flex flex-col md:flex-row justify-between items-center mb-8 gap-4 sticky top-0 bg-white/90 backdrop-blur-sm p-4 rounded-xl shadow-sm z-10 border border-gray-100">
