import { GoogleGenAI, Type, Schema } from "@google/genai";
import { PaperConfig, GeneratedPaper } from "../types";
import { CBSE_EXAM_PATTERNS } from "../constants";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

// Define the response schema strictly to ensure easy parsing
const paperResponseSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    title: {
      type: Type.STRING,
      description: "The formal title of the examination paper (e.g., 'Grade 10 Physics - Mid Term').",
    },
    questionPaper: {
      type: Type.STRING,
      description: "The full question paper text. IMPORTANT: Output CLEAN PLAIN TEXT ONLY. Do NOT use Markdown symbols (no #, no *, no **). Use actual blank lines for spacing. Format Sections clearly (e.g., SECTION A: ...).",
    },
    answerKey: {
      type: Type.STRING,
      description: "The comprehensive answer key and marking scheme in clean plain text format.",
    },
  },
  required: ["title", "questionPaper", "answerKey"],
};

export const generateQuestionPaper = async (config: PaperConfig): Promise<GeneratedPaper> => {
  if (!apiKey) {
    throw new Error("API Key is missing. Please check your environment configuration.");
  }

  let structurePrompt = '';

  if (config.testType === 'CBSE Board Exam') {
    // 1. Handle CBSE Official Pattern
    const pureSubject = config.subject.split(' (Chapters:')[0].trim();
    const pattern = CBSE_EXAM_PATTERNS[pureSubject];

    if (pattern) {
        structurePrompt = `
        STRICTLY FOLLOW THIS OFFICIAL CBSE EXAM PATTERN for Class 10:
        ${JSON.stringify(pattern, null, 2)}

        INSTRUCTIONS FOR PATTERN:
        - Maintain the exact number of sections, questions, and marks per question as defined in the JSON above.
        - Ensure internal choices are provided exactly where specified in the 'internal_choice' fields.
        `;
    } else {
        structurePrompt = `Generate a standard CBSE Class 10 Board Exam paper for ${config.subject}.`;
    }

  } else if (config.customSections && config.customSections.length > 0) {
    // 2. Handle Custom Builder Sections
    structurePrompt = `
    Generate the paper STRICTLY according to these defined sections:
    ${config.customSections.map((sec, idx) => `
    SECTION ${idx + 1}: ${sec.title}
    - Question Type: ${sec.type}
    - Number of Questions: ${sec.count}
    - Marks per Question: ${sec.marksPerQuestion}
    ${sec.instructions ? `- Instructions: ${sec.instructions}` : ''}
    `).join('\n')}
    Ensure the total marks sum up to ${config.totalMarks}.
    `;
  } else {
    // 3. Handle Standard/Legacy Distribution
    structurePrompt = `
    Structure the paper with the following question distribution:
    - Multiple Choice Questions (MCQ): ${config.counts.mcq}
    - Assertion-Reasoning (A/R): ${config.counts.ar}
    - Very Short Answer (VSAQ): ${config.counts.vsaq}
    - Short Answer (SAQ): ${config.counts.saq}
    - Long Answer (LAQ): ${config.counts.laq}
    - Case Study/Source-based: ${config.counts.caseStudy}
    `;
  }

  const prompt = `
    Act as a senior academic curriculum developer for ${config.board} (India). 
    Generate a high-quality question paper.

    Exam Details:
    - Subject: ${config.subject}
    - Grade: ${config.grade}
    - Marks: ${config.totalMarks}
    - Difficulty: ${config.difficulty}

    ${structurePrompt}

    Pedagogical Guidelines:
    1. Apply Bloom's Taxonomy. Ensure a mix of knowledge, understanding, application, and analysis.
    2. Questions must be aligned with ${config.board} syllabus.

    FORMATTING RULES (CRITICAL - WORD EQUATION COMPATIBILITY):

    Rule #1: WORD EQUATION OBJECTS
    - ALL mathematical formulas, fractions, and equations MUST be wrapped inside <<EQ>> ... <</EQ>> tags.
    - Anything inside <<EQ>> will be converted to a Microsoft Word Equation Object.

    Rule #2: FRACTIONS
    - NEVER use slashes (/) or division signs (÷) for fractions.
    - ALWAYS use the syntax [[numerator|denominator]] inside the <<EQ>> block.
    - Example: To write 22/7, output: <<EQ>> [[22|7]] <</EQ>>
    - Example: To write 1/2, output: <<EQ>> [[1|2]] <</EQ>>
    - Example with text: <<EQ>> [[4|3]] × πr³ <</EQ>>

    Rule #3: SYMBOLS (Unicode)
    - Use strict Unicode symbols INSIDE the <<EQ>> block.
    - Triangles: Δ (e.g., <<EQ>> ΔABC <</EQ>>)
    - Angles: ∠ (e.g., <<EQ>> ∠A = 90° <</EQ>>)
    - Multiplication: × (e.g., <<EQ>> 2 × 3 <</EQ>>)
    - Pi: π
    - Theta: θ
    - Roots: √
    - Powers: ² ³ (e.g., <<EQ>> πr² <</EQ>>)

    Rule #4: NO MARKDOWN/LATEX
    - Do NOT use LaTeX commands like \\frac, \\Delta.
    - Do NOT use Markdown bold (**).
    - Keep <<EQ>> blocks on a SINGLE LINE.

    Rule #5: MCQ FORMATTING
    - Options A), B), C), D) must be on NEW LINES.
    - Example:
      1. What is the value of π?
      A) <<EQ>> [[22|7]] <</EQ>>
      B) <<EQ>> 3.14 <</EQ>>
      C) <<EQ>> [[10|3]] <</EQ>>
      D) None
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: paperResponseSchema,
        temperature: 0.4,
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response received from AI.");

    const data = JSON.parse(text);

    return {
      id: crypto.randomUUID(),
      timestamp: Date.now(),
      config,
      title: data.title,
      content: data.questionPaper,
      answerKey: data.answerKey,
    };
  } catch (error) {
    console.error("Error generating paper:", error);
    throw error;
  }
};

export const generateQuestionBankUpdate = async (subject: string, grade: string, board: string = 'CBSE / NCERT'): Promise<string> => {
  if (!apiKey) {
    throw new Error("API Key is missing.");
  }

  const prompt = `
    Act as a Subject Matter Expert for ${board}. 
    Generate "Important Questions" for Subject: "${subject}", Grade: "${grade}".

    Requirements:
    - 5 MCQs, 3 Short Answer, 2 Long Answer, 1 Case Study.

    FORMATTING - STRICT WORD EQUATIONS:
    - Wrap ALL math in <<EQ>> ... <</EQ>>.
    - Fractions: <<EQ>> [[numerator|denominator]] <</EQ>>.
    - Symbols: Δ, π, θ, ×, √ inside <<EQ>>.
    - No LaTeX.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        temperature: 0.5,
      },
    });

    return response.text || "Failed to generate questions.";
  } catch (error) {
    console.error("Error updating question bank:", error);
    throw error;
  }
};

import React, { useState, useRef } from 'react';
import { GeneratedPaper } from '../types';
import MarkdownRenderer from './MarkdownRenderer';
import { FONT_OPTIONS } from '../constants';

interface PaperPreviewProps {
  paper: GeneratedPaper;
  onBack: () => void;
}

const PaperPreview: React.FC<PaperPreviewProps> = ({ paper, onBack }) => {
  const [showAnswerKey, setShowAnswerKey] = useState(false);
  const [downloadFormat, setDownloadFormat] = useState<'pdf' | 'word' | 'txt'>('pdf');
  const printRef = useRef<HTMLDivElement>(null);

  const { schoolName, schoolLogo, logoPlacement, headingFont, bodyFont, generalInstructions } = paper.config;

  const timeAllowed = paper.config.timeAllowed || '2 Hours';
  const effectiveHeadingFont = headingFont || FONT_OPTIONS[0].value;
  const effectiveBodyFont = bodyFont || FONT_OPTIONS[1].value;

  // --- Helper: Basic cleanup before processing ---
  const preProcessMath = (text: string): string => {
    let content = text;
    // Basic fixes just in case AI missed something outside EQ
    content = content.replace(/\\Delta/g, 'Δ');
    content = content.replace(/\bDelta\s+([A-Z])/g, 'Δ$1');
    content = content.replace(/(\d)\*(\d)/g, '$1×$2');
    content = content.replace(/\s\*\s/g, ' × ');
    return content;
  };

  // --- Text Export Processor ---
  const processForTextExport = (text: string): string => {
    let content = preProcessMath(text);
    // Remove EQ tags
    content = content.replace(/<<EQ>>/g, '').replace(/<<\/EQ>>/g, '');
    // Convert [[a|b]] to (a ÷ b)
    content = content.replace(/\[\[(.*?)\|(.*?)\]\]/g, '($1 ÷ $2)');
    return content;
  };

  // --- Word Export Processor: OMML Generation ---
  const convertToOMML = (eqContent: string): string => {
    // 1. Split by Fraction Token [[...|...]]
    // Regex matches [[...|...]]
    const parts = eqContent.split(/(\[\[.*?\|.*?\]\])/g);

    const ommlParts = parts.map(part => {
      const fracMatch = part.match(/^\[\[(.*?)\|(.*?)\]\]$/);
      if (fracMatch) {
        // It's a fraction -> <m:f>
        const [, num, den] = fracMatch;
        return `<m:f>
                  <m:num><m:r><m:t>${num}</m:t></m:r></m:num>
                  <m:den><m:r><m:t>${den}</m:t></m:r></m:den>
                </m:f>`;
      } else if (part.trim() !== "") {
        // It's text/symbols -> <m:r><m:t>
        return `<m:r><m:t>${part}</m:t></m:r>`;
      }
      return "";
    });

    return `<m:oMath>${ommlParts.join('')}</m:oMath>`;
  };

  // --- Generate Word HTML Content with OMML ---
  const generateWordContent = (rawContent: string) => {
      // 1. Normalize line breaks inside EQ tags first (prevent splitting equation across lines)
      // Remove newlines strictly inside <<EQ>>...<</EQ>> blocks
      const cleanRaw = preProcessMath(rawContent).replace(/<<EQ>>([\s\S]*?)<<\/EQ>>/g, (match, inner) => {
          return `<<EQ>>${inner.replace(/\n/g, ' ')}<</EQ>>`;
      });

      const lines = cleanRaw.replace(/\r\n/g, '\n').split('\n');
      let html = '';

      lines.forEach(line => {
          const trimmed = line.trim();
          if (!trimmed) {
              html += '<p>&nbsp;</p>';
              return;
          }

          // Header Detection
          const isMcqOption = /^[A-Ea-e][\)\.]\s+/.test(trimmed) || /^\([A-Ea-e]\)\s+/.test(trimmed);
          const isSectionHeader = !isMcqOption && (
              trimmed.match(/^(SECTION|PART)\s+[A-Z0-9]+/i) || 
              (trimmed === trimmed.toUpperCase() && trimmed.length < 50 && trimmed.length > 3 && !trimmed.match(/^\d+\./))
          );

          // --- WORD EQUATION PROCESSING ---
          // Replace <<EQ>>...<</EQ>> with actual OMML XML
          let lineHtml = trimmed.replace(/<<EQ>>([\s\S]*?)<<\/EQ>>/g, (match, inner) => {
             return convertToOMML(inner);
          });

          // Check for math content to set font
          const hasMath = lineHtml.includes('<m:oMath>');
          const fontFamily = hasMath 
            ? "'Cambria Math', 'Times New Roman', serif" 
            : "'Times New Roman', serif";

          const style = `font-family: ${fontFamily}; font-size: 11pt; line-height: 1.5; color: #000;`;

          if (isSectionHeader) {
              // Headers shouldn't usually have equations, but if they do, strip them for safety or render text
              const cleanHeader = trimmed.replace(/<<EQ>>/g, '').replace(/<<\/EQ>>/g, '').replace(/\[\[(.*?)\|(.*?)\]\]/g, '$1/$2'); 
              html += `<h3 style="font-size:14pt; font-weight:bold; text-transform:uppercase; margin-top:12pt; margin-bottom:6pt; font-family: 'Times New Roman', serif;">${cleanHeader}</h3>`;
          } else if (trimmed.match(/^(-{3,}|={3,}|_{3,})$/)) {
               html += `<hr style="border-top:1px solid #000;"/>`;
          } else {
               html += `<p style="${style}">${lineHtml}</p>`;
          }
      });
      return html;
  };

  const handleDownload = () => {
    switch (downloadFormat) {
      case 'txt': exportToText(); break;
      case 'pdf': exportToPdf(); break;
      case 'word': exportToWord(); break;
    }
  };

  const exportToText = () => {
    const instructionsText = generalInstructions ? `\nGeneral Instructions:\n${generalInstructions}\n` : `\nGeneral Instructions:\n- All questions are compulsory.\n`;
    const cleanTitleBlock = `\n${paper.title}\nTime Allowed: ${timeAllowed} | Total Marks: ${paper.config.totalMarks}\n`;

    const processedContent = processForTextExport(paper.content);
    const processedKey = processForTextExport(paper.answerKey);

    const fileContent = `${paper.config.schoolName.toUpperCase()}${cleanTitleBlock}${instructionsText}\n${processedContent}\n\n========================================\nANSWER KEY\n========================================\n\n${processedKey}\n\n© All Rights Reserved. Made by GenPaper AI`;

    const blob = new Blob([fileContent], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${paper.title.replace(/\s+/g, '_')}_${showAnswerKey ? 'Key' : 'Paper'}.txt`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const exportToPdf = () => {
    if (!printRef.current) return;
    const opt = {
      margin: [0.5, 0.5, 0.5, 0.5],
      filename: `${paper.title.replace(/\s+/g, '_')}_${showAnswerKey ? 'AnswerKey' : 'QuestionPaper'}.pdf`,
      image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { scale: 2, useCORS: true },
      jsPDF: { unit: 'in', format: 'a4', orientation: 'portrait' }
    };
    (window as any).html2pdf().set(opt).from(printRef.current).save();
  };

  const exportToWord = () => {
    const targetContent = showAnswerKey ? paper.answerKey : paper.content;
    const bodyHtml = generateWordContent(targetContent);

    const instructionsHtml = generalInstructions 
        ? `<div style="margin-bottom:16pt; font-size:10pt;"><b>General Instructions:</b><br/>${generalInstructions.replace(/\n/g, '<br/>')}</div>`
        : `<div style="margin-bottom:16pt; font-size:10pt;"><b>General Instructions:</b><ul><li>All questions are compulsory.</li><li>Calculators are not permitted.</li></ul></div>`;

    const titleBlockHtml = `
      <div style="text-align:center; margin-bottom:20pt; border-bottom:2px solid #000; padding-bottom:12pt;">
          <h1 style="font-size:24pt; font-weight:bold; text-transform:uppercase; margin:0;">${schoolName || 'QUESTION PAPER'}</h1>
          <h2 style="font-size:18pt; margin:8pt 0 4pt 0;">${paper.title}</h2>
          <p style="font-size:12pt; margin:0;">Time Allowed: ${timeAllowed} &nbsp;|&nbsp; Total Marks: ${paper.config.totalMarks}</p>
      </div>
    `;

    // CRITICAL: Include xmlns:m for Office MathML
    const preHtml = `<html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns:m='http://schemas.openxmlformats.org/officeDocument/2006/math' xmlns='http://www.w3.org/TR/REC-html40'>
<head><meta charset='utf-8'><title>${paper.title}</title>
<style>
body { font-family: 'Times New Roman', serif; }
p, li, div { font-family: 'Times New Roman', serif; }
</style>
</head><body>`;

    const postHtml = "</body></html>";
    const fullHtml = preHtml + titleBlockHtml + instructionsHtml + bodyHtml + postHtml;

    const blob = new Blob(['\ufeff', fullHtml], { type: 'application/msword' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${paper.title.replace(/\s+/g, '_')}_${showAnswerKey ? 'AnswerKey' : 'QuestionPaper'}.doc`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  let headerLayoutClass = "flex flex-row items-center justify-center gap-6";
  let textAlignClass = "text-center";

  if (logoPlacement === 'center') {
      headerLayoutClass = "flex flex-col items-center justify-center gap-4";
  } else if (logoPlacement === 'right') {
      headerLayoutClass = "flex flex-row-reverse items-center justify-center gap-6";
  }

  return (
    <div className="max-w-5xl mx-auto p-4 sm:p-8 animate-fade-in pb-20">
      <div className="flex flex-col md:flex-row justify-between items-center mb-8 gap-4 sticky top-0 bg-white/90 backdrop-blur-sm p-4 rounded-xl shadow-sm z-10 border border-gray-100">
        <button onClick={onBack} className="text-gray-600 hover:text-gray-900 flex items-center gap-2 font-medium transition-colors">
          ← Back to Dashboard
        </button>
        <div className="flex flex-wrap gap-3 items-center justify-end">
          <button onClick={() => setShowAnswerKey(!showAnswerKey)} className="btn-glass btn-glass-secondary px-4 py-2 rounded-lg text-sm">
            {showAnswerKey ? 'Show Question Paper' : 'Show Answer Key'}
          </button>
          <div className="flex items-center gap-2 bg-indigo-50 p-1 rounded-lg border border-indigo-100">
              <select value={downloadFormat} onChange={(e) => setDownloadFormat(e.target.value as any)} className="bg-white border-0 text-gray-800 text-sm rounded-md focus:ring-2 focus:ring-indigo-500 py-1.5 pl-3 pr-8 shadow-sm cursor-pointer hover:bg-gray-50">
                <option value="pdf">PDF (.pdf)</option>
                <option value="word">Word (.doc)</option>
                <option value="txt">Text (.txt)</option>
              </select>
              <button onClick={handleDownload} className="btn-glass btn-glass-primary px-4 py-1.5 rounded-md text-sm flex items-center gap-2">
                Download
              </button>
          </div>
        </div>
      </div>

      <div ref={printRef} className="bg-white shadow-xl shadow-gray-200/50 rounded-lg min-h-[800px] border border-gray-200 flex flex-col">
        <div className="bg-white p-8 sm:p-12 border-b-2 border-gray-800">
            <div className={headerLayoutClass}>
                {schoolLogo && (
                    <div className="flex-shrink-0">
                        <img src={schoolLogo} alt="School Logo" className="h-20 w-auto object-contain max-w-[150px]" />
                    </div>
                )}
                <div className={textAlignClass}>
                     {schoolName && (
