import React, { useState, useRef, useMemo } from 'react';
import { GeneratedPaper, Question } from '../types';
import MarkdownRenderer from './MarkdownRenderer';
import { FONT_OPTIONS } from '../constants';
import QuestionCard from './QuestionCard';
import { regenerateSingleQuestion } from '../services/geminiService';

interface PaperPreviewProps {
  paper: GeneratedPaper;
  onBack: () => void;
}

const PaperPreview: React.FC<PaperPreviewProps> = ({ paper, onBack }) => {
  const [questions, setQuestions] = useState<Question[]>(paper.questions || []);
  const [showAnswerKey, setShowAnswerKey] = useState(false);
  const [viewMode, setViewMode] = useState<'edit' | 'preview'>('edit');
  const [downloadFormat, setDownloadFormat] = useState<'pdf' | 'word' | 'txt'>('pdf');
  const printRef = useRef<HTMLDivElement>(null);

  const { schoolName, schoolLogo, logoPlacement, headingFont, bodyFont, generalInstructions } = paper.config;
  const timeAllowed = paper.config.timeAllowed || '2 Hours';
  const effectiveHeadingFont = headingFont || FONT_OPTIONS[0].value;
  const effectiveBodyFont = bodyFont || FONT_OPTIONS[1].value;

  // --- Logic to Regenerate a single question ---
  const handleRegenerateQuestion = async (id: string, newDiff: number, instruction: string) => {
    const qIndex = questions.findIndex(q => q.question_id === id);
    if (qIndex === -1) return;

    try {
        const updatedData = await regenerateSingleQuestion(
            questions[qIndex], 
            newDiff, 
            instruction, 
            paper.config.subject
        );

        setQuestions(prev => {
            const newArr = [...prev];
            newArr[qIndex] = { 
                ...newArr[qIndex], 
                ...updatedData,
                difficulty: newDiff 
            };
            return newArr;
        });
    } catch (e) {
        alert("Failed to regenerate question. Please try again.");
    }
  };

  // --- Construct the Final Paper Text dynamically from the Question State ---
  const constructedPaperContent = useMemo(() => {
    let content = "";
    let currentSection = "";

    questions.forEach((q, index) => {
        // Section Header
        if (q.section !== currentSection) {
            content += `\n\n**${q.section}**\n\n`;
            currentSection = q.section;
        }

        // Question Text
        content += `${index + 1}. ${q.question_text}  ([${q.marks} Mark${q.marks > 1 ? 's' : ''}])\n`;

        // Options
        if (q.options && q.options.length > 0) {
            q.options.forEach((opt, i) => {
                content += `${String.fromCharCode(65 + i)}) ${opt}\n`;
            });
            content += "\n";
        } else {
            content += "\n";
        }
    });

    return content;
  }, [questions]);

  // --- Standard Export Helpers (same as before but using constructed content) ---

  const preProcessMath = (text: string): string => {
    let content = text;
    content = content.replace(/\\Delta/g, 'Δ');
    content = content.replace(/\bDelta\s+([A-Z])/g, 'Δ$1');
    content = content.replace(/(\d)\*(\d)/g, '$1×$2');
    content = content.replace(/\s\*\s/g, ' × ');
    return content;
  };

  const processForTextExport = (text: string): string => {
    let content = preProcessMath(text);
    content = content.replace(/\[\[MATH\]\]/g, '').replace(/\[\[\/MATH\]\]/g, '');
    content = content.replace(/\[\[(.*?)\|(.*?)\]\]/g, '($1 ÷ $2)');
    return content;
  };

  const convertToOMML = (eqContent: string): string => {
    const parts = eqContent.split(/(\[\[.*?\|.*?\]\])/g);
    const ommlParts = parts.map(part => {
      const fracMatch = part.match(/^\[\[(.*?)\|(.*?)\]\]$/);
      if (fracMatch) {
        const [, num, den] = fracMatch;
        return `<m:f><m:num><m:r><m:t>${num}</m:t></m:r></m:num><m:den><m:r><m:t>${den}</m:t></m:r></m:den></m:f>`;
      } else if (part.trim() !== "") {
        return `<m:r><m:t xml:space="preserve">${part}</m:t></m:r>`;
      }
      return "";
    });
    return `<m:oMath>${ommlParts.join('')}</m:oMath>`;
  };

  const generateWordContent = (rawContent: string) => {
      const cleanRaw = preProcessMath(rawContent).replace(/\[\[MATH\]\]([\s\S]*?)\[\[\/MATH\]\]/g, (match, inner) => {
          return `[[MATH]]${inner.replace(/\n/g, ' ')}[[/MATH]]`;
      });
      const lines = cleanRaw.replace(/\r\n/g, '\n').split('\n');
      let html = '';
      lines.forEach(line => {
          const trimmed = line.trim();
          if (!trimmed) { html += '<p>&nbsp;</p>'; return; }

          const isMcqOption = /^[A-Ea-e][\)\.]\s+/.test(trimmed) || /^\([A-Ea-e]\)\s+/.test(trimmed);
          const isSectionHeader = !isMcqOption && (trimmed.match(/^\*\*.*\*\*$/) || trimmed.match(/^(SECTION|PART)\s+[A-Z0-9]+/i));

          let lineHtml = trimmed.replace(/\[\[MATH\]\]([\s\S]*?)\[\[\/MATH\]\]/g, (match, inner) => convertToOMML(inner));
          // Remove markdown bold from headers for word
          lineHtml = lineHtml.replace(/\*\*/g, '');

          const hasMath = lineHtml.includes('<m:oMath>');
          const fontFamily = hasMath ? "'Cambria Math', 'Times New Roman', serif" : "'Times New Roman', serif";
          const style = `font-family: ${fontFamily}; font-size: 11pt; line-height: 1.5; color: #000;`;

          if (isSectionHeader) {
               html += `<h3 style="font-size:14pt; font-weight:bold; text-transform:uppercase; margin-top:12pt; margin-bottom:6pt; font-family: 'Times New Roman', serif;">${lineHtml}</h3>`;
          } else {
               html += `<p style="${style}">${lineHtml}</p>`;
          }
      });
      return html;
  };

  const handleDownload = () => {
    switch (downloadFormat) {
      case 'txt': exportToText(); break;
      case 'pdf': exportToPdf(); break;
      case 'word': exportToWord(); break;
    }
  };

  const exportToText = () => {
    const instructionsText = generalInstructions ? `\nGeneral Instructions:\n${generalInstructions}\n` : `\nGeneral Instructions:\n- All questions are compulsory.\n`;
    const cleanTitleBlock = `\n${paper.title}\nTime Allowed: ${timeAllowed} | Total Marks: ${paper.config.totalMarks}\n`;
    const processedContent = processForTextExport(constructedPaperContent);
    const fileContent = `${paper.config.schoolName.toUpperCase()}${cleanTitleBlock}${instructionsText}\n${processedContent}\n\n© GenPaper AI`;
    const blob = new Blob([fileContent], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${paper.title.replace(/\s+/g, '_')}.txt`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const exportToPdf = () => {
    if (!printRef.current) return;
    const opt = {
      margin: 0.5,
      filename: `${paper.title.replace(/\s+/g, '_')}.pdf`,
      image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { scale: 2, useCORS: true },
      jsPDF: { unit: 'in', format: 'a4', orientation: 'portrait' }
    };
    (window as any).html2pdf().set(opt).from(printRef.current).save();
  };

  const exportToWord = () => {
    const bodyHtml = generateWordContent(constructedPaperContent);
    const instructionsHtml = generalInstructions ? `<div style="margin-bottom:16pt;"><b>General Instructions:</b><br/>${generalInstructions.replace(/\n/g, '<br/>')}</div>` : '';
    const titleBlockHtml = `<div style="text-align:center; margin-bottom:20pt; border-bottom:2px solid #000; padding-bottom:12pt;"><h1 style="font-size:24pt; font-weight:bold; margin:0;">${schoolName || 'QUESTION PAPER'}</h1><h2 style="font-size:18pt; margin:8pt 0;">${paper.title}</h2><p>Time: ${timeAllowed} | Marks: ${paper.config.totalMarks}</p></div>`;
    const fullHtml = `<html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns:m='http://schemas.openxmlformats.org/officeDocument/2006/math' xmlns='http://www.w3.org/TR/REC-html40'><head><meta charset='utf-8'><title>${paper.title}</title><style>body{font-family:'Times New Roman',serif;}</style></head><body>${titleBlockHtml}${instructionsHtml}${bodyHtml}</body></html>`;
    const blob = new Blob(['\ufeff', fullHtml], { type: 'application/msword' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${paper.title.replace(/\s+/g, '_')}.doc`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  // --- UI Renderers ---

  let headerLayoutClass = "flex flex-row items-center justify-center gap-6";
  let textAlignClass = "text-center";
  if (logoPlacement === 'center') { headerLayoutClass = "flex flex-col items-center justify-center gap-4"; }
  else if (logoPlacement === 'right') { headerLayoutClass = "flex flex-row-reverse items-center justify-center gap-6"; }

  return (
    <div className="max-w-6xl mx-auto p-4 sm:p-6 animate-fade-in pb-20">

      {/* Top Toolbar */}
      <div className="flex flex-col md:flex-row justify-between items-center mb-6 gap-4 sticky top-0 bg-white/90 backdrop-blur-md p-4 rounded-xl shadow-lg z-20 border border-gray-100">
        <div className="flex items-center gap-4">
             <button onClick={onBack} className="text-gray-600 hover:text-gray-900 flex items-center gap-2 font-bold transition-colors">
                ← Dashboard
            </button>
            <div className="h-6 w-px bg-gray-300"></div>
            <div className="flex bg-gray-100 p-1 rounded-lg">
                <button 
                    onClick={() => setViewMode('edit')}
                    className={`px-4 py-1.5 rounded-md text-xs font-bold transition-all ${viewMode === 'edit' ? 'bg-white shadow text-[#3C128D]' : 'text-gray-500 hover:text-gray-900'}`}
                >
                    Edit Mode
                </button>
                <button 
                    onClick={() => setViewMode('preview')}
                    className={`px-4 py-1.5 rounded-md text-xs font-bold transition-all ${viewMode === 'preview' ? 'bg-white shadow text-[#3C128D]' : 'text-gray-500 hover:text-gray-900'}`}
                >
                    Print Preview
                </button>
            </div>
        </div>

        <div className="flex items-center gap-3">
             <button onClick={() => setShowAnswerKey(!showAnswerKey)} className="btn-glass btn-glass-secondary px-4 py-2 rounded-lg text-xs font-bold">
                {showAnswerKey ? 'Hide Answer Key' : 'Show Answer Key'}
             </button>
             <div className="flex items-center gap-2 bg-indigo-50 p-1 rounded-lg border border-indigo-100">
                  <select value={downloadFormat} onChange={(e) => setDownloadFormat(e.target.value as any)} className="bg-transparent border-none text-gray-800 text-xs font-bold focus:ring-0 cursor-pointer">
                    <option value="pdf">PDF</option>
                    <option value="word">Word</option>
                    <option value="txt">Txt</option>
                  </select>
                  <button onClick={handleDownload} className="btn-glass btn-glass-primary px-4 py-1.5 rounded-md text-xs font-bold">Download</button>
             </div>
        </div>
      </div>

      <div className="grid grid-cols-1 gap-8">

          {/* EDIT MODE: Interactive Grid */}
          {viewMode === 'edit' && !showAnswerKey && (
              <div className="space-y-8">
                  {/* Group Questions by Section */}
                  {Array.from(new Set(questions.map(q => q.section))).map((section) => (
                      <div key={section} className="bg-white/60 backdrop-blur-sm rounded-xl p-6 border border-white/50 shadow-sm">
                          <h3 className="text-lg font-bold text-[#3C128D] mb-4 border-b border-[#3C128D]/20 pb-2">{section}</h3>
                          <div className="grid grid-cols-1 gap-4">
                              {questions.filter(q => q.section === section).map((q, idx) => {
                                  // Global index finding
                                  const globalIdx = questions.findIndex(item => item.question_id === q.question_id);
                                  return (
                                    <QuestionCard 
                                        key={q.question_id} 
                                        question={q} 
                                        index={globalIdx} 
                                        onRegenerate={handleRegenerateQuestion} 
                                    />
                                  );
                              })}
                          </div>
                      </div>
                  ))}
              </div>
          )}

          {/* PREVIEW MODE: Clean Paper */}
          {(viewMode === 'preview' || showAnswerKey) && (
              <div ref={printRef} className="bg-white shadow-xl shadow-gray-200/50 rounded-lg min-h-[800px] border border-gray-200 flex flex-col p-8 sm:p-16">
                 {/* Paper Header */}
                 <div className="border-b-2 border-gray-800 pb-8 mb-8">
                    <div className={headerLayoutClass}>
                        {schoolLogo && <img src={schoolLogo} alt="Logo" className="h-20 w-auto object-contain" />}
                        <div className={textAlignClass}>
                            {schoolName && <h2 style={{ fontFamily: effectiveHeadingFont }} className="text-3xl font-bold uppercase tracking-widest">{schoolName}</h2>}
                        </div>
                    </div>
                    <div className="text-center mt-6">
                        <h1 style={{ fontFamily: effectiveHeadingFont }} className="text-xl font-bold mb-1">{paper.title}</h1>
                        <p style={{ fontFamily: effectiveBodyFont }} className="text-base font-medium">Time: {timeAllowed} | Marks: {paper.config.totalMarks}</p>
                    </div>
                 </div>

                 {/* Content */}
                 {showAnswerKey ? (
                     <div className="bg-yellow-50 p-6 rounded border-l-4 border-yellow-400">
                         <h2 className="font-bold text-yellow-800 mb-4">ANSWER KEY</h2>
                         <MarkdownRenderer content={paper.answerKey} />
                     </div>
                 ) : (
                     <div>
                        {generalInstructions && (
                            <div className="mb-8 p-4 bg-gray-50 text-sm rounded border border-gray-200">
                                <strong className="block mb-1">General Instructions:</strong>
                                <p style={{ fontFamily: effectiveBodyFont, whiteSpace: 'pre-wrap' }}>{generalInstructions}</p>
                            </div>
                        )}
                        <MarkdownRenderer content={constructedPaperContent} headingFont={effectiveHeadingFont} bodyFont={effectiveBodyFont} />
                     </div>
                 )}
              </div>
          )}
      </div>
    </div>
  );
};

