import { GoogleGenAI, Type, Schema } from "@google/genai";
import { PaperConfig, GeneratedPaper, Question } from "../types";
import { CBSE_EXAM_PATTERNS } from "../constants";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

// Schema for individual questions
const questionSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    question_id: { type: Type.STRING },
    section: { type: Type.STRING, description: "The section this question belongs to (e.g., 'Section A')." },
    question_text: { type: Type.STRING, description: "The question content. Use [[MATH]]...[[/MATH]] for math." },
    options: { 
      type: Type.ARRAY, 
      items: { type: Type.STRING },
      description: "Array of 4 options for MCQs. Null/Empty for others." 
    },
    answer_type: { type: Type.STRING, description: "MCQ | Short | Long | Case" },
    marks: { type: Type.NUMBER },
    difficulty: { type: Type.NUMBER, description: "1 (Very Easy) to 5 (HOTS)" },
    topic: { type: Type.STRING, description: "Chapter or topic name" },
    can_regenerate: { type: Type.BOOLEAN }
  },
  required: ["question_id", "section", "question_text", "answer_type", "marks", "difficulty", "topic"]
};

// Main schema
const paperResponseSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    title: {
      type: Type.STRING,
      description: "The formal title of the examination paper.",
    },
    questions: {
      type: Type.ARRAY,
      items: questionSchema,
      description: "The ordered list of questions."
    },
    answerKey: {
      type: Type.STRING,
      description: "The answer key as a structured plain text string.",
    },
  },
  required: ["title", "questions", "answerKey"],
};

export const generateQuestionPaper = async (config: PaperConfig): Promise<GeneratedPaper> => {
  if (!apiKey) {
    throw new Error("API Key is missing. Please check your environment configuration.");
  }

  let structurePrompt = '';

  if (config.testType === 'CBSE Board Exam') {
    const pureSubject = config.subject.split(' (Chapters:')[0].trim();
    const pattern = CBSE_EXAM_PATTERNS[pureSubject];
    if (pattern) {
        structurePrompt = `STRICTLY FOLLOW CBSE PATTERN: ${JSON.stringify(pattern)}`;
    } else {
        structurePrompt = `Generate a standard CBSE Class 10 Board Exam paper.`;
    }
  } else if (config.customSections && config.customSections.length > 0) {
    structurePrompt = `Follow these sections: ${JSON.stringify(config.customSections)}`;
  } else {
    structurePrompt = `Use standard distribution: ${JSON.stringify(config.counts)}`;
  }

  const prompt = `
    Act as a senior academic curriculum developer. Generate a structured question paper.

    Details: Subject: ${config.subject}, Grade: ${config.grade}, Marks: ${config.totalMarks}.
    ${structurePrompt}

    CRITICAL OUTPUT RULES:
    1. Return a JSON object with a "questions" array.
    2. Each question MUST follow the schema: id, section, text, options (if MCQ), marks, difficulty (1-5), topic.
    3. **MATH FORMATTING**: Wrap ALL math/formulas in [[MATH]] ... [[/MATH]]. 
       - Fractions: [[MATH]] [[num|den]] [[/MATH]].
       - Symbols: Δ, π, θ, × inside tags.
    4. **DIFFICULTY SCALE**:
       1: Very Easy, 2: Easy, 3: Moderate, 4: Hard, 5: HOTS/Case-based.
    5. **MCQs**: Must have 4 options.

    ANSWER KEY FORMATTING RULES (STRICT):
    1. Format the answer key strictly as a vertical list, grouped by Section.
    2. Do NOT use paragraphs. Use table-like blocks.
    3. For MCQs, output ONLY the correct option letter (e.g., "Q1 – B"). Do not repeat the full text.
    4. For Short/Long answers, provide a concise model answer.
    5. For Multi-part questions, use format "Q14 (i) Answer" on new lines.
    6. Insert blank lines between sections.

    Example Answer Key Layout:
    SECTION A – MCQs
    Q1 – B
    Q2 – C
    Q3 – A

    SECTION B – Short Answer
    Q4 – [Concise answer text]
    Q5 – [Concise answer text]

    SECTION C – Case Study
    Q14 (i) [Answer]
    Q14 (ii) [Answer]

    Ensure questions are grouped logically by Section (A, B, C...).
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: paperResponseSchema,
        temperature: 0.4,
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response received from AI.");
    const data = JSON.parse(text);

    return {
      id: crypto.randomUUID(),
      timestamp: Date.now(),
      config,
      title: data.title,
      questions: data.questions,
      answerKey: data.answerKey,
    };
  } catch (error) {
    console.error("Error generating paper:", error);
    throw error;
  }
};

export const regenerateSingleQuestion = async (
  currentQuestion: Question,
  newDifficulty: number,
  userInstruction: string,
  subjectContext: string
): Promise<Partial<Question>> => {

  const prompt = `
    REGENERATE this specific question.

    Original Question: "${currentQuestion.question_text}"
    Topic: ${currentQuestion.topic}
    Type: ${currentQuestion.answer_type}
    Marks: ${currentQuestion.marks}

    NEW REQUIREMENTS:
    1. New Difficulty Level: ${newDifficulty} (Scale 1-5).
    2. User Instruction: "${userInstruction || 'Make it strictly compliant with the new difficulty.'}"
    3. Subject Context: ${subjectContext}

    CONSTRAINTS:
    - Keep the same Marks, Topic, and Answer Type.
    - Output ONLY the new "question_text" and "options" (if MCQ).
    - Use [[MATH]] ... [[/MATH]] for any math.
    - If MCQ, provide 4 options.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
            type: Type.OBJECT,
            properties: {
                question_text: { type: Type.STRING },
                options: { type: Type.ARRAY, items: { type: Type.STRING } }
            }
        },
        temperature: 0.7,
      },
    });

    const text = response.text;
    if(!text) throw new Error("Failed to regenerate");
    return JSON.parse(text);

  } catch (error) {
    console.error("Regeneration failed", error);
    throw error;
  }
};

